class MainWindowAboutDialogTest(unittest.TestCase):

    def test_about_dialog_mentions_developer_site_and_alpha_review_limit(self) -> None:

        window = MainWindow.__new__(MainWindow)

        with patch("photometry_app.ui.main_window.QMessageBox.information") as information:

            MainWindow._show_about_dialog(window)

        args, _kwargs = information.call_args

        self.assertEqual(args[0], window)

        self.assertEqual(args[1], "About Citizen Astronomy (CAst)")

        self.assertIn("Developed by Ogetay.", args[2])

        self.assertIn("For more info, please visit: ogetay.com/citizen-astronomy-cast", args[2])

        self.assertIn("Alpha-reviewer build only. Do not distribute.", args[2])





class MainWindowLightCurveSegmentTest(unittest.TestCase):

    @classmethod

    def setUpClass(cls) -> None:
        cls._app = QApplication.instance() or QApplication([])



    def setUp(self) -> None:

        self._config_dir = tempfile.TemporaryDirectory()

        self._state_dir = tempfile.TemporaryDirectory()

        self._previous_config_path = os.environ.get("CITIZEN_PHOTOMETRY_CONFIG_PATH")

        self._previous_state_path = os.environ.get("CITIZEN_PHOTOMETRY_STATE_PATH")

        self._previous_training_db = os.environ.get("CITIZEN_PHOTOMETRY_TRAINING_DB")

        config_path = Path(self._config_dir.name) / "settings.json"

        state_path = Path(self._state_dir.name) / "state.json"

        training_db_path = Path(self._state_dir.name) / "training.sqlite3"

        config_path.write_text("{}", encoding="utf-8")

        state_path.write_text("{}", encoding="utf-8")

        os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = str(config_path)

        os.environ["CITIZEN_PHOTOMETRY_STATE_PATH"] = str(state_path)

        os.environ["CITIZEN_PHOTOMETRY_TRAINING_DB"] = str(training_db_path)

        self.window = MainWindow()



    def tearDown(self) -> None:

        self.window.close()

        if self._previous_config_path is None:

            os.environ.pop("CITIZEN_PHOTOMETRY_CONFIG_PATH", None)

        else:

            os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = self._previous_config_path

        if self._previous_state_path is None:

            os.environ.pop("CITIZEN_PHOTOMETRY_STATE_PATH", None)

        else:

            os.environ["CITIZEN_PHOTOMETRY_STATE_PATH"] = self._previous_state_path

            os.environ["CITIZEN_PHOTOMETRY_STATE_PATH"] = self._previous_state_path

        if self._previous_training_db is None:

            os.environ.pop("CITIZEN_PHOTOMETRY_TRAINING_DB", None)

        else:

            os.environ["CITIZEN_PHOTOMETRY_TRAINING_DB"] = self._previous_training_db

        self._config_dir.cleanup()

        self._state_dir.cleanup()



