    def test_milky_way_debug_render_mode_normalizes_invalid_values(self) -> None:

        canvas = self.window._sky_view_canvas

        self.assertEqual(canvas._normalize_milky_way_debug_render_mode(None), "normal")

        self.assertEqual(canvas._normalize_milky_way_debug_render_mode("tiles_only"), "tiles_only")

        self.assertEqual(canvas._normalize_milky_way_debug_render_mode("normal_without_base"), "normal_without_base")

        self.assertEqual(canvas._normalize_milky_way_debug_render_mode("normal_with_base_forced"), "normal_with_base_forced")

        self.assertEqual(canvas._normalize_milky_way_debug_render_mode("unexpected-mode"), "normal")

        self.assertEqual(canvas._normalize_milky_way_debug_output_mode(None), "final")

        self.assertEqual(canvas._normalize_milky_way_debug_output_mode("raw_tile_rgb"), "raw_tile_rgb")

        self.assertEqual(canvas._normalize_milky_way_debug_output_mode("local_uv_packed"), "local_uv_packed")

        self.assertEqual(canvas._normalize_milky_way_debug_output_mode("unexpected-output"), "final")

        self.assertEqual(canvas._normalize_milky_way_tile_sample_mode(None), "normal")

        self.assertEqual(canvas._normalize_milky_way_tile_sample_mode("manual_bilinear_debug"), "manual_bilinear_debug")

        self.assertEqual(canvas._normalize_milky_way_tile_sample_mode("unexpected-sample-mode"), "normal")

    def test_milky_way_debug_options_update_canvas_state(self) -> None:

        canvas = self.window._sky_view_canvas

        canvas.set_milky_way_debug_options(
            tile_debug=True,
            tile_debug_labels=True,
            tile_debug_missing=True,
            tile_debug_vertices=True,
            debug_render_mode="tiles_only",
            debug_output_mode="alpha",
            tile_sample_mode="linear_no_mip",
            debug_uv=True,
        )

        self.assertTrue(canvas._sky_view_gl_milky_way_tile_debug)

        self.assertTrue(canvas._sky_view_gl_milky_way_tile_debug_labels)

        self.assertTrue(canvas._sky_view_gl_milky_way_tile_debug_missing)

        self.assertTrue(canvas._sky_view_gl_milky_way_tile_debug_vertices)

        self.assertEqual(canvas._sky_view_gl_milky_way_debug_render_mode, "tiles_only")

        self.assertEqual(canvas._sky_view_gl_milky_way_debug_output_mode, "alpha")

        self.assertEqual(canvas._sky_view_gl_milky_way_tile_sample_mode, "linear_no_mip")

        self.assertTrue(canvas._sky_view_gl_milky_way_debug_uv)

        canvas._sky_view_gl_milky_way_last_tile_debug_snapshot = {"requested_tile_ids": ["L4/31/7"]}

        copied_snapshot = canvas.milky_way_tile_debug_snapshot()

        copied_snapshot["requested_tile_ids"].append("L4/0/7")

        self.assertEqual(canvas._sky_view_gl_milky_way_last_tile_debug_snapshot["requested_tile_ids"], ["L4/31/7"])

    def test_sky_view_moon_debug_controls_apply_live_polar_cap_tuning(self) -> None:

        canvas = self.window._sky_view_canvas
        canvas._sky_view_moon_debug_ui_enabled = True
        self.window._sync_sky_view_moon_debug_controls_from_canvas()

        self.window._sky_view_moon_debug_polar_cap_blend_start_spin.setValue(63.0)
        self.window._sky_view_moon_debug_polar_cap_blend_end_spin.setValue(81.0)
        self.window._sky_view_moon_debug_polar_cap_normal_strength_spin.setValue(0.019)
        self.window._sky_view_moon_debug_polar_cap_sharpness_spin.setValue(0.44)
        self.window._sky_view_moon_debug_polar_cap_boundary_match_spin.setValue(0.52)

        self.assertAlmostEqual(canvas.moon_debug_polar_cap_blend_start_lat_deg, 63.0)
        self.assertAlmostEqual(canvas.moon_debug_polar_cap_blend_end_lat_deg, 81.0)
        self.assertAlmostEqual(canvas.moon_debug_polar_cap_normal_strength, 0.019)
        self.assertAlmostEqual(canvas.moon_debug_polar_cap_albedo_sharpness, 0.44)
        self.assertAlmostEqual(canvas.moon_debug_polar_cap_boundary_match_strength, 0.52)

        self.window._handle_sky_view_moon_debug_reset_polar_cap_tuning()

        self.assertAlmostEqual(canvas.moon_debug_polar_cap_blend_start_lat_deg, DEFAULT_MOON_VISUAL_SETTINGS.polar_cap_blend_start_lat_deg)
        self.assertAlmostEqual(canvas.moon_debug_polar_cap_blend_end_lat_deg, DEFAULT_MOON_VISUAL_SETTINGS.polar_cap_blend_end_lat_deg)
        self.assertAlmostEqual(canvas.moon_debug_polar_cap_normal_strength, DEFAULT_MOON_VISUAL_SETTINGS.polar_cap_normal_strength)
        self.assertAlmostEqual(canvas.moon_debug_polar_cap_albedo_sharpness, DEFAULT_MOON_VISUAL_SETTINGS.polar_cap_albedo_sharpness)
        self.assertAlmostEqual(canvas.moon_debug_polar_cap_boundary_match_strength, DEFAULT_MOON_VISUAL_SETTINGS.polar_cap_boundary_match_strength)

    def test_milky_way_diagnostic_capture_request_round_trip(self) -> None:

        canvas = self.window._sky_view_canvas

        sample_points = [{"sample_id": "probe_01", "x": 12, "y": 34, "classification": "test"}]

        canvas.request_milky_way_diagnostic_capture(
            capture_id="capture-123",
            sample_points=sample_points,
            debug_output_mode="local_uv_packed",
            tile_sample_mode="normal",
            probe_size=3,
            synthetic_override={"local_uv": (0.25, 0.75)},
        )

        self.assertEqual(canvas._sky_view_gl_milky_way_diagnostic_capture_request["capture_id"], "capture-123")

        self.assertEqual(canvas._sky_view_gl_milky_way_diagnostic_capture_request["probe_size"], 3)

        self.assertEqual(canvas._sky_view_gl_milky_way_diagnostic_capture_request["sample_points"], sample_points)

        canvas._sky_view_gl_milky_way_diagnostic_capture_result = {"capture_id": "capture-123", "status": "complete"}

        self.assertEqual(canvas.milky_way_diagnostic_capture_result(), {"capture_id": "capture-123", "status": "complete"})

        canvas.clear_milky_way_diagnostic_capture()

        self.assertIsNone(canvas._sky_view_gl_milky_way_diagnostic_capture_request)

        self.assertIsNone(canvas.milky_way_diagnostic_capture_result())

