    def test_milky_way_triangle_screening_rejects_degenerate_and_large_triangles(self) -> None:

        canvas = self.window._sky_view_canvas

        scene = SimpleNamespace(viewport_rect=QRectF(0.0, 0.0, 1000.0, 600.0))

        degenerate_triangle = (
            _SkyViewMilkyWayProjectedTileVertex(0.0, 0.0, 0.0, 0.0, 100.0, 100.0, 0.1),
            _SkyViewMilkyWayProjectedTileVertex(0.0, 0.0, 0.5, 0.0, 100.2, 100.2, 0.1),
            _SkyViewMilkyWayProjectedTileVertex(0.0, 0.0, 0.5, 0.5, 100.4, 100.4, 0.1),
        )

        degenerate_area = canvas._milky_way_projected_triangle_area(degenerate_triangle)

        self.assertEqual(canvas._milky_way_triangle_screening_reason(scene, degenerate_triangle, degenerate_area), "degenerate")

        discontinuity_triangle = (
            _SkyViewMilkyWayProjectedTileVertex(0.0, 0.0, 0.0, 0.0, 20.0, 20.0, 0.1),
            _SkyViewMilkyWayProjectedTileVertex(0.0, 0.0, 0.5, 0.0, 980.0, 40.0, 0.1),
            _SkyViewMilkyWayProjectedTileVertex(0.0, 0.0, 0.5, 0.5, 500.0, 580.0, 0.1),
        )

        discontinuity_area = canvas._milky_way_projected_triangle_area(discontinuity_triangle)

        self.assertEqual(canvas._milky_way_triangle_screening_reason(scene, discontinuity_triangle, discontinuity_area), "discontinuity")

        large_triangle = (
            _SkyViewMilkyWayProjectedTileVertex(0.0, 0.0, 0.0, 0.0, 120.0, 120.0, 0.1),
            _SkyViewMilkyWayProjectedTileVertex(0.0, 0.0, 0.5, 0.0, 880.0, 150.0, 0.1),
            _SkyViewMilkyWayProjectedTileVertex(0.0, 0.0, 0.5, 0.5, 500.0, 520.0, 0.1),
        )

        large_area = canvas._milky_way_projected_triangle_area(large_triangle)

        self.assertEqual(canvas._milky_way_triangle_screening_reason(scene, large_triangle, large_area), "large_area")

    def test_milky_way_tile_mesh_subdivision_increases_for_zoom_and_poles(self) -> None:

        canvas = self.window._sky_view_canvas

        scene = SimpleNamespace(
            viewport_rect=QRectF(0.0, 0.0, 1000.0, 600.0),
            camera_forward=(1.0, 0.0, 0.0),
            camera_up=(0.0, 0.0, 1.0),
            field_width_deg=12.0,
            field_height_deg=7.2,
        )

        manifest_asset = SimpleNamespace(manifest=SimpleNamespace(orientation_ra_increases="left"))

        with patch.object(canvas, "_make_scene_horizon_unclipped_projector", return_value=lambda _vector: (300.0, 200.0, 0.1)):
            detail_subdivision = canvas._milky_way_tile_mesh_subdivision(
                scene,
                manifest_asset,
                SimpleNamespace(level=4, width=32768, height=16384),
                u_min=0.6875,
                u_max=0.71875,
                v_min=0.5625,
                v_max=0.625,
            )

            polar_subdivision = canvas._milky_way_tile_mesh_subdivision(
                scene,
                manifest_asset,
                SimpleNamespace(level=4, width=32768, height=16384),
                u_min=0.09375,
                u_max=0.125,
                v_min=0.0,
                v_max=0.0625,
            )

        self.assertGreaterEqual(detail_subdivision, canvas._SKY_VIEW_GL_MILKY_WAY_TILE_MESH_DEFAULT_SUBDIVISION)

        self.assertGreater(polar_subdivision, detail_subdivision)



