    def test_differential_workflow_dialog_defaults_and_measurement_warning(self) -> None:

        choose_folder = MagicMock()

        generate = MagicMock()

        dialog = _DifferentialWorkflowDialog(self.window, choose_folder, generate)

        try:

            dialog.show()

            self._app.processEvents()

            self.assertTrue(dialog._light_curves_checkbox.isChecked())

            self.assertFalse(dialog._light_curves_checkbox.isEnabled())

            self.assertEqual(dialog._generate_group.title(), "2. Pipeline")

            self.assertTrue(dialog._plate_solving_checkbox.isChecked())

            self.assertFalse(dialog._plate_solving_checkbox.isEnabled())

            self.assertTrue(dialog._filter_targets_checkbox.isChecked())

            self.assertFalse(dialog._filter_targets_checkbox.isEnabled())

            self.assertTrue(dialog._designation_filters_checkbox.isChecked())

            self.assertTrue(dialog._brightest_variables_checkbox.isChecked())

            self.assertFalse(dialog._analyze_best_checkbox.isChecked())

            self.assertEqual(dialog._brightest_percent_input.value(), 100)

            self.assertFalse(dialog._calibration_checkbox.isChecked())

            self.assertFalse(dialog._star_alignment_checkbox.isChecked())

            self.assertTrue(dialog._star_alignment_checkbox.isEnabled())

            self.assertTrue(dialog._pull_periods_checkbox.isChecked())

            self.assertTrue(dialog._calculate_periods_checkbox.isChecked())

            self.assertFalse(dialog._measurements_checkbox.isChecked())

            self.assertEqual(dialog.minimumSize(), dialog.maximumSize())

            self.assertIn("Hover each workflow option", dialog._footer_tip_label.full_text())

            self.assertFalse(dialog._generate_button.isEnabled())

            self.assertIn("QPushButton#workflowGenerateButton:disabled", dialog.styleSheet())

            generate_group_height = dialog._generate_group.height()



            dialog.move(dialog.x() + 20, dialog.y() + 20)

            self._app.processEvents()



            self.assertEqual(dialog._generate_group.height(), generate_group_height)



            dialog._measurements_checkbox.setChecked(True)

            dialog._analyze_best_checkbox.setChecked(True)

            self.assertFalse(dialog._brightest_variables_checkbox.isChecked())

            self.assertFalse(dialog._brightest_percent_input.isEnabled())

            self.assertTrue(dialog.options().analyze_best_targets)

            dialog._brightest_variables_checkbox.setChecked(True)

            self.assertFalse(dialog._analyze_best_checkbox.isChecked())

            self.assertTrue(dialog._brightest_percent_input.isEnabled())



            self.assertIn("Warning:", dialog._footer_tip_label.full_text())

            self.assertTrue(dialog.options().create_measurements_table)



            long_path = Path(self._config_dir.name) / ("very_" * 30 + "long_folder_name")

            dialog.set_folder_path(long_path)

            self._app.processEvents()



            self.assertEqual(dialog._folder_path_label.toolTip(), str(long_path))

            self.assertIn("...", dialog._folder_path_label.text())

            self.assertNotEqual(dialog._folder_path_label.text(), str(long_path))



            dialog._calibration_checkbox.setChecked(True)



            self.assertTrue(dialog._star_alignment_checkbox.isEnabled())



            dialog._star_alignment_checkbox.setChecked(True)



            dialog._pull_periods_checkbox.setChecked(False)

            dialog._calculate_periods_checkbox.setChecked(False)

            dialog._default_button.click()



            self.assertTrue(dialog._pull_periods_checkbox.isChecked())

            self.assertTrue(dialog._calculate_periods_checkbox.isChecked())

            self.assertTrue(dialog._designation_filters_checkbox.isChecked())

            self.assertTrue(dialog._brightest_variables_checkbox.isChecked())

            self.assertFalse(dialog._analyze_best_checkbox.isChecked())

            self.assertEqual(dialog._brightest_percent_input.value(), 100)

            self.assertFalse(dialog._calibration_checkbox.isChecked())

            self.assertFalse(dialog._star_alignment_checkbox.isChecked())

            self.assertTrue(dialog._star_alignment_checkbox.isEnabled())

            self.assertFalse(dialog._measurements_checkbox.isChecked())

            self.assertIn("Hover each workflow option", dialog._footer_tip_label.full_text())



            dialog.set_ready("Demo", 12)

            dialog._reset_button.click()



            self.assertEqual(dialog._folder_path_label.full_text(), "No folder selected.")

            self.assertEqual(dialog._step_label.full_text(), "Status: waiting for a folder.")

            self.assertFalse(dialog._generate_button.isEnabled())



            dialog._measurements_checkbox.setChecked(True)



            dialog.set_ready("Demo", 12)

            dialog._generate_button.click()



            self.assertTrue(dialog._generate_button.isEnabled())

            generate.assert_called_once_with(_DifferentialWorkflowOptions(False, False, True, True, True))

        finally:

            dialog.close()



