    def test_differential_workflow_generate_queues_selected_outputs(self) -> None:

        root_path = Path(self._config_dir.name)

        self.window._root_path_input.setText(str(root_path))

        report = ScanReport(

            root_path=root_path,

            object_summaries=[ObjectScanSummary(object_name="Alpha", files=[])],

        )

        with patch.object(self.window, "_show_scan_results_summary_dialog"):

            self.window._handle_scan_completed(report)



        options = _DifferentialWorkflowOptions(

            calibrate_images=False,

            align_star_images=True,

            pull_periods=True,

            calculate_periods=False,

            create_measurements_table=True,

        )



        with (
            patch.object(self.window, "_begin_processing") as begin_processing,
            patch("photometry_app.ui.main_window.CachedProcessingReportWorker") as cached_worker_class,
        ):

            cached_worker = MagicMock()

            cached_worker_class.return_value = cached_worker

