    def test_processing_report_cache_round_trip(self) -> None:

        root_path = Path(self._config_dir.name)

        source_path = root_path / "alpha_0001.fits"

        source_path.write_bytes(b"cached")

        summary_files = [

            FileScanResult(

                path=source_path,

                object_folder="Alpha",

                metadata=ObservationMetadata(None, None, None, 100, 100, "Alpha"),

                wcs_status=WcsStatus.SOLVED,

            )

        ]

        report = ProcessingReport(

            object_name="Alpha",

            files_processed=1,

            solved_files=1,

            field_catalog=FieldCatalog(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=0.5),

            reference_stars=[

                CatalogStar("gaia", "ref-1", "Ref 1", 10.0, 20.0, 11.0, False)

            ],

            measurements=[

                PhotometryMeasurement(

                    source_id="var-1",

                    source_name="Var 1",

                    catalog="vsx",

                    object_name="Alpha",

                    file_path=source_path,

                    observation_time=datetime.now(UTC),

                    filter_name="L",

                    ra_deg=10.0,

                    dec_deg=20.0,

                    x=100.0,

                    y=120.0,

                    flux=1234.0,

                    flux_error=12.0,

                    instrumental_magnitude=13.2,

                    differential_magnitude=0.12,

                    is_variable=True,

                    is_reference=False,

                )

            ],

            light_curves=[

                LightCurveSeries(

                    object_name="Alpha",

                    source_id="var-1",

                    source_name="Var 1",

                    filter_name="L",

                    points=[

                        LightCurvePoint(

                            observation_time=datetime.now(UTC),

                            file_path=source_path,

                            differential_magnitude=0.12,

                            instrumental_magnitude=13.2,

                            flux=1234.0,

                            flux_error=12.0,

                        )

                    ],

                )

            ],

        )

        self.window._pipeline.save_cached_processing_report(root_path, report, summary_files=summary_files)

        cached_report, cache_note = self.window._pipeline.load_cached_processing_report(

            root_path,

            "Alpha",

            summary_files=summary_files,

        )

        self.assertEqual(cache_note, "Reused cached light-curve results.")

        self.assertIsNotNone(cached_report)

        assert cached_report is not None

        self.assertEqual(cached_report.object_name, "Alpha")

        self.assertEqual(len(cached_report.measurements), 1)

        self.assertEqual(len(cached_report.light_curves), 1)

