    def test_workflow_calibration_dialog_prefills_saved_master_paths(self) -> None:

        settings = self.window._ensure_settings()
        settings.calibration_bias_path = str((Path(self._config_dir.name) / "bias").resolve())
        settings.calibration_dark_path = str((Path(self._config_dir.name) / "dark").resolve())
        settings.calibration_flat_path = str((Path(self._config_dir.name) / "flat").resolve())

        dialog = WorkflowCalibrationPipelineDialog(
            default_root=Path(self._config_dir.name),
            settings=settings,
            align_output=True,
        )

        try:
            dialog.show()
            self._app.processEvents()

            self.assertEqual(dialog.windowTitle(), "Workflow Calibration")
            self.assertEqual(dialog.objectName(), "workflowCalibrationDialog")
            self.assertEqual(dialog.layout().count(), 4)
            self.assertFalse(dialog._science_input.isVisible())
            self.assertFalse(dialog._output_input.isVisible())
            self.assertFalse(dialog._align_input.isVisible())
            self.assertEqual(dialog._bias_input.text(), settings.calibration_bias_path)
            self.assertEqual(dialog._dark_input.text(), settings.calibration_dark_path)
            self.assertEqual(dialog._flat_input.text(), settings.calibration_flat_path)

            group_boxes = dialog.findChildren(QGroupBox)
            self.assertEqual([group.title() for group in group_boxes], ["Calibration Files"])

            button_texts = [button.text() for button in dialog.findChildren(QPushButton)]
            self.assertNotIn("File...", button_texts)
            self.assertIn("Continue", button_texts)

            request = dialog.request()

            self.assertEqual(request.science_path, Path(self._config_dir.name))
            self.assertEqual(request.output_directory, Path(self._config_dir.name) / "calibration_output")
            self.assertTrue(request.align_output)
        finally:
            dialog.close()

