    def test_transient_training_labels_persist_and_model_scores_table(self) -> None:

        root_path = Path(self._config_dir.name)
        candidates = (
            self._build_transient_training_candidate("T001", root_path, snr=22.0, flux_ratio=4.0),
            self._build_transient_training_candidate("T002", root_path, snr=4.0, flux_ratio=1.0),
        )
        self.window._current_transient_root_path = root_path
        self.window._current_transient_search_result = TransientSearchResult(
            root_path=root_path,
            frame_results=(),
            total_files=2,
            solved_frame_count=2,
            astrometry_solved_count=0,
            detected_source_count=2,
            catalog_star_count=0,
            candidates=candidates,
            notes=(),
            report_text="Synthetic transient training result.",
        )

        self.window._populate_transient_results_table(candidates)

        self.assertTrue(self.window._transient_quick_label_button.isEnabled())

        for row_index, label in enumerate(("real", "artifact")):
            with patch.object(self.window, "_start_transient_image_preload"), patch.object(self.window, "_set_current_transient_image_path"), patch.object(self.window, "_sync_transient_image_controls"):
                self.window._transient_results_table.setCurrentCell(row_index, 0)
                self.window._transient_results_table.selectRow(row_index)
            label_index = self.window._transient_training_label_combo.findData(label)
            self.assertGreaterEqual(label_index, 0)
            self.window._transient_training_label_combo.setCurrentIndex(label_index)
            self.window._save_transient_training_label()

        self.assertEqual(self.window._transient_results_table.item(0, 8).text(), "Real")
        self.assertEqual(self.window._transient_results_table.item(1, 8).text(), "Artifact")

        with patch.object(self.window, "_start_transient_image_preload"), patch.object(self.window, "_set_current_transient_image_path"), patch.object(self.window, "_sync_transient_image_controls"):
            self.window._train_transient_candidate_model()

        self.assertNotEqual(self.window._transient_results_table.item(0, 9).text(), "-")
        self.assertIn("Latest model", self.window._transient_training_status_label.text())

        with patch("photometry_app.ui.main_window.TransientQuickLabelDialog") as dialog_class:
            dialog = dialog_class.return_value
            dialog.saved_count = 0
            dialog.exec.return_value = QDialog.DialogCode.Accepted

            self.window._open_transient_quick_label_dialog()

        dialog_class.assert_called_once()
        self.assertEqual(dialog_class.call_args.kwargs["candidates"], candidates)



