    def _build_transient_training_candidate(self, candidate_id: str, root_path: Path, *, snr: float, flux_ratio: float) -> TransientCandidate:

        observed_at = datetime(2026, 5, 1, 2, 0, tzinfo=UTC)
        detection = TransientSourceDetection(
            source_path=root_path / f"{candidate_id}.fit",
            observation_time=observed_at,
            x=32.0,
            y=32.0,
            ra_deg=100.0 + snr / 1000.0,
            dec_deg=20.0,
            snr=snr,
            flux=snr * 100.0,
            peak_value=snr * 20.0,
        )
        return TransientCandidate(
            candidate_id=candidate_id,
            ra_deg=detection.ra_deg,
            dec_deg=detection.dec_deg,
            frame_count=1,
            detection_count=1,
            first_observation=observed_at,
            last_observation=observed_at,
            median_snr=snr,
            max_snr=snr,
            nearest_catalog_name=None,
            nearest_catalog_separation_arcsec=None,
            detections=(detection,),
            summary_text=f"Candidate {candidate_id}",
            variability_snr=snr,
            flux_ratio=flux_ratio,
        )

        self.assertIs(self.window._hr_settings_selection_circle_opacity_spin.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_settings_selection_circle_size_factor_spin.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_settings_marker_size_mode_combo.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_settings_fixed_marker_size_spin.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_settings_motion_color_button.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_settings_motion_width_spin.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_settings_motion_color_by_angle_checkbox.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_settings_motion_saturation_by_magnitude_checkbox.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_settings_search_catalog_names_checkbox.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_settings_search_catalog_names_magnitude_threshold_spin.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_roi_mode_combo.parentWidget(), settings_widget)

        self.assertIs(self.window._hr_roi_invert_checkbox.parentWidget(), settings_widget)



