    def test_manual_aperture_drag_previews_until_mouse_release(self) -> None:

        image_path = Path("frame_01.fits")

        target = ManualSourceConfig(

            source_id="manual-target-1",

            name="Demo",

            role=ManualSourceRole.TARGET,

            ra_deg=10.0,

            dec_deg=20.0,

            reference_frame_name=image_path.name,

            reference_x=50.0,

            reference_y=60.0,

            aperture_radius=6.0,

            annulus_inner_radius=9.0,

            annulus_outer_radius=13.0,

        )

        self.window._settings.manual_photometry_configs = {

            "Demo": ManualPhotometryConfig(object_name="Demo", keep_comparison_stars=False, sources=[target])

        }

        self.window._current_processing_report = ProcessingReport(

            object_name="Demo",

            files_processed=1,

            solved_files=1,

            field_catalog=FieldCatalog(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=1.0, variable_stars=[]),

            measurements=[],

            light_curves=[],

        )

        with patch.object(self.window, "_render_image_panel"):

            self.window._edit_apertures_checkbox.setChecked(True)

        with (

            patch.object(self.window, "_current_image_path", return_value=image_path),

            patch.object(self.window, "_manual_overlay_positions_for_image", return_value={"manual-target-1": (50.0, 60.0)}),

            patch.object(self.window, "_pixel_to_sky", side_effect=lambda _path, x_value, y_value: (x_value / 10.0, y_value / 10.0)),

            patch.object(self.window, "_render_image_panel"),

        ):

            self.window._handle_image_press(50.0, 60.0, Qt.MouseButton.LeftButton, Qt.KeyboardModifier.NoModifier)

            self.window._handle_image_motion(80.0, 90.0, Qt.MouseButtons(Qt.MouseButton.LeftButton), Qt.KeyboardModifier.NoModifier)

            self.assertEqual(target.reference_x, 50.0)

            self.assertIsNotNone(self.window._manual_drag_preview)

            assert self.window._manual_drag_preview is not None

            self.assertEqual(self.window._manual_drag_preview.x, 80.0)

            section = self.window._manual_editor_info_section(image_path)

            self.assertIsNotNone(section)

            assert section is not None

            item_lookup = {item.label: item.value for item in section.items}

            self.assertEqual(item_lookup["Source"], "Target")

            self.assertEqual(item_lookup["Pixel Position"], "(80.00, 90.00)")

            self.window._handle_image_release(Qt.MouseButton.LeftButton, Qt.KeyboardModifier.NoModifier)

        self.assertEqual(target.name, "Target")

        self.assertEqual(target.reference_x, 80.0)

        self.assertEqual(target.reference_y, 90.0)

        self.assertIsNone(self.window._manual_drag_preview)



    def test_discover_results_merge_candidate_sources_into_processing_report(self) -> None:

        report = ProcessingReport(

            object_name="Alpha",

            files_processed=1,

            solved_files=1,

            field_catalog=FieldCatalog(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=0.2),

            measurements=[],

            light_curves=[],

        )

        self.window._current_processing_report = report

        candidate_entry = CatalogStar(

            catalog="gaia",

            source_id="gaia-42",

            name="Discover 1",

            ra_deg=10.5,

            dec_deg=20.5,

            magnitude=12.4,

            is_variable=True,

            metadata={"discover_candidate": True, "discover_type": "raw light curve", "discover_original_name": "Gaia Candidate 42"},

        )

        measurement = PhotometryMeasurement(

            source_id="gaia-42",

            source_name="Discover 1",

            catalog="gaia",

            object_name="Alpha",

            file_path=Path("frame-001.fits"),

            observation_time=datetime(2025, 1, 1, tzinfo=UTC),

            filter_name="V",

            ra_deg=10.5,

            dec_deg=20.5,

            x=100.0,

            y=120.0,

            flux=15000.0,

            flux_error=120.0,

            instrumental_magnitude=10.2,

            differential_magnitude=0.18,

            is_variable=True,

            is_reference=False,

            comparison_source_ids=["gaia-ref-1"],

            comparison_source_names=["Ref 1"],

            comparison_scatter=0.012,

        )

        series = LightCurveSeries(

            object_name="Alpha",

            source_id="gaia-42",

            source_name="Discover 1",

            filter_name="V",

            points=[

                LightCurvePoint(

                    observation_time=measurement.observation_time,

                    file_path=measurement.file_path,

                    differential_magnitude=measurement.differential_magnitude,

                    instrumental_magnitude=measurement.instrumental_magnitude,

                    flux=measurement.flux,

                    flux_error=measurement.flux_error,

                )

            ],

            candidate_score=41.0,

        )

        batch_result = DiscoverBatchResult(

            report_token=id(report),

            source_results=[

                DiscoverSourceResult(

                    entry=candidate_entry,

                    best_measurements=[measurement],

                    best_series=series,

                    best_period_result=None,

                    total_combination_count=12,

                    evaluated_combination_count=12,

                    valid_point_count=1,

                    excluded_point_count=0,

                    median_comparison_scatter=0.012,

                    sampled_search=False,

                )

            ],

            tested_candidate_count=8,

            retained_candidate_count=1,

            reference_star_count=6,

            total_candidate_count=24,

            current_stage_label="raw light curve",

        )

        checkpoint_path = Path(self._state_dir.name) / "discover.jsonl"

        self.window._discover_checkpoint_report_token = id(report)

        self.window._discover_checkpoint_path = checkpoint_path

        self.window._discover_checkpoint_cache_key = "cache-key"

        with (

            patch.object(self.window._pipeline, "save_cached_processing_report") as save_cached_processing_report,

            patch.object(self.window, "_refresh_processing_views") as refresh_processing_views,

            patch("photometry_app.ui.main_window.build_light_curve_series", side_effect=AssertionError("Discover batches should not rebuild the full light-curve table")),

        ):

            self.window._discover_sources_worker = object()

            self.window._handle_discover_sources_batch_ready(batch_result)

            self.window._flush_pending_discover_ui_updates()

            refresh_processing_views.assert_not_called()

            save_cached_processing_report.assert_not_called()

            checkpoint_payloads = [json.loads(line) for line in checkpoint_path.read_text(encoding="utf-8").splitlines()]

            self.assertEqual(len(checkpoint_payloads), 1)

            self.assertEqual(checkpoint_payloads[0]["cache_key"], "cache-key")

            self.assertEqual(checkpoint_payloads[0]["source_results"][0]["entry"]["fields"]["source_id"], "gaia-42")

            self.window._discover_sources_worker = None

            self.window._flush_pending_discover_ui_updates(persist_cache=True)

            refresh_processing_views.assert_called_once_with(refresh_source_table=True)

            save_cached_processing_report.assert_called_once()

        self.assertEqual(len(report.field_catalog.variable_stars), 1)

        self.assertEqual(report.field_catalog.variable_stars[0].name, "Discover 1")

        self.assertEqual(self.window._source_type_label(report.field_catalog.variable_stars[0]), "raw light curve")

        self.assertEqual(len(report.measurements), 1)

        self.assertEqual(len(report.light_curves), 1)

        self.assertIsNone(self.window._calculated_period_results[("gaia-42", "V")])


