    def test_loaded_results_dialog_shows_per_object_note_preview(self) -> None:

        summaries = [

            ObjectScanSummary(

                object_name="Alpha",

                files=[

                    FileScanResult(

                        path=Path("alpha_01.fits"),

                        object_folder="Alpha",

                        metadata=ObservationMetadata(None, None, None, None, None, "Alpha"),

                        wcs_status=WcsStatus.SOLVED,

                        reasons=[],

                    ),

                    FileScanResult(

                        path=Path("alpha_02.fits"),

                        object_folder="Alpha",

                        metadata=ObservationMetadata(None, None, None, None, None, "Alpha"),

                        wcs_status=WcsStatus.UNSOLVED,

                        reasons=["Missing WCS header"],

                    ),

                    FileScanResult(

                        path=Path("alpha_03.fits"),

                        object_folder="Alpha",

                        metadata=ObservationMetadata(None, None, None, None, None, "Alpha"),

                        wcs_status=WcsStatus.INVALID,

                        reasons=["Corrupt FITS header"],

                    ),

                ],

            )

        ]



        dialog = ScanResultsSummaryDialog(summaries, selected_object_name="Alpha", parent=self.window)



        preview_text = dialog._object_note_preview.toPlainText()



        self.assertIn("Alpha: 1 solved, 1 needing solve, 1 invalid across 3 file(s).", preview_text)

        self.assertIn("Needs solve: alpha_02.fits", preview_text)

        self.assertIn("Invalid: alpha_03.fits", preview_text)

        self.assertIn("Common notes: Missing WCS header (1), Corrupt FITS header (1)", preview_text)

        dialog.close()



