    def test_preview_failure_shows_friendly_vizier_warning(self) -> None:

        self.window._pending_object_name = "AE UMa"



        with patch("photometry_app.ui.main_window.QMessageBox.warning") as warning:

            self.window._handle_preview_failed(

                "HTTPSConnectionPool(host='vizier.cds.unistra.fr', port=443): Max retries exceeded with url: /viz-bin/votable "

                "(Caused by NewConnectionError(\"HTTPSConnection(host='vizier.cds.unistra.fr', port=443): "

                "Failed to establish a new connection: [WinError 10061] No connection could be made because the target machine actively refused it\"))"

            )



        self.assertIn("Could not reach the VizieR catalog service", self.window._summary_label.text())

        self.assertIn("refused the connection", self.window._summary_label.text())

        self.assertIn("Preview failed for AE UMa: Could not reach the VizieR catalog service", self.window._work_log_output.toPlainText())

        warning.assert_called_once()

        self.assertEqual(warning.call_args.args[1], "Preview unavailable")

        self.assertIn("Could not reach the VizieR catalog service", warning.call_args.args[2])



