        self.assertIsNotNone(item)

        assert item is not None

        selected_action: QAction | None = None

        def choose_gaia_action(menu: QMenu, *_args: object) -> QAction | None:

            nonlocal selected_action

            labels = [action.text() for action in menu.actions() if not action.isSeparator()]

            self.assertEqual(labels, ["Simbad", "VSX", "CDS", "Gaia", "Pull Period", "Calculate Period", "Copy Source Name"])

            selected_action = next((action for action in menu.actions() if action.text() == "Gaia"), None)

            return selected_action

