    def test_clear_selected_asteroid_dataset_cache_removes_current_sequence_cache_files(self) -> None:

        self.window._handle_app_mode_changed(AppMode.ASTEROID_COMET_DETECTION)

        with tempfile.TemporaryDirectory() as temp_dir:

            dataset_dir = Path(temp_dir) / "DemoSequence"

            dataset_dir.mkdir(parents=True, exist_ok=True)

            source_path = dataset_dir / "frame_001.fit"

            source_path.write_text("placeholder", encoding="utf-8")

            self.window._set_asteroid_sequence_paths([source_path], source_label=dataset_dir)

            settings = AppSettings.from_root(dataset_dir)

            source_cache_key = hashlib.sha256(str(source_path.resolve()).encode("utf-8")).hexdigest()

            cache_dir = settings.cache_dir / "solar-system-wcs"

            cache_dir.mkdir(parents=True, exist_ok=True)

            (cache_dir / f"{source_cache_key}.json").write_text("{}", encoding="utf-8")

            (cache_dir / f"{source_cache_key}_solved.fits").write_text("fits", encoding="utf-8")

            self.window._clear_selected_dataset_cache()

            self.assertFalse((cache_dir / f"{source_cache_key}.json").exists())

            self.assertFalse((cache_dir / f"{source_cache_key}_solved.fits").exists())



