    def test_export_active_light_curve_animated_gif_action_uses_animated_export(self) -> None:
        series = self._build_series()
        report = ProcessingReport(
            object_name="Demo",
            files_processed=1,
            solved_files=1,
            field_catalog=FieldCatalog(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=1.0, variable_stars=[]),
            measurements=[],
            light_curves=[series],
        )
        self.window._current_processing_report = report
        self.window._populate_series_selector([series])

        with tempfile.TemporaryDirectory() as temp_dir:
            output_path = Path(temp_dir) / "animated.gif"
            progress_dialog = MagicMock()
            progress_dialog.canceled.connect = MagicMock()
            image = QImage(8, 6, QImage.Format.Format_ARGB32)
            image.fill(QColor("black"))

            with patch(
                "photometry_app.ui.main_window.QFileDialog.getSaveFileName",
                return_value=(str(output_path), "GIF Files (*.gif)"),
            ), patch(
                "photometry_app.ui.main_window.QProgressDialog",
                return_value=progress_dialog,
            ) as progress_dialog_class, patch(
                "photometry_app.ui.main_window.export_qimages_to_gif",
            ) as export_gif, patch.object(
                self.window,
                "_light_curve_animation_frame_payloads",
                return_value=[MagicMock()],
            ) as frame_payloads, patch.object(
                self.window,
                "_render_light_curve_animation_payloads_current_view",
                return_value=[image],
            ) as worker_class, patch(
                "photometry_app.ui.main_window.export_light_curve_plot",
            ) as export_plot, patch.object(
                self.window._light_curve_widget,
                "export_current_view",
            ) as export_current_view:
                self.window._export_active_light_curve_animated_gif()

            frame_payloads.assert_called_once()
            worker_class.assert_called_once()
            export_gif.assert_called_once()
            progress_dialog_class.assert_called_once()
            export_plot.assert_not_called()
            export_current_view.assert_not_called()

