    def test_grid_overlay_from_world_samples_retains_edge_crossing_points(self) -> None:

        class FakeWcs:

            def world_to_pixel_values(self, _ra_values, _dec_values):

                return np.array([-12.0, 8.0, 50.0, 92.0, 112.0]), np.array([30.0, 30.0, 30.0, 30.0, 30.0])

        overlays = self.window._grid_overlay_from_world_samples(
            FakeWcs(),
            np.array([0.0, 1.0, 2.0, 3.0, 4.0]),
            np.array([5.0, 5.0, 5.0, 5.0, 5.0]),
            image_width=100,
            image_height=80,
            label="12h36m",
            color="#808080",
            axis_kind="ra",
        )

        self.assertEqual(len(overlays), 1)
        self.assertEqual(overlays[0].points[0], (-12.0, 30.0))
        self.assertEqual(overlays[0].points[-1], (112.0, 30.0))

