    def test_differential_train_model_scores_source_results(self) -> None:

        root = Path(self._config_dir.name)

        self.window._root_path_input.setText(str(root))

        self.window._settings = AppSettings.from_root(root)

        entries = [

            CatalogStar(catalog="vsx", source_id="vsx-1", name="Alpha", ra_deg=10.0, dec_deg=20.0, magnitude=11.8, is_variable=True),

            CatalogStar(catalog="gaia-dr3", source_id="gaia-2", name="Beta", ra_deg=11.0, dec_deg=21.0, magnitude=12.7, is_variable=False),

            CatalogStar(catalog="gaia-dr3", source_id="gaia-3", name="Gamma", ra_deg=12.0, dec_deg=22.0, magnitude=13.2, is_variable=False),

        ]

        measurements: list[PhotometryMeasurement] = []

        light_curves: list[LightCurveSeries] = []

        file_results: list[FileScanResult] = []

        for index, entry in enumerate(entries, start=1):

            source_path = root / f"frame_{index:02d}.fits"

            source_path.write_text("", encoding="utf-8")

            measurements.append(

                PhotometryMeasurement(

                    source_id=entry.source_id,

                    source_name=entry.name,

                    catalog=entry.catalog,

                    object_name="Demo",

                    file_path=source_path,

                    observation_time=datetime(2026, 3, 16, 1, index, 0),

                    filter_name="V",

                    ra_deg=entry.ra_deg,

                    dec_deg=entry.dec_deg,

                    x=50.0 + index,

                    y=60.0 + index,

                    flux=5000.0 - (index * 500.0),

                    flux_error=12.0 + index,

                    instrumental_magnitude=-9.0 + (index * 0.2),

                    differential_magnitude=12.0 + (index * 0.1),

                    is_variable=entry.is_variable,

                    is_reference=False,

                    differential_magnitude_error=0.02 + (index * 0.01),

                    snr=35.0 - (index * 8.0),

                    comparison_scatter=0.015 + (index * 0.01),

                    quality_score=0.96 - (index * 0.08),

                    aperture_radius=4.0 + (index * 0.2),

                    annulus_inner_radius=7.0 + (index * 0.2),

                    annulus_outer_radius=10.0 + (index * 0.2),

                )

            )

            light_curves.append(

                LightCurveSeries(

                    object_name="Demo",

                    source_id=entry.source_id,

                    source_name=entry.name,

                    filter_name="V",

                    candidate_score=9.5 - (index * 2.5),

                    variability_metrics={

                        "mad": 0.03 + (index * 0.01),

                        "rms": 0.05 + (index * 0.02),

                        "amplitude": 0.24 - (index * 0.05),

                        "reduced_chi2": 3.0 - (index * 0.6),

                        "von_neumann": 0.7 + (index * 0.2),

                        "stetson_j": 1.6 - (index * 0.4),

                    },

                )

            )

            file_results.append(

                FileScanResult(

                    path=source_path,

                    object_folder="Demo",

                    metadata=ObservationMetadata(

                        date_obs=datetime(2026, 3, 16, 1, index, 0),

                        filter_name="V",

                        exposure_seconds=60.0,

                        width=2048,

                        height=1536,

                        object_name="Demo",

                        binning="1x1",

                    ),

                    wcs_status=WcsStatus.SOLVED,

                )

            )

        report = ProcessingReport(

            object_name="Demo",

            files_processed=3,

            solved_files=3,

            field_catalog=FieldCatalog(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=1.0, variable_stars=entries),

            measurements=measurements,

            light_curves=light_curves,

        )

        self.window._current_report = ScanReport(

            root_path=root,

            object_summaries=[ObjectScanSummary(object_name="Demo", files=file_results)],

        )

        self.window._current_processing_report = report

        self.window._populate_source_table(report)

        for source_name, label in (("Alpha", "detectable_variable"), ("Beta", "not_detectable")):

            row_index = next(row for row in range(self.window._source_table.rowCount()) if self.window._source_table.item(row, 0).text() == source_name)

            self.window._source_table.setCurrentCell(row_index, 0)

            self.window._source_table.selectRow(row_index)

            self.window._handle_source_selection_changed()

            label_index = self.window._differential_training_label_combo.findData(label)

            self.window._differential_training_label_combo.setCurrentIndex(label_index)

            self.window._save_differential_training_label()

        self.window._train_differential_candidate_model()

        gamma_row = next(row for row in range(self.window._source_table.rowCount()) if self.window._source_table.item(row, 0).text() == "Gamma")

        self.assertNotEqual(self.window._source_table.item(gamma_row, 13).text(), "-")

        self.assertIn("Latest model:", self.window._differential_training_status_label.text())


