    def test_restore_period_result_cache_recovers_saved_results(self) -> None:

        with tempfile.TemporaryDirectory() as temp_dir:

            root = Path(temp_dir)

            self.window._root_path_input.setText(str(root))

            self.window._settings = AppSettings.from_root(root)

            self.window._settings.literature_period_cache = {

                "Demo": {

                    "vsx|vsx-1": {

                        "period_days": 1.2345,

                        "eclipse_duration_hours": 2.75,

                        "source": "VSX",

                    }

                }

            }

            self.window._settings.calculated_period_cache = {

                "Demo": {

                    "vsx-1|R": {

                        "period_hours": 12.0,

                        "periodic_harmonics": 2,

                        "method": "harmonic_fit",

                        "eclipse_duration_hours": 1.5,

                        "origin": "comparison_fit",

                        "comparison_source_ids": ["ref-1"],

                    }

                }

            }



            report = ProcessingReport(

                object_name="Demo",

                files_processed=1,

                solved_files=1,

                field_catalog=FieldCatalog(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=1.0, variable_stars=[]),

                measurements=[],

                light_curves=[],

            )



            self.window._restore_period_result_cache(report)



            literature_result = self.window._literature_period_results[("vsx", "vsx-1")]

            calculated_result = self.window._calculated_period_results[("vsx-1", "R")]

            self.assertAlmostEqual(literature_result.period_days, 1.2345)

            self.assertAlmostEqual(literature_result.eclipse_duration_hours or 0.0, 2.75)

            self.assertEqual(literature_result.source, "VSX")

            self.assertAlmostEqual(calculated_result.period_hours, 12.0)

            self.assertEqual(calculated_result.periodic_harmonics, 2)

            self.assertEqual(calculated_result.method, "harmonic_fit")

            self.assertIn(("vsx-1", "R"), self.window._comparison_fit_cached_series_keys)

            self.assertNotIn(("vsx-1", "R"), self.window._manual_period_override_series_keys)



