        infer_fit_period_result.assert_called_once()

        fitted_series = infer_fit_period_result.call_args.args[0]

        self.assertEqual(len(fitted_series.points), 2)

        self.assertEqual(

            [point.file_path.name for point in fitted_series.points],

            ["frame_00.fits", "frame_02.fits"],

        )

        self.assertAlmostEqual(self.window._calculated_period_results[("vsx-1", "R")].period_hours, 18.0)

        self.assertEqual(self.window._source_table.item(0, 9).text(), "0.7500")



