    def test_switching_to_sky_view_mode_shows_standalone_catalog_panel(self) -> None:

        packaged_objects = load_local_sky_atlas_objects()

        scientific_objects = packaged_objects + (
            SkyAtlasObject(
                name="HIP 32349",
                object_type="Star",
                ra_deg=101.2875,
                dec_deg=-16.7161,
                magnitude=-1.46,
                catalog="Hipparcos",
                searchable=False,
                label_visible=False,
            ),
        )

        with (
            patch("photometry_app.ui.main_window.load_sky_atlas_objects", return_value=scientific_objects),
            patch.object(self.window, "showMaximized") as show_maximized,
        ):

            self.window._handle_app_mode_changed(AppMode.SKY_VIEW)

        self.assertEqual(self.window._current_app_mode(), AppMode.SKY_VIEW)

        self.assertEqual(self.window._app_mode_stack.currentWidget(), self.window._sky_view_panel)

        self.assertTrue(self.window._app_mode_sky_view_action.isChecked())

        self.assertEqual(self.window.windowTitle(), "Citizen Astronomy - Sky View")

        self.assertTrue(self.window._sky_view_scientific_catalog_loaded)

        self.assertTrue(any(item.catalog == "Hipparcos" for item in self.window._sky_view_catalog_objects))

        self.assertFalse(hasattr(self.window, "_sky_view_results_table"))

        self.assertIsInstance(self.window._sky_view_canvas, QOpenGLWidget)

        self.assertIs(self.window._sky_view_canvas.parent(), self.window._sky_view_overlay_container)

        self.assertIs(self.window._sky_view_overlay_menu_bar.parent(), self.window._sky_view_overlay_container)

        self.assertIs(self.window._sky_view_object_panel.parent(), self.window._sky_view_overlay_container)

        self.assertTrue(self.window._sky_view_object_panel.isHidden())

        self.assertFalse(self.window._sky_view_status_label.isVisible())

        self.assertFalse(self.window._sky_view_detail_label.isVisible())

        self.assertFalse(self.window.statusBar().isVisible())

        self.window._sky_view_overlay_container.resize(900, 600)

        self.window._sky_view_overlay_container._update_dock_visibility(QPoint(450, 592))

        self.assertEqual(self.window._sky_view_canvas.geometry(), self.window._sky_view_overlay_container.rect())

        self.assertGreater(self.window._sky_view_overlay_menu_bar.y(), 520)

        self.assertLess(self.window._sky_view_overlay_menu_bar.x(), 360)

        self.assertLess(self.window._sky_view_object_panel.x(), 24)

        self.assertLess(self.window._sky_view_object_panel.y(), 24)

        self.assertGreaterEqual(self.window._sky_view_object_panel.width(), 280)

        self.window._sky_view_overlay_container._update_dock_visibility(QPoint(450, 80))

        self.assertGreater(self.window._sky_view_overlay_menu_bar.y(), 580)

        show_maximized.assert_called_once()

        self.assertEqual(self.window._sky_view_full_screen_button.text(), "")


