    def test_sky_view_time_flow_advances_by_default_and_can_pause(self) -> None:

        with patch("photometry_app.ui.main_window.load_sky_atlas_objects", return_value=load_local_sky_atlas_objects()):

            self.window._handle_app_mode_changed(AppMode.SKY_VIEW)

        self.assertTrue(self.window._sky_view_time_flow_enabled)

        self.assertTrue(self.window._sky_view_time_flow_button.isChecked())

        self.assertTrue(self.window._sky_view_time_flow_timer.isActive())

        self.assertEqual(self.window._sky_view_time_flow_button.toolTip(), "Pause time")

        selected_time = datetime(2026, 5, 25, 22, 15, tzinfo=UTC)

        self.window._set_sky_view_observation_time(selected_time)

        self.window._set_sky_view_time_rate(2.0)

        self.window._sky_view_simulation_clock._base_monotonic_seconds -= 0.125

        self.window._advance_sky_view_time_flow()

        advanced_time = self.window._sky_view_canvas._observation_time_utc

        self.assertGreater((advanced_time - selected_time).total_seconds(), 0.2)

        self.assertLess((advanced_time - selected_time).total_seconds(), 0.6)

        self.assertEqual(self.window._sky_view_canvas._sky_view_simulation_time_rate, 2.0)

        self.window._sky_view_time_flow_button.setChecked(False)

        self.assertFalse(self.window._sky_view_time_flow_enabled)

        self.assertFalse(self.window._sky_view_time_flow_timer.isActive())

        self.assertEqual(self.window._sky_view_time_flow_button.toolTip(), "Play time")

        paused_time = self.window._sky_view_canvas._observation_time_utc

        self.window._sky_view_time_flow_last_monotonic = monotonic() - 10.0

        self.window._advance_sky_view_time_flow()

        self.assertEqual(self.window._sky_view_canvas._observation_time_utc, paused_time)

    def test_sky_view_fractional_time_updates_sidereal_rotation_smoothly(self) -> None:

        widget = _SkyAtlasViewWidget()
        start_time = datetime(2026, 5, 25, 22, 15, tzinfo=UTC)
        widget.set_observation_time(start_time)
        first_matrix = widget._equatorial_to_horizon_matrix

        widget.set_simulation_frame_time(start_time + timedelta(milliseconds=125), time_rate=1.0, playing=True)
        second_matrix = widget._equatorial_to_horizon_matrix

        self.assertNotEqual(first_matrix, second_matrix)
        self.assertLess(abs(second_matrix[0][0] - first_matrix[0][0]), 0.001)


