    def test_sky_view_overlapping_labels_prefer_selected_object(self) -> None:

        widget = _SkyAtlasViewWidget()

        selected_star = SkyAtlasObject(
            name="Toliman",
            object_type="Star",
            ra_deg=219.9,
            dec_deg=-60.8,
            magnitude=1.35,
            catalog="Hipparcos",
            searchable=True,
            label_visible=True,
        )

        nearby_star = SkyAtlasObject(
            name="Rigil Kentaurus",
            object_type="Star",
            ra_deg=219.902,
            dec_deg=-60.835,
            magnitude=0.01,
            catalog="Hipparcos",
            searchable=True,
            label_visible=True,
        )

        widget.set_selected_object(selected_star)

        pixmap = QPixmap(640, 420)

        painter = QPainter(pixmap)

        try:

            selected_candidate = widget._build_object_label_candidate(
                painter,
                selected_star,
                1.35,
                hit_radius=12.0,
                x=100.0,
                y=100.0,
                is_star=True,
            )

            nearby_candidate = widget._build_object_label_candidate(
                painter,
                nearby_star,
                0.01,
                hit_radius=12.0,
                x=101.0,
                y=100.5,
                is_star=True,
            )

        finally:

            painter.end()

        resolved = widget._resolved_non_overlapping_object_label_candidates(
            (selected_candidate, nearby_candidate),
            rect=QRectF(0.0, 0.0, 640.0, 420.0),
            object_avoid_bounds={
                selected_star: QRectF(86.0, 86.0, 28.0, 28.0),
                nearby_star: QRectF(87.0, 86.5, 28.0, 28.0),
            },
        )

        self.assertEqual(len(resolved), 1)

        self.assertEqual(resolved[0][4], "Toliman")


