    def test_sky_view_bright_star_spikes_fade_toward_tips_and_scale_with_brightness(self) -> None:

        widget = _SkyAtlasViewWidget()

        bright_sprite = widget._build_star_sprite_pixmap("#f8fbff", -1.5).toImage()

        dim_sprite = widget._build_star_sprite_pixmap("#f8fbff", 1.5).toImage()

        bright_center_y = bright_sprite.height() // 2

        bright_center_x = bright_sprite.width() // 2

        bright_alphas = [bright_sprite.pixelColor(x, bright_center_y).alpha() for x in range(bright_sprite.width())]

        bright_nonzero = [index for index, alpha in enumerate(bright_alphas) if alpha > 6]

        self.assertGreater(bright_alphas[bright_center_x + 4], bright_alphas[bright_center_x + 12])

        self.assertGreater(bright_alphas[bright_nonzero[-1] - 1], bright_alphas[bright_nonzero[-1]])

        self.assertGreater(bright_sprite.width(), dim_sprite.width())

        self.assertGreaterEqual(bright_sprite.width(), 32)


    def test_sky_view_star_sprite_keeps_crisp_core_with_soft_bloom_and_aura(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.set_star_spike_style("off")

        sprite = widget._build_star_sprite_pixmap("#d7e7ff", 0.0).toImage()

        center_y = sprite.height() // 2

        center_x = sprite.width() // 2

        alphas = [sprite.pixelColor(x, center_y).alpha() for x in range(sprite.width())]

        nonzero = [index for index, alpha in enumerate(alphas) if alpha > 2]

        self.assertGreater(alphas[center_x], alphas[center_x + 2])

        self.assertGreater(alphas[center_x + 2], alphas[center_x + 5])

        self.assertGreater(alphas[center_x + 5], 0)

        self.assertGreater(alphas[nonzero[-1] - 2], alphas[nonzero[-1]])


