    def test_sky_view_wheel_zoom_preserves_drag_orientation(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(640, 420)

        rect = QRectF(0.0, 0.0, 640.0, 420.0)

        widget._set_camera_state(0.0, 89.0, 45.0)

        widget._apply_drag_rotation(0.0, 240.0, rect)

        forward_before = widget._camera_forward

        up_before = widget._camera_up

        right_before = widget._camera_right

        event = QWheelEvent(
            QPointF(320.0, 210.0),
            QPointF(320.0, 210.0),
            QPoint(0, 0),
            QPoint(0, 120),
            Qt.MouseButton.NoButton,
            Qt.KeyboardModifier.NoModifier,
            Qt.ScrollPhase.NoScrollPhase,
            False,
        )

        widget.wheelEvent(event)

        self.assertLess(widget._field_width_deg, 45.0)

        self.assertLess(widget._vector_angle(widget._camera_forward, forward_before), 1.0e-8)

        self.assertLess(widget._vector_angle(widget._camera_up, up_before), 1.0e-8)

        self.assertLess(widget._vector_angle(widget._camera_right, right_before), 1.0e-8)

