    def test_sky_view_moon_focus_fov_pair_preserves_viewport_aspect_ratio(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(800, 400)

        moon = self._sky_view_test_moon()

        widget.set_selected_object(moon)

        widget._set_camera_state(moon.ra_deg, moon.dec_deg, 1.6)

        rect = QRectF(0.0, 0.0, 800.0, 400.0)

        field_height_deg = widget._field_height_deg(rect)

        self.assertAlmostEqual(widget._field_width_deg, 1.6, places=6)
        self.assertAlmostEqual(field_height_deg, 0.8, places=6)
        self.assertAlmostEqual(widget._field_width_deg / field_height_deg, rect.width() / rect.height(), places=6)


    def test_sky_view_moon_focus_repeated_zoom_in_does_not_wrap_to_normal_floor(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(800, 400)

        moon = self._sky_view_test_moon()

        widget.set_selected_object(moon)

        widget._set_camera_state(moon.ra_deg, moon.dec_deg, 2.0)

        rect = QRectF(0.0, 0.0, 800.0, 400.0)

        fov_pairs = [(widget._field_width_deg, widget._field_height_deg(rect))]

        for _step in range(5):

            widget.wheelEvent(self._sky_view_zoom_in_event())

            fov_pairs.append((widget._field_width_deg, widget._field_height_deg(rect)))

        widths = [pair[0] for pair in fov_pairs]

        heights = [pair[1] for pair in fov_pairs]

        self.assertTrue(all(later < earlier for earlier, later in zip(widths, widths[1:])))
        self.assertTrue(all(later < earlier for earlier, later in zip(heights, heights[1:])))
        self.assertTrue(all(width < 2.0 for width in widths[1:]))
        self.assertTrue(all(height < 1.0 for height in heights[1:]))
        for field_width_deg, field_height_deg in fov_pairs:

            self.assertAlmostEqual(field_width_deg / field_height_deg, 2.0, places=6)


