        widget.set_show_ground(False)

        objects = tuple(
            SkyAtlasObject(
                name=f"HIP Spatial {index}",
                object_type="Star",
                ra_deg=float(index),
                dec_deg=0.0,
                magnitude=2.2,
                catalog="Hipparcos",
                searchable=False,
                label_visible=False,
                selectable=False,
            )
            for index in range(360)
        )
        widget.set_objects(objects)

        original_project = widget._project_to_rect

        projection_call_count = 0

        def counting_project(ra_deg: float, dec_deg: float, rect: QRectF) -> tuple[float, float] | None:

            nonlocal projection_call_count

            projection_call_count += 1

            return original_project(ra_deg, dec_deg, rect)

        with patch.object(widget, "_project_to_rect", side_effect=counting_project):

            visible_names = {
                visible_object.sky_object.name
                for visible_object in widget._collect_visible_objects(QRectF(0.0, 0.0, 640.0, 420.0))
            }

        self.assertIn("HIP Spatial 0", visible_names)

        self.assertLess(projection_call_count, 60)


