    def test_sky_view_moon_debug_flag_combinations_are_finite_and_predictable(self) -> None:

        widget = _SkyAtlasViewWidget()
        widget.resize(320, 220)
        scene = widget._build_sky_view_render_scene(QRectF(0.0, 0.0, 320.0, 220.0), [], {}, [], [], timing_enabled=False)
        center_altitude_deg = math.degrees(math.asin(max(-1.0, min(1.0, scene.camera_forward[2]))))
        center_azimuth_deg = math.degrees(math.atan2(scene.camera_forward[0], scene.camera_forward[1])) % 360.0
        moon_state = MoonState(
            observation_time_utc=scene.observation_time_utc,
            observer_latitude_deg=scene.observer_latitude_deg,
            observer_longitude_deg=scene.observer_longitude_deg,
            observer_elevation_m=scene.observer_elevation_m,
            ra_deg=0.0,
            dec_deg=0.0,
            altitude_deg=center_altitude_deg,
            azimuth_deg=center_azimuth_deg,
            distance_km=384_000.0,
            angular_diameter_deg=2.0,
            phase_angle_deg=80.0,
            illuminated_fraction=0.18,
            moon_direction_equatorial=(1.0, 0.0, 0.0),
            moon_to_sun_direction_equatorial=(0.0, 0.0, 1.0),
        )

        for mask in range(16):
            widget.moon_debug_disable_terrain_normals = bool(mask & 1)
            widget.moon_debug_exaggerate_terrain_normals = bool(mask & 2)
            widget.moon_debug_disable_earthshine = bool(mask & 4)
            widget.moon_debug_disable_atmosphere = bool(mask & 8)
            widget.moon_debug_orientation_overlay = bool(mask & 1)
            draw_state = widget._build_moon_draw_state(scene, moon_state)
            self.assertIsNotNone(draw_state)
            assert draw_state is not None
            finite_values = (
                draw_state.terrain_normal_strength,
                draw_state.terrain_normal_strength_global,
                draw_state.terrain_normal_strength_terminator,
                draw_state.earthshine_strength,
                draw_state.earthshine_floor,
                draw_state.atmosphere_extinction,
                *draw_state.atmosphere_tint_rgb,
            )
            self.assertTrue(all(math.isfinite(value) for value in finite_values))
            if widget.moon_debug_disable_terrain_normals:
                self.assertEqual(draw_state.terrain_normal_strength, 0.0)
            else:
                if widget.moon_debug_exaggerate_terrain_normals:
                    base_global = DEFAULT_MOON_VISUAL_SETTINGS.terrain_normal_strength_global_exaggerated
                    base_terminator = DEFAULT_MOON_VISUAL_SETTINGS.terrain_normal_strength_terminator_exaggerated
                else:
                    base_global = DEFAULT_MOON_VISUAL_SETTINGS.terrain_normal_strength_global
                    base_terminator = DEFAULT_MOON_VISUAL_SETTINGS.terrain_normal_strength_terminator
                expected_global, expected_terminator = MoonRendererGL.resolved_terrain_normal_strength_components(
                    base_global,
                    base_terminator,
                    draw_state.diameter_px,
                )
                self.assertAlmostEqual(draw_state.terrain_normal_strength_global, expected_global)
                self.assertAlmostEqual(draw_state.terrain_normal_strength_terminator, expected_terminator)
                self.assertAlmostEqual(draw_state.terrain_normal_strength, max(expected_global, expected_terminator))
            if widget.moon_debug_disable_earthshine:
                self.assertEqual(draw_state.earthshine_strength, 0.0)
                self.assertEqual(draw_state.earthshine_floor, 0.0)
            if widget.moon_debug_disable_atmosphere:
                self.assertEqual(draw_state.atmosphere_extinction, 1.0)
                self.assertEqual(draw_state.atmosphere_tint_rgb, (1.0, 1.0, 1.0))


    def test_sky_view_moon_debug_options_keep_texture_isolation_flags_mutually_exclusive(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.set_moon_debug_options(force_global_texture_only=True)
        self.assertTrue(widget.moon_debug_force_global_texture_only)
        self.assertTrue(widget.moon_debug_disable_tiled_textures)

        widget.set_moon_debug_options(
            debug_render_mode="albedo_only",
            overlay_enabled=True,
            force_global_texture_only=True,
            force_tiled_texture_only=True,
            disable_tone_mapping=True,
        )

        self.assertEqual(widget.moon_debug_render_mode, "albedo_only")
        self.assertTrue(widget.moon_debug_overlay_enabled)
        self.assertFalse(widget.moon_debug_force_global_texture_only)
        self.assertFalse(widget.moon_debug_disable_tiled_textures)
        self.assertTrue(widget.moon_debug_force_tiled_texture_only)
        self.assertTrue(widget.moon_debug_disable_tone_mapping)
        self.assertEqual(widget._resolved_moon_source_mix_mode(), "tiled_only_if_available")

        widget.set_moon_debug_options(disable_tiled_normals=True)
        self.assertTrue(widget.moon_debug_disable_tiled_normals)

        widget.set_moon_debug_options(
            polar_cap_blend_start_lat_deg=82.0,
            polar_cap_blend_end_lat_deg=70.0,
            polar_cap_normal_blend_start_lat_deg=76.0,
            polar_cap_normal_blend_end_lat_deg=74.0,
            polar_cap_local_contrast=2.8,
            polar_cap_boundary_match_strength=1.4,
            polar_cap_core_match_strength=-0.2,
        )
        self.assertAlmostEqual(widget.moon_debug_polar_cap_blend_start_lat_deg, 82.0)
        self.assertAlmostEqual(widget.moon_debug_polar_cap_blend_end_lat_deg, 82.1)
        self.assertAlmostEqual(widget.moon_debug_polar_cap_normal_blend_start_lat_deg, 82.0)
        self.assertAlmostEqual(widget.moon_debug_polar_cap_normal_blend_end_lat_deg, 82.1)
        self.assertAlmostEqual(widget.moon_debug_polar_cap_local_contrast, 2.0)
        self.assertAlmostEqual(widget.moon_debug_polar_cap_boundary_match_strength, 1.0)
        self.assertAlmostEqual(widget.moon_debug_polar_cap_core_match_strength, 0.0)


