    def test_sky_view_gl_stars_above_threshold_failure_falls_back_and_disables_session(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(640, 420)

        widget._sky_view_gl_stars_requested = True

        widget._SKY_VIEW_GL_STARS_MIN_SUBMITTED = 1

        widget._gl_functions = object()  # type: ignore[assignment]

        groups = {
            ("#ffffff", 126, 1.5): [QPointF(120.0, 130.0), QPointF(150.0, 180.0)],
        }

        class FailingGlStarFieldLayer:

            def __init__(self) -> None:

                self.call_count = 0

            def is_available(self, _functions) -> bool:

                return True

            def draw(self, _functions, _groups, _rect, _device_pixel_ratio) -> int:

                self.call_count += 1

                raise RuntimeError("simulated GL star failure")

        fake_layer = FailingGlStarFieldLayer()

        widget._gl_star_field_layer = fake_layer

        scene = widget._build_sky_view_render_scene(
            QRectF(0.0, 0.0, 640.0, 420.0),
            [],
            groups,
            [],
            [],
            timing_enabled=False,
        )

        painter = MagicMock()

        with patch.object(widget, "_draw_fast_star_groups") as draw_fast_star_groups:

            widget._qpainter_renderer.draw_fast_stars(painter, scene)

        draw_fast_star_groups.assert_called_once_with(painter, groups)

        painter.beginNativePainting.assert_called_once()

        painter.endNativePainting.assert_called_once()

        self.assertEqual(fake_layer.call_count, 1)

        self.assertTrue(widget._sky_view_gl_stars_disabled_for_session)

        self.assertEqual(widget._sky_view_gl_stars_last_candidate_count, 2)

        self.assertFalse(widget._sky_view_gl_stars_last_threshold_skip)

        self.assertEqual(widget._sky_view_gl_stars_fallback_count, 1)

        self.assertTrue(widget._sky_view_gl_stars_last_qpainter_fallback)

        second_painter = MagicMock()

        with patch.object(widget, "_draw_fast_star_groups") as draw_fast_star_groups:

            widget._qpainter_renderer.draw_fast_stars(second_painter, scene)

        draw_fast_star_groups.assert_called_once_with(second_painter, groups)

        second_painter.beginNativePainting.assert_not_called()

        self.assertEqual(fake_layer.call_count, 1)


