    def test_sky_view_gl_faint_star_input_excludes_rich_selectable_and_labeled_objects(self) -> None:

        widget = _SkyAtlasViewWidget()

        faint_background_star = SkyAtlasObject(
            name="HIP GL Fast",
            object_type="Star",
            ra_deg=1.0,
            dec_deg=1.0,
            magnitude=7.2,
            catalog="Hipparcos",
            searchable=False,
            label_visible=False,
            selectable=False,
        )

        faint_labeled_star = SkyAtlasObject(
            name="HIP Labeled",
            object_type="Star",
            ra_deg=2.0,
            dec_deg=1.0,
            magnitude=7.1,
            catalog="Hipparcos",
            searchable=False,
            label_visible=True,
            selectable=False,
        )

        faint_selectable_star = SkyAtlasObject(
            name="HIP Selectable",
            object_type="Star",
            ra_deg=3.0,
            dec_deg=1.0,
            magnitude=7.0,
            catalog="Hipparcos",
            searchable=False,
            label_visible=False,
            selectable=True,
        )

        bright_star = SkyAtlasObject(
            name="HIP Bright Rich",
            object_type="Star",
            ra_deg=4.0,
            dec_deg=1.0,
            magnitude=2.4,
            catalog="Hipparcos",
            searchable=False,
            label_visible=False,
            selectable=False,
        )

        galaxy = SkyAtlasObject(
            name="Visible Galaxy",
            object_type="Galaxy",
            ra_deg=5.0,
            dec_deg=1.0,
            magnitude=3.0,
            catalog="Test",
            selectable=False,
        )

        visible_objects = [
            _SkyVisibleObject(faint_background_star, 100.0, 110.0, 0.8, 7.2, 45.0),
            _SkyVisibleObject(faint_labeled_star, 120.0, 110.0, 0.8, 7.1, 45.0),
            _SkyVisibleObject(faint_selectable_star, 140.0, 110.0, 0.8, 7.0, 45.0),
            _SkyVisibleObject(bright_star, 160.0, 110.0, 1.0, 2.4, 45.0),
            _SkyVisibleObject(galaxy, 180.0, 110.0, 1.0, 3.0, 45.0),
        ]

        fast_star_groups, rich_objects, gpu_star_draws = widget._partition_visible_objects(visible_objects)

        self.assertEqual(sum(len(points) for points in fast_star_groups.values()), 1)

        self.assertEqual([visible_object.sky_object for visible_object in rich_objects], [galaxy, bright_star, faint_selectable_star, faint_labeled_star])

        self.assertEqual(gpu_star_draws, [])


