    def test_sky_view_gl_atmosphere_projection_uniforms_use_scene_camera_and_viewport(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(640, 420)

        rect = QRectF(0.0, 0.0, 640.0, 420.0)

        widget._set_camera_orientation_state(widget._horizon_vector_from_az_alt(135.0, 25.0), (0.0, 0.0, 1.0), 92.0)

        with patch.object(widget, "_projected_grid_device_pixel_ratio_key", return_value=1.5):

            scene = widget._build_sky_view_render_scene(rect, [], {}, [], [], timing_enabled=False)

        uniforms = widget._build_gl_projection_uniforms(scene)

        self.assertEqual(uniforms.viewport_rect, rect)

        self.assertEqual(uniforms.viewport_width_px, 960)

        self.assertEqual(uniforms.viewport_height_px, 630)

        self.assertAlmostEqual(uniforms.device_pixel_ratio, 1.5, places=6)

        self.assertAlmostEqual(uniforms.half_horizontal_fov_rad * 2.0 * 180.0 / np.pi, scene.field_width_deg, places=6)

        self.assertAlmostEqual(uniforms.half_vertical_fov_rad * 2.0 * 180.0 / np.pi, scene.field_height_deg, places=6)

        self.assertAlmostEqual(sum(component * component for component in uniforms.camera_forward), 1.0, places=6)

        self.assertAlmostEqual(sum(component * component for component in uniforms.camera_up), 1.0, places=6)

        self.assertAlmostEqual(sum(component * component for component in uniforms.camera_right), 1.0, places=6)

        self.assertAlmostEqual(sum(lhs * rhs for lhs, rhs in zip(uniforms.camera_forward, uniforms.camera_up, strict=False)), 0.0, places=6)

        self.assertAlmostEqual(sum(lhs * rhs for lhs, rhs in zip(uniforms.camera_forward, uniforms.camera_right, strict=False)), 0.0, places=6)

        self.assertEqual(uniforms.projection_version, widget._SKY_VIEW_GL_PROJECTION_VERSION)


