    def test_sky_view_grid_cull_keeps_edge_crossing_lines(self) -> None:

        cases = (
            (170.0, -50.38, 125.9, 1415.0, 771.0),
            (124.16, -61.32, 25.9, 1415.0, 771.0),
            (170.0, -50.38, 8.0, 1415.0, 771.0),
        )

        for ra_deg, dec_deg, field_width_deg, width, height in cases:

            widget = _SkyAtlasViewWidget()

            widget.resize(int(width), int(height))

            rect = QRectF(0.0, 0.0, width, height)

            widget._set_camera_state(ra_deg, dec_deg, field_width_deg)

            field_height = widget._field_height_deg(rect)

            ra_step = widget._grid_axis_step(widget._field_width_deg)

            dec_step = widget._grid_axis_step(field_height)

            meridian_segments, parallel_segments = widget._equatorial_grid_segment_counts()

            for grid_ra_deg in widget._equatorial_grid_ra_values(rect, ra_step):

                coarse = tuple((grid_ra_deg, sample_dec_deg) for sample_dec_deg in widget._sample_range(-90.0, 90.0, meridian_segments))

                fine = tuple((grid_ra_deg, sample_dec_deg) for sample_dec_deg in widget._sample_range(-90.0, 90.0, 144))

                if any(widget._project_to_rect(sample_ra_deg, sample_dec_deg, rect) is not None for sample_ra_deg, sample_dec_deg in fine):

                    self.assertTrue(widget._equatorial_curve_may_intersect_view(coarse, rect))

            for grid_dec_deg in widget._equatorial_grid_dec_values(rect, dec_step):

                if abs(abs(grid_dec_deg) - 90.0) <= 1.0e-9:

                    continue

                coarse = tuple((sample_ra_deg % 360.0, grid_dec_deg) for sample_ra_deg in widget._sample_range(0.0, 360.0, parallel_segments))

                fine = tuple((sample_ra_deg % 360.0, grid_dec_deg) for sample_ra_deg in widget._sample_range(0.0, 360.0, 192))

                if any(widget._project_to_rect(sample_ra_deg, sample_dec_deg, rect) is not None for sample_ra_deg, sample_dec_deg in fine):

                    self.assertTrue(widget._equatorial_curve_may_intersect_view(coarse, rect))



