    def test_sky_view_drag_tracks_screen_direction(self) -> None:

        rect = QRectF(0.0, 0.0, 640.0, 420.0)

        def projected_center_after_drag(delta_x: float, delta_y: float) -> tuple[tuple[float, float], tuple[float, float]]:

            widget = _SkyAtlasViewWidget()

            widget.resize(640, 420)

            widget._set_camera_state(83.8, -5.0, 95.0)

            target_ra_deg = widget._center_ra_deg

            target_dec_deg = widget._center_dec_deg

            before = widget._project_to_rect(target_ra_deg, target_dec_deg, rect)

            self.assertIsNotNone(before)

            widget._apply_drag_rotation(delta_x, delta_y, rect)

            after = widget._project_to_rect(target_ra_deg, target_dec_deg, rect)

            self.assertIsNotNone(after)

            assert before is not None

            assert after is not None

            return before, after

        before, after = projected_center_after_drag(32.0, 0.0)

        self.assertGreater(after[0], before[0])

        before, after = projected_center_after_drag(-32.0, 0.0)

        self.assertLess(after[0], before[0])

        before, after = projected_center_after_drag(0.0, 24.0)

        self.assertGreater(after[1], before[1])

        before, after = projected_center_after_drag(0.0, -24.0)

        self.assertLess(after[1], before[1])


    def test_sky_view_small_drag_rotates_incrementally(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(640, 420)

        widget.set_observation_time(datetime(2026, 5, 21, tzinfo=UTC))

        widget._set_camera_state(83.8, -5.0, 95.0)

        start_ra_deg = widget._center_ra_deg

        start_dec_deg = widget._center_dec_deg

        rect = QRectF(0.0, 0.0, 640.0, 420.0)

        target_ra_deg = widget._center_ra_deg

        target_dec_deg = widget._center_dec_deg

        before_projection = widget._project_to_rect(target_ra_deg, target_dec_deg, rect)

        self.assertIsNotNone(before_projection)

        widget._apply_drag_rotation(3.0, 2.0, rect)

        after_projection = widget._project_to_rect(target_ra_deg, target_dec_deg, rect)

        self.assertIsNotNone(after_projection)

        assert before_projection is not None

        assert after_projection is not None

        self.assertAlmostEqual(after_projection[0] - before_projection[0], 3.0, delta=0.05)

        self.assertAlmostEqual(after_projection[1] - before_projection[1], 2.0, delta=0.06)

        self.assertLess(abs(widget._ra_delta(widget._center_ra_deg, start_ra_deg)), 0.6)

        self.assertLess(abs(widget._center_dec_deg - start_dec_deg), 0.6)

        widget._apply_drag_rotation(-3.0, -2.0, rect)

        self.assertAlmostEqual(widget._center_ra_deg, start_ra_deg, delta=0.01)

        self.assertAlmostEqual(widget._center_dec_deg, start_dec_deg, delta=0.01)


    def test_sky_view_drag_keeps_horizon_level_at_normal_altitude(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(640, 420)

        rect = QRectF(0.0, 0.0, 640.0, 420.0)

        widget._set_camera_state(180.0, 20.0, 50.0)

        for delta_x, delta_y in ((120.0, 40.0), (-30.0, 80.0), (90.0, -60.0), (-140.0, 20.0)):

            widget._apply_drag_rotation(delta_x, delta_y, rect)

            level_up = widget._camera_up_for_forward(widget._camera_forward)

            expected_right = widget._camera_right_vector(widget._camera_forward, level_up)

            self.assertLess(widget._vector_angle(widget._camera_up, level_up), 1.0e-8)

            self.assertLess(widget._vector_angle(widget._camera_right, expected_right), 1.0e-8)

            self.assertAlmostEqual(widget._camera_right[2], 0.0, places=8)

        camera_right = widget._camera_right_vector(widget._camera_forward, widget._camera_up)

        self.assertAlmostEqual(sum(component * component for component in widget._camera_forward), 1.0, places=6)

        self.assertAlmostEqual(sum(component * component for component in widget._camera_up), 1.0, places=6)

        self.assertAlmostEqual(sum(component * component for component in widget._camera_right), 1.0, places=6)

        self.assertAlmostEqual(widget._vector_dot(widget._camera_forward, widget._camera_up), 0.0, places=6)

        self.assertAlmostEqual(widget._vector_dot(widget._camera_forward, widget._camera_right), 0.0, places=6)

        self.assertAlmostEqual(widget._vector_dot(widget._camera_up, widget._camera_right), 0.0, places=6)

        self.assertLess(widget._vector_angle(widget._camera_right, camera_right), 1.0e-8)

        self.assertGreater(widget._vector_dot(widget._vector_cross(widget._camera_forward, widget._camera_up), widget._camera_right), 0.999999)

    def _assert_sky_view_near_zenith_drag_basis_continuity(
        self,
        drag_sequence: tuple[tuple[float, float], ...],
    ) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(640, 420)

        rect = QRectF(0.0, 0.0, 640.0, 420.0)

        initial_forward = widget._horizon_vector_from_az_alt(135.0, 89.999)

        widget._set_camera_orientation_state(initial_forward, widget._camera_up_for_forward(initial_forward), 5.0)

        initial_right = widget._camera_right

        initial_up = widget._camera_up

        test_star_horizon = widget._vector_normalize(
            (
                initial_forward[0] + initial_right[0] * 0.015 + initial_up[0] * 0.007,
                initial_forward[1] + initial_right[1] * 0.015 + initial_up[1] * 0.007,
                initial_forward[2] + initial_right[2] * 0.015 + initial_up[2] * 0.007,
            )
        )

        test_star_ra_deg, test_star_dec_deg = widget._vector_to_equatorial(widget._horizon_to_equatorial_vector(test_star_horizon))

        previous_forward = widget._camera_forward

        previous_up = widget._camera_up

        previous_right = widget._camera_right

        previous_projection = widget._project_to_rect(test_star_ra_deg, test_star_dec_deg, rect)

        self.assertIsNotNone(previous_projection)

        max_forward_step_deg = 0.0

        min_up_dot = 1.0

        min_right_dot = 1.0

        max_screen_step_px = 0.0

        for delta_x, delta_y in drag_sequence:

            widget._apply_drag_rotation(delta_x, delta_y, rect)

            current_forward = widget._camera_forward

            current_up = widget._camera_up

            current_right = widget._camera_right

            current_projection = widget._project_to_rect(test_star_ra_deg, test_star_dec_deg, rect)

            self.assertIsNotNone(current_projection)

            max_forward_step_deg = max(max_forward_step_deg, math.degrees(widget._vector_angle(previous_forward, current_forward)))

            min_up_dot = min(min_up_dot, widget._vector_dot(current_up, previous_up))

            min_right_dot = min(min_right_dot, widget._vector_dot(current_right, previous_right))

            assert previous_projection is not None

            assert current_projection is not None

            max_screen_step_px = max(
                max_screen_step_px,
                math.hypot(current_projection[0] - previous_projection[0], current_projection[1] - previous_projection[1]),
            )

            self.assertAlmostEqual(sum(component * component for component in current_forward), 1.0, places=6)

            self.assertAlmostEqual(sum(component * component for component in current_up), 1.0, places=6)

            self.assertAlmostEqual(sum(component * component for component in current_right), 1.0, places=6)

            self.assertAlmostEqual(widget._vector_dot(current_forward, current_up), 0.0, places=6)

            self.assertAlmostEqual(widget._vector_dot(current_forward, current_right), 0.0, places=6)

            self.assertAlmostEqual(widget._vector_dot(current_up, current_right), 0.0, places=6)

            previous_forward = current_forward

            previous_up = current_up

            previous_right = current_right

            previous_projection = current_projection

        self.assertLess(max_forward_step_deg, 0.02)

        self.assertGreater(min_up_dot, 0.999999)

        self.assertGreater(min_right_dot, 0.999999)

        self.assertLess(max_screen_step_px, 2.0)

