    def test_sky_view_ground_and_appearance_controls_sync_to_canvas(self) -> None:

        with patch("photometry_app.ui.main_window.load_sky_atlas_objects", return_value=load_local_sky_atlas_objects()):

            self.window._handle_app_mode_changed(AppMode.SKY_VIEW)

        self.assertFalse(self.window._sky_view_equatorial_grid_button.isChecked())

        self.assertFalse(self.window._sky_view_alt_az_grid_button.isChecked())

        self.assertFalse(self.window._sky_view_canvas.show_equatorial_grid())

        self.assertFalse(self.window._sky_view_canvas.show_alt_az_grid())

        self.assertFalse(self.window._sky_view_ground_button.isChecked())

        self.assertFalse(self.window._sky_view_canvas.show_ground())

        self.window._sky_view_equatorial_grid_button.setChecked(False)

        self.assertFalse(self.window._sky_view_canvas.show_equatorial_grid())

        self.window._sky_view_alt_az_grid_button.setChecked(False)

        self.assertFalse(self.window._sky_view_canvas.show_alt_az_grid())

        self.window._sky_view_ground_button.setChecked(True)

        self.assertTrue(self.window._sky_view_canvas.show_ground())

        self.window._sky_view_bloom_strength_spin.setValue(1.35)

        self.assertAlmostEqual(self.window._sky_view_canvas.star_bloom_strength(), 1.35, places=2)

        self.window._show_sky_view_options_popup()

        options_widget = self.window._sky_view_options_menu_action.defaultWidget()

        self.assertIsNotNone(options_widget)

        assert options_widget is not None

        self.assertGreaterEqual(options_widget.width(), options_widget.sizeHint().width())

        self.assertGreaterEqual(self.window._sky_view_options_menu.width(), options_widget.width())

        self.assertGreaterEqual(self.window._sky_view_magnitude_limit_spin.width(), 112)

        self.assertGreaterEqual(self.window._sky_view_bloom_strength_spin.width(), 112)

        for spin_box, original_value, expected_step in (
            (self.window._sky_view_magnitude_limit_spin, 9.5, 0.5),
            (self.window._sky_view_bloom_strength_spin, 1.35, 0.05),
        ):

            option = QStyleOptionSpinBox()

            spin_box.initStyleOption(option)

            up_rect = spin_box.style().subControlRect(
                QStyle.ComplexControl.CC_SpinBox,
                option,
                QStyle.SubControl.SC_SpinBoxUp,
                spin_box,
            )

            down_rect = spin_box.style().subControlRect(
                QStyle.ComplexControl.CC_SpinBox,
                option,
                QStyle.SubControl.SC_SpinBoxDown,
                spin_box,
            )

            self.assertGreater(up_rect.width(), 0)

            self.assertGreater(down_rect.width(), 0)

            QTest.mouseClick(spin_box, Qt.MouseButton.LeftButton, Qt.KeyboardModifier.NoModifier, up_rect.center())

            self._app.processEvents()

            self.assertAlmostEqual(spin_box.value(), original_value + expected_step, places=2)

            QTest.mouseClick(spin_box, Qt.MouseButton.LeftButton, Qt.KeyboardModifier.NoModifier, down_rect.center())

            self._app.processEvents()

            self.assertAlmostEqual(spin_box.value(), original_value, places=2)

        classic_index = self.window._sky_view_spike_style_combo.findData("classic")

        self.assertGreaterEqual(classic_index, 0)

        self.window._sky_view_spike_style_combo.setCurrentIndex(classic_index)

        self.assertEqual(self.window._sky_view_canvas.star_spike_style(), "classic")

