    def test_sky_view_ground_mask_covers_below_horizon_and_not_above(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(1415, 771)

        rect = QRectF(0.0, 0.0, 1415.0, 771.0)

