        below_point = QPointF(rect.center().x(), rect.center().y() + 80.0)

        above_point = QPointF(rect.center().x(), rect.center().y() - 80.0)

        self.assertLess(widget._screen_point_to_horizon_vector(below_point, rect)[2], 0.0)

