    def test_sky_view_ground_draw_does_not_wrap_into_sky_when_looking_up(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(1368, 768)

        rect = QRectF(0.0, 0.0, 1368.0, 768.0)

        widget.set_show_ground(True)

        widget._set_camera_orientation_state(widget._horizon_vector_from_az_alt(90.0, 20.0), (0.0, 0.0, 1.0), 116.0)

        image = QImage(1368, 768, QImage.Format.Format_ARGB32_Premultiplied)

        image.fill(0)

        painter = QPainter(image)

        ground_path = widget._ground_mask_path(rect)

        widget._draw_ground(painter, rect, ground_path=ground_path)

        painter.end()

        self.assertIsNotNone(ground_path)

        sky_leak_count = 0

        painted_ground_count = 0

        for y_position in range(24, 744, 48):

            for x_position in range(24, 1344, 48):

                sample_point = QPointF(float(x_position), float(y_position))

                altitude_component = widget._screen_point_to_horizon_vector(sample_point, rect)[2]

                alpha = image.pixelColor(x_position, y_position).alpha()

                if altitude_component > 0.04 and alpha > 0:

                    sky_leak_count += 1

                if altitude_component < -0.04 and alpha > 0:

                    painted_ground_count += 1

        self.assertEqual(sky_leak_count, 0)

        self.assertGreater(painted_ground_count, 0)


    def test_sky_view_rendered_ground_layer_cache_hits_on_identical_state(self) -> None:

        with patch.dict(
            os.environ,
            {
                "CITIZEN_PHOTOMETRY_SKY_VIEW_TIMING": "1",
                "CITIZEN_PHOTOMETRY_SKY_VIEW_GROUND_DETAIL": "1",
            },
        ):

            widget = _SkyAtlasViewWidget()

        widget.resize(480, 260)

        rect = QRectF(0.0, 0.0, 480.0, 260.0)

        widget.set_show_ground(True)

        widget._set_camera_state(43.6, 9.1, 191.3)

        ground_path = widget._ground_mask_path(rect)

        self.assertIsNotNone(ground_path)

        assert ground_path is not None

        image = QImage(480, 260, QImage.Format.Format_ARGB32_Premultiplied)

        image.fill(0)

        painter = QPainter(image)

        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)

        try:

            widget._draw_ground(painter, rect, ground_path=ground_path)

            cache_entry = widget._rendered_ground_layer_cache

            widget._draw_ground(painter, rect, ground_path=ground_path)

        finally:

            painter.end()

        self.assertIsNotNone(cache_entry)

        assert cache_entry is not None

        self.assertFalse(cache_entry.image.isNull())

