    def test_sky_view_rendered_ground_layer_cache_matches_uncached_alpha_bounds(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(480, 260)

        rect = QRectF(0.0, 0.0, 480.0, 260.0)

        widget.set_show_ground(True)

        widget._set_camera_state(43.6, 9.1, 191.3)

        ground_path = widget._ground_mask_path(rect)

        self.assertIsNotNone(ground_path)

        assert ground_path is not None


        def alpha_bounds(image: QImage) -> tuple[tuple[int, int, int, int] | None, int]:

            min_x = image.width()

            min_y = image.height()

            max_x = -1

            max_y = -1

            alpha_count = 0

            for y_position in range(image.height()):

                for x_position in range(image.width()):

                    if image.pixelColor(x_position, y_position).alpha() == 0:

                        continue

                    min_x = min(min_x, x_position)

                    min_y = min(min_y, y_position)

                    max_x = max(max_x, x_position)

                    max_y = max(max_y, y_position)

                    alpha_count += 1

            if alpha_count == 0:

                return None, 0

            return (min_x, min_y, max_x, max_y), alpha_count

        uncached_image = QImage(480, 260, QImage.Format.Format_ARGB32_Premultiplied)

        uncached_image.fill(0)

        uncached_painter = QPainter(uncached_image)

        uncached_painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)

        widget._draw_ground_uncached(uncached_painter, rect, ground_path=ground_path)

        uncached_painter.end()

        widget._clear_rendered_ground_layer_cache()

        cached_image = QImage(480, 260, QImage.Format.Format_ARGB32_Premultiplied)

        cached_image.fill(0)

        cached_painter = QPainter(cached_image)

        cached_painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)

        widget._draw_ground(cached_painter, rect, ground_path=ground_path)

        cached_painter.end()

        uncached_bounds, uncached_alpha_count = alpha_bounds(uncached_image)

        cached_bounds, cached_alpha_count = alpha_bounds(cached_image)

        self.assertEqual(cached_bounds, uncached_bounds)

        self.assertLessEqual(abs(cached_alpha_count - uncached_alpha_count), 8)

        widget._clear_rendered_ground_layer_cache()

        widget._drag_origin = QPoint(10, 10)

        preview_image = QImage(480, 260, QImage.Format.Format_ARGB32_Premultiplied)

        preview_image.fill(0)

        preview_painter = QPainter(preview_image)

        preview_painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)

        try:

            widget._draw_ground(preview_painter, rect, ground_path=ground_path)

        finally:

            preview_painter.end()

            widget._drag_origin = None

        preview_bounds, preview_alpha_count = alpha_bounds(preview_image)

        self.assertEqual(preview_bounds, uncached_bounds)

        self.assertLessEqual(abs(preview_alpha_count - uncached_alpha_count), 8)


    def test_sky_view_horizon_atmosphere_uses_smooth_altitude_falloff(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(900, 520)

        rect = QRectF(0.0, 0.0, 900.0, 520.0)

        widget._set_camera_orientation_state(widget._horizon_vector_from_az_alt(180.0, 0.0), (0.0, 0.0, 1.0), 95.0)

        atmosphere_image = widget._horizon_atmosphere_image(rect)

        self.assertIsNotNone(atmosphere_image)

        assert atmosphere_image is not None

        x_position = atmosphere_image.width() // 2

        alpha_values = [atmosphere_image.pixelColor(x_position, y_position).alpha() for y_position in range(atmosphere_image.height())]

        visible_alpha_values = [alpha for alpha in alpha_values if alpha > 0]

        self.assertGreaterEqual(len(set(visible_alpha_values)), 16)

        self.assertGreater(max(visible_alpha_values), min(visible_alpha_values))

        self.assertGreater(max(visible_alpha_values), 30)

        self.assertLess(min(visible_alpha_values), 10)


