    def test_sky_view_ground_mask_full_view_follows_viewport_ground_classification(self) -> None:

        widget = _SkyAtlasViewWidget()

        widget.resize(800, 500)

        rect = QRectF(0.0, 0.0, 800.0, 500.0)

        widget.set_show_ground(True)

        matching_state = None

        ground_path = None

        for ra_deg in (0.0, 45.0, 90.0, 180.0, 270.0):

            for dec_deg in (-89.0, -70.0, -50.0, -30.0, 0.0, 30.0, 50.0, 70.0, 89.0):

                widget._set_camera_state(ra_deg, dec_deg, 70.0)

                horizon_points = widget._projected_horizon_polyline(rect, altitude_deg=0.0, sample_segments=360)

                candidate_path = widget._ground_mask_path(rect)

                if len(horizon_points) >= 2:

                    continue

                if not widget._screen_point_is_below_horizon(rect.center(), rect):

                    continue

                if candidate_path is None or not candidate_path.contains(rect.center()):

                    continue

                matching_state = (ra_deg, dec_deg)

                ground_path = candidate_path

                break

            if matching_state is not None:

                break

        self.assertIsNotNone(matching_state)

        self.assertIsNotNone(ground_path)


