    def test_scientific_sky_atlas_download_uses_cache_after_first_load(self) -> None:

        downloaded_objects = (
            SkyAtlasObject(
                name="HIP 12345",
                object_type="Star",
                ra_deg=12.3456,
                dec_deg=23.4567,
                magnitude=5.2,
                catalog="Hipparcos",
                searchable=False,
                label_visible=False,
            ),
        )

        with tempfile.TemporaryDirectory() as temp_dir:

            cache_dir = Path(temp_dir)

            with patch("photometry_app.core.sky_atlas._download_hipparcos_star_objects", return_value=downloaded_objects) as download_mock:

                first_load = load_sky_atlas_objects(cache_dir, maximum_scientific_magnitude=6.0, download_if_missing=True)

                second_load = load_sky_atlas_objects(cache_dir, maximum_scientific_magnitude=6.0, download_if_missing=True)

        self.assertEqual(download_mock.call_count, 1)

        self.assertTrue(any(item.catalog == "Hipparcos" for item in first_load))

        self.assertTrue(any(item.name == "Andromeda Galaxy" for item in first_load))

        self.assertEqual(first_load, second_load)


