    def test_setting_sky_explorer_source_image_preloads_preview_before_refresh(self) -> None:

        with tempfile.TemporaryDirectory() as temp_dir:

            root_path = Path(temp_dir)

            source_path = root_path / "sky_explorer_source.tif"

            source_path.write_bytes(b"test")

            self.window._root_path_input.setText(str(root_path))



            with (

                patch.object(self.window, "_preload_annotated_image_display_with_loading_dialog") as preload_preview,

                patch.object(self.window, "_apply_recommended_stretch_mode_for_loaded_image") as apply_stretch,

                patch.object(self.window, "_refresh_sky_explorer_image_view") as refresh_image_view,

            ):

                self.window._set_sky_explorer_source_image_path(source_path)



            self.assertEqual(self.window._current_app_mode(), AppMode.SKY_EXPLORER)

            self.assertEqual(self.window._sky_explorer_image_input.text(), str(source_path))

            preload_preview.assert_called_once_with(

                source_path,

                loading_text=f"Loading {source_path.name} for Sky Explorer preview.",

            )

            apply_stretch.assert_called_once_with(source_path, self.window._sky_explorer_image_stretch_combo)

            refresh_image_view.assert_called_once_with(reset_view=True, focus_selected=False)



    def test_sky_explorer_completion_populates_results_table(self) -> None:

        image_path = Path(self._state_dir.name) / "sky_explorer_source.fits"

        image_path.touch()

        display = build_annotated_image_display_from_array(np.ones((16, 16), dtype=np.float32), image_path=image_path)

        result = SkyExplorerResult(

            source_path=image_path,

            solved_field=SolvedField(

                center_ra_deg=10.0,

                center_dec_deg=20.0,

                radius_deg=0.5,

                width=16,

                height=16,

                wcs_path=image_path,

            ),

            used_astrometry_fallback=False,

            footprint=SkyExplorerFieldFootprint(

                center_ra_deg=10.0,

                center_dec_deg=20.0,

                radius_deg=0.5,

                width_deg=1.0,

                height_deg=0.75,

                corners=(

                    SkyExplorerCorner("Top Left", 9.5, 20.5),

                    SkyExplorerCorner("Top Right", 10.5, 20.5),

                    SkyExplorerCorner("Bottom Right", 10.5, 19.5),

                    SkyExplorerCorner("Bottom Left", 9.5, 19.5),

                ),

            ),

            objects=(

                SkyExplorerObject(

                    layer_key="deep_sky",

                    catalog="simbad",

                    source_id="M 31",

                    name="M 31",

                    object_type="Galaxy",

                    ra_deg=10.684,

                    dec_deg=41.269,

                    pixel_x=8.0,

                    pixel_y=7.0,

                    magnitude=3.44,

                    angular_distance_arcmin=12.5,

                    short_label="M 31",

                    metadata={"main_id": "M 31", "catalog_size_arcmin": 190.0},

                ),

            ),

            layer_summaries=(

                SkyExplorerLayerSummary(

                    layer_key="deep_sky",

                    title="Deep Sky",

                    returned_count=1,

                    displayed_count=1,

                ),

            ),

            warning_messages=(),

            summary_text="Resolved a 0.500 deg field and prepared Deep Sky: 1 for image overlay and table review.",

        )

        with patch.object(self.window, "_cached_annotated_image_display", return_value=display):
            self.window._handle_app_mode_changed(AppMode.SKY_EXPLORER)

            self.window._handle_sky_explorer_completed(result)

        header_labels = [

            self.window._sky_explorer_results_table.horizontalHeaderItem(column_index).text()

            for column_index in range(self.window._sky_explorer_results_table.columnCount())

        ]

        self.assertEqual(header_labels, ["Name", "Type", "Mag", "RA", "Dec", "Angular Size"])

        self.assertEqual(self.window._sky_explorer_results_table.rowCount(), 2)

        self.assertEqual(self.window._sky_explorer_results_table.item(0, 0).text(), "Galaxies (1 object)")

        self.assertEqual(self.window._sky_explorer_results_table.item(0, 0).textAlignment(), Qt.AlignmentFlag.AlignCenter)

        self.assertEqual(self.window._sky_explorer_results_table.columnSpan(0, 0), self.window._sky_explorer_results_table.columnCount())

        self.assertEqual(self.window._sky_explorer_results_table.verticalHeaderItem(0).text(), "")

        self.assertEqual(self.window._sky_explorer_results_table.verticalHeaderItem(1).text(), "1")

        self.assertEqual(self.window._sky_explorer_results_table.item(1, 0).text(), "M 31")

        self.assertEqual(self.window._sky_explorer_results_table.item(1, 5).text(), "190.00'")

        self.assertEqual(self.window._sky_explorer_status_label.text(), result.summary_text)


