                SkyExplorerObject("deep_sky", "simbad", "M 31", "M 31", "Galaxy", 10.1, 20.1, 4.0, 5.0, 3.44, 12.5, "M 31", {"main_id": "M 31"}),

                SkyExplorerObject("deep_sky", "simbad", "M 32", "M 32", "Galaxy", 10.2, 20.2, 11.0, 12.0, 8.08, 13.5, "M 32", {"main_id": "M 32"}),

