    def test_sky_explorer_color_relations_control_generated_marker_and_text_colors(self) -> None:

        settings = self.window._ensure_settings()

        settings.sky_explorer_marker_color_relation = "stroke_dark_fill_bright"

        settings.sky_explorer_text_color_relation = "dark"

        self.window._sky_explorer_object_group_color_overrides["nebula"] = "#22ccaa"


        dark_stroke, bright_fill = self.window._sky_explorer_object_type_colors_for_key("emission_nebula")

        self.assertLess(self.window._relative_color_luminance(dark_stroke), self.window._relative_color_luminance(bright_fill))


        settings.sky_explorer_marker_color_relation = "stroke_bright_fill_dark"

        inverted_stroke, inverted_fill = self.window._sky_explorer_object_type_colors_for_key("emission_nebula")

        self.assertEqual(inverted_stroke, bright_fill)

        self.assertEqual(inverted_fill, dark_stroke)


        self.assertEqual(

            self.window._sky_explorer_object_type_text_color_for_key("emission_nebula", stroke_color=inverted_stroke, fill_color=inverted_fill),

            inverted_fill,

        )

        settings.sky_explorer_text_color_relation = "bright"

        self.assertEqual(

            self.window._sky_explorer_object_type_text_color_for_key("emission_nebula", stroke_color=inverted_stroke, fill_color=inverted_fill),

            inverted_stroke,

        )


