            self.assertFalse(focus_mock.called)


            previous_block_state = self.window._sky_explorer_center_object_button.blockSignals(True)

            self.window._sky_explorer_center_object_button.setChecked(True)

            self.window._sky_explorer_center_object_button.blockSignals(previous_block_state)

            self.window._select_sky_explorer_result_object(first_object)

            self.window._handle_sky_explorer_result_selection_changed()

            focus_mock.assert_called()


