    def test_sky_explorer_object_selection_defaults_to_simple_mode(self) -> None:

        self.window._handle_app_mode_changed(AppMode.SKY_EXPLORER)

        header_labels = [

            self.window._sky_explorer_object_type_table.horizontalHeaderItem(column_index).text()

            for column_index in range(self.window._sky_explorer_object_type_table.columnCount())

        ]

        visible_rows = [

            row_index

            for row_index in range(self.window._sky_explorer_object_type_table.rowCount())

            if not self.window._sky_explorer_object_type_table.isRowHidden(row_index)

        ]

        self.assertEqual(self.window._current_sky_explorer_object_type_mode(), "simple")

        self.assertEqual(self.window._sky_explorer_object_type_mode_button.text(), "Simple")

        self.assertEqual(header_labels, ["Stroke Color", "Fill Color", "Text", "Group", "Object Type", "Description"])

        self.assertEqual(self.window._sky_explorer_object_type_table.columnCount(), 6)

        group_titles = {"Nebulae / ISM", "Galaxies", "Star Clusters / Associations"}

        member_rows = [

            row_index

            for row_index in visible_rows

            if self.window._sky_explorer_object_type_table.item(row_index, 4).text() not in group_titles

        ]

        group_rows = [

            row_index

            for row_index in visible_rows

            if self.window._sky_explorer_object_type_table.item(row_index, 4).text() in group_titles

        ]

        self.assertEqual(len(visible_rows), 9)

        self.assertEqual(len(member_rows), 6)

        self.assertEqual(len(group_rows), 3)

        self.assertEqual(self.window._sky_explorer_object_type_table.item(0, 4).text(), "Nebulae / ISM")

        self.assertEqual(self.window._sky_explorer_object_type_table.item(0, 4).checkState(), Qt.CheckState.Checked)

        first_member_row = member_rows[0]

        self.assertTrue(bool(self.window._sky_explorer_object_type_table.item(first_member_row, 0).text()))

        self.assertTrue(bool(self.window._sky_explorer_object_type_table.item(first_member_row, 1).text()))

        self.assertTrue(bool(self.window._sky_explorer_object_type_table.item(first_member_row, 2).text()))

        self.assertTrue(bool(self.window._sky_explorer_object_type_table.item(first_member_row, 3).text()))

        self.assertTrue(bool(self.window._sky_explorer_object_type_table.item(first_member_row, 4).text()))

        groups_by_title = {

            self.window._sky_explorer_object_type_table.item(row_index, 4).text(): self.window._sky_explorer_object_type_table.item(row_index, 3).text()

            for row_index in member_rows

        }

        self.assertEqual(groups_by_title.get("Galaxy"), "Galaxies")

        self.assertEqual(groups_by_title.get("Emission Nebula"), "Nebulae / ISM")

        self.assertEqual(groups_by_title.get("Open Cluster"), "Star Clusters / Associations")

        self.assertEqual(self.window._sky_explorer_select_all_button.text(), "Unselect All")


    def test_sky_explorer_object_type_group_row_toggles_members(self) -> None:

        self.window._handle_app_mode_changed(AppMode.SKY_EXPLORER)

        group_row = next(

            row_index

            for row_index in range(self.window._sky_explorer_object_type_table.rowCount())

            if self.window._sky_explorer_object_type_table.item(row_index, 4).text() == "Nebulae / ISM"

        )

        member_rows = [

            row_index

            for row_index in range(self.window._sky_explorer_object_type_table.rowCount())

            if self.window._sky_explorer_object_type_table.item(row_index, 3).text() == "Nebulae / ISM"

            and self.window._sky_explorer_object_type_table.item(row_index, 4).text() != "Nebulae / ISM"

        ]

        self.assertEqual(len(member_rows), 3)

        self.window._sky_explorer_object_type_table.item(group_row, 4).setCheckState(Qt.CheckState.Unchecked)

        self.assertTrue(

            all(self.window._sky_explorer_object_type_table.item(row_index, 4).checkState() == Qt.CheckState.Unchecked for row_index in member_rows)

        )

        self.assertEqual(self.window._sky_explorer_object_type_table.item(group_row, 4).checkState(), Qt.CheckState.Unchecked)

        self.window._sky_explorer_object_type_table.item(member_rows[0], 4).setCheckState(Qt.CheckState.Checked)

        self.assertEqual(self.window._sky_explorer_object_type_table.item(group_row, 4).checkState(), Qt.CheckState.PartiallyChecked)

        self.window._sky_explorer_object_type_table.item(group_row, 4).setCheckState(Qt.CheckState.Checked)

        self.assertTrue(

            all(self.window._sky_explorer_object_type_table.item(row_index, 4).checkState() == Qt.CheckState.Checked for row_index in member_rows)

        )


    def test_sky_explorer_object_type_table_edits_font_color_and_text_style(self) -> None:

        self.window._handle_app_mode_changed(AppMode.SKY_EXPLORER)

        galaxy_row = next(

            row_index

            for row_index in range(self.window._sky_explorer_object_type_table.rowCount())

            if self.window._sky_explorer_object_type_table.item(row_index, 4).text() == "Galaxy"

        )

        selected_font = QFont(self.window.font())

        selected_font.setPointSize(max(12, self.window.font().pointSize() + 2))

        selected_font.setBold(True)

        selected_font.setItalic(True)

        with patch.object(self.window, "_edit_sky_explorer_text_style", return_value=(selected_font, "#556677")):

            self.window._handle_sky_explorer_object_type_table_clicked(galaxy_row, 2)

        text_item = self.window._sky_explorer_object_type_table.item(galaxy_row, 2)

        self.assertEqual(text_item.background().color().name(), "#556677")

        self.assertEqual(text_item.foreground().color().name(), self.window._contrast_text_color("#556677"))


        self.assertFalse(text_item.font().bold())

        self.assertFalse(text_item.font().italic())

        self.assertEqual(text_item.font().pointSize(), self.window.font().pointSize())

        self.assertIn("Bold", text_item.text())

        self.assertIn("Italic", text_item.text())


    def test_sky_explorer_stroke_color_edit_keeps_default_text_color(self) -> None:

        self.window._handle_app_mode_changed(AppMode.SKY_EXPLORER)

        self.window._ensure_settings()

        galaxy_row = next(

            row_index

            for row_index in range(self.window._sky_explorer_object_type_table.rowCount())

            if self.window._sky_explorer_object_type_table.item(row_index, 4).text() == "Galaxy"

        )

