    def test_sky_explorer_object_type_table_can_sort_by_object_type(self) -> None:

        self.window._handle_app_mode_changed(AppMode.SKY_EXPLORER)

        self.window._sky_explorer_object_type_table.sortItems(4, Qt.SortOrder.DescendingOrder)

        grouped_titles: dict[str, list[str]] = {}

        group_order: list[str] = []

        current_group = ""

        for row_index in range(self.window._sky_explorer_object_type_table.rowCount()):

            group_title = self.window._sky_explorer_object_type_table.item(row_index, 3).text()

            object_title = self.window._sky_explorer_object_type_table.item(row_index, 4).text()

            if object_title == group_title:

                group_order.append(group_title)

                grouped_titles[group_title] = []

                current_group = group_title

                continue

            grouped_titles[current_group].append(object_title)

        self.assertEqual(group_order, ["Nebulae / ISM", "Galaxies", "Star Clusters / Associations"])

        for titles in grouped_titles.values():

            self.assertEqual(titles, sorted(titles, reverse=True))


