    def test_sky_explorer_group_color_override_sets_related_type_hues(self) -> None:

        self.window._handle_app_mode_changed(AppMode.SKY_EXPLORER)

        settings = self.window._ensure_settings()

        settings.sky_explorer_object_group_color_overrides = {"cluster": "#ff6600"}

        self.window._load_sky_explorer_style_settings_from_settings()

        _stroke_color, fill_color = self.window._sky_explorer_object_type_colors_for_key("open_cluster")

        chosen_hue = QColor("#ff6600").hue()

        fill_hue = QColor(fill_color).hue()

        hue_distance = abs(chosen_hue - fill_hue)

        hue_distance = min(hue_distance, 360 - hue_distance)

        self.assertLessEqual(hue_distance, 18)


    def test_sky_explorer_settings_save_applies_group_colors_immediately(self) -> None:

        with tempfile.TemporaryDirectory() as temp_dir:

            root_path = Path(temp_dir)

            self.window._root_path_input.setText(str(root_path))

            settings = AppSettings.from_root(root_path)

            settings.app_mode = AppMode.SKY_EXPLORER

            settings.save(root_path)

            self.window._settings = settings

            self.window._load_sky_explorer_style_settings_from_settings()

            self.window._handle_app_mode_changed(AppMode.SKY_EXPLORER)

            self.window._populate_sky_explorer_object_type_table(preserve_selection=True)

            open_cluster_row = next(

                row_index

                for row_index in range(self.window._sky_explorer_object_type_table.rowCount())

                if self.window._sky_explorer_object_type_table.item(row_index, 4).text() == "Open Cluster"

            )

            original_stroke = self.window._sky_explorer_object_type_table.item(open_cluster_row, 0).background().color().name()

            original_color = self.window._sky_explorer_object_type_table.item(open_cluster_row, 1).background().color().name()

            original_text_color = self.window._sky_explorer_object_type_table.item(open_cluster_row, 2).background().color().name()

            updated_settings = replace(

                settings,

                sky_explorer_object_group_color_overrides={"cluster": "#ff6600"},

            )

            fake_dialog = MagicMock()

            fake_dialog.exec.return_value = True

            fake_dialog.selected_config_path_override.return_value = None

            fake_dialog.build_settings.return_value = updated_settings

            with (

                patch("photometry_app.ui.main_window.SettingsDialog", return_value=fake_dialog),

                patch("photometry_app.ui.main_window.save_settings_config_override"),

                patch.object(self.window, "_sync_hr_background_name_lookup"),

            ):

                self.window._open_settings()

            open_cluster_row = next(

                row_index

                for row_index in range(self.window._sky_explorer_object_type_table.rowCount())

                if self.window._sky_explorer_object_type_table.item(row_index, 4).text() == "Open Cluster"

            )

            updated_color = self.window._sky_explorer_object_type_table.item(open_cluster_row, 1).background().color().name()

            updated_stroke = self.window._sky_explorer_object_type_table.item(open_cluster_row, 0).background().color().name()

            updated_text_color = self.window._sky_explorer_object_type_table.item(open_cluster_row, 2).background().color().name()

            self.assertNotEqual(updated_color, original_color)

            self.assertNotEqual(updated_stroke, original_stroke)

            self.assertNotEqual(updated_text_color, original_text_color)

            self.assertEqual(updated_text_color, updated_stroke)

            chosen_hue = QColor("#ff6600").hue()

            updated_hue = QColor(updated_color).hue()

            hue_distance = abs(chosen_hue - updated_hue)

            self.assertLessEqual(min(hue_distance, 360 - hue_distance), 18)


