    def test_asteroid_blink_frame_advance_stays_single_step_when_rendering_falls_behind_interval(self) -> None:

        folder_path = Path(self._config_dir.name) / "subframes_catchup"

        folder_path.mkdir()

        first_path = folder_path / "frame1.fit"

        second_path = folder_path / "frame2.fit"

        third_path = folder_path / "frame3.fit"

        for path, label in ((first_path, b"first"), (second_path, b"second"), (third_path, b"third")):

            path.write_bytes(label)

        metadata = ObservationMetadata(

            date_obs=datetime(2025, 1, 14, 21, 12, tzinfo=UTC),

            filter_name="L",

            exposure_seconds=120.0,

            width=2048,

            height=1536,

            object_name="Demo",

            frame_type="Light",

        )

        with (

            patch("photometry_app.ui.main_window.inspect_fits_file", return_value=FileScanResult(path=first_path, object_folder="Demo", metadata=metadata, wcs_status=WcsStatus.SOLVED)),

            patch.object(self.window, "_refresh_asteroid_image_view"),

            patch("photometry_app.ui.main_window.monotonic", return_value=100.0),

        ):

            self.window._set_asteroid_sequence_paths([first_path, second_path, third_path], source_label=folder_path)

            self.window._asteroid_blink_button.blockSignals(True)

            self.window._asteroid_blink_button.setChecked(True)

            self.window._asteroid_blink_button.blockSignals(False)

            with patch.object(self.window, "_asteroid_blink_preload_ready", return_value=True):

                self.window._start_asteroid_blink_playback()

        def assert_frame_swap_pauses_timer(index: int, *, refresh_image: bool) -> None:

            self.assertEqual(index, 1)

            self.assertTrue(refresh_image)

            self.assertFalse(self.window._asteroid_blink_timer.isActive())

            self.assertTrue(self.window._asteroid_blink_frame_advance_in_progress)

        with (

            patch("photometry_app.ui.main_window.monotonic", return_value=100.13),

            patch.object(self.window, "_set_active_asteroid_frame", side_effect=assert_frame_swap_pauses_timer) as set_active_frame,

        ):

            self.window._advance_asteroid_blink_frame()

        set_active_frame.assert_called_once_with(1, refresh_image=True)

        self.assertTrue(self.window._asteroid_blink_timer.isActive())

        self.window._asteroid_blink_timer.stop()



