    def test_search_asteroid_planning_targets_streams_named_results(self) -> None:

        comet_detection = SolarSystemDetection(
            name="Bright Comet",
            designation="C/2026 B1",
            object_type="Comet",
            orbit_class="comet",
            predicted_ra_deg=10.0,
            predicted_dec_deg=20.0,
            predicted_x=float("nan"),
            predicted_y=float("nan"),
            predicted_magnitude=8.4,
            ra_rate_arcsec_per_hour=0.5,
            dec_rate_arcsec_per_hour=0.2,
            motion_rate_arcsec_per_hour=0.54,
            expected_trail_length_px=None,
            positional_uncertainty_arcsec=0.8,
            altitude_deg=35.0,
            likely_visible=False,
            confidence_score=0.0,
            status="Planning candidate",
        )
        dim_detection = SolarSystemDetection(
            name="Dim Comet",
            designation="C/2026 B2",
            object_type="Comet",
            orbit_class="comet",
            predicted_ra_deg=11.0,
            predicted_dec_deg=21.0,
            predicted_x=float("nan"),
            predicted_y=float("nan"),
            predicted_magnitude=10.4,
            ra_rate_arcsec_per_hour=0.5,
            dec_rate_arcsec_per_hour=0.2,
            motion_rate_arcsec_per_hour=0.54,
            expected_trail_length_px=None,
            positional_uncertainty_arcsec=0.8,
            altitude_deg=35.0,
            likely_visible=False,
            confidence_score=0.0,
            status="Planning candidate",
        )
        streamed_names: list[tuple[str, ...]] = []

        def fake_named_search(*_args, **kwargs):
            result_callback = kwargs["result_callback"]
            result_callback(SolarSystemSearchResult(detection=comet_detection, angular_distance_deg=None, is_in_image=False))
            result_callback(SolarSystemSearchResult(detection=dim_detection, angular_distance_deg=None, is_in_image=False))
            return [
                SolarSystemSearchResult(detection=comet_detection, angular_distance_deg=None, is_in_image=False),
                SolarSystemSearchResult(detection=dim_detection, angular_distance_deg=None, is_in_image=False),
            ]

        with patch(
            "photometry_app.ui.main_window.search_known_solar_system_objects_globally",
            side_effect=fake_named_search,
        ) as search:
            entries = self.window._search_asteroid_planning_targets(
                KnownObjectOrbit3DPlannerRequest(
                    identifier="154P",
                    start_time=datetime(2026, 4, 22, 0, 0, tzinfo=UTC),
                    end_time=datetime(2026, 4, 24, 0, 0, tzinfo=UTC),
                ),
                partial_results_callback=lambda current_entries: streamed_names.append(
                    tuple(entry.target.detection.name for entry in current_entries)
                ),
            )

        self.assertEqual([entry.target.detection.name for entry in entries], ["Bright Comet", "Dim Comet"])
        self.assertIn(("Bright Comet", "Dim Comet"), streamed_names)
        self.assertEqual(search.call_args.kwargs["max_parallel_workers"], self.window._settings.asteroid_search_parallel_workers)

