    def test_known_object_orbit_3d_dialog_builds_playback_and_camera_controls(self) -> None:

        now = datetime(2025, 1, 14, 21, 13, tzinfo=UTC)

        object_path = tuple(

            SolarSystemStateVectorSample(

                observation_time=now + timedelta(minutes=index * 2),

                x_au=1.2 + (index * 0.03),

                y_au=0.4 + (index * 0.02),

                z_au=0.1 + (index * 0.01),

                vx_au_per_day=0.01,

                vy_au_per_day=0.01,

                vz_au_per_day=0.0,

            )

            for index in range(4)

        )

        earth_path = tuple(

            SolarSystemStateVectorSample(

                observation_time=sample.observation_time,

                x_au=0.2 + (index * 0.01),

                y_au=0.9 - (index * 0.01),

                z_au=0.0,

                vx_au_per_day=0.0,

                vy_au_per_day=0.0,

                vz_au_per_day=0.0,

            )

            for index, sample in enumerate(object_path)

        )

        context = KnownObjectHeliocentricContext(

            object_label="(1) Ceres",

            resolved_target_name="1 Ceres",

            earth_target_name="Earth (399)",

            earth_orbital_period_days=365.25,

            window_start=object_path[0].observation_time,

            window_end=object_path[-1].observation_time,

            arc_padding_days=45.0,

            reference_time=object_path[1].observation_time,

            object_path_samples=object_path,

            earth_path_samples=earth_path,

            observation_object_samples=object_path[:3],

            observation_earth_samples=earth_path[:3],

            comparison_tracks=(

                KnownObjectComparisonTrack(

                    object_label="(20) Massalia",

                    resolved_target_name="20 Massalia",

                    path_samples=object_path,

                    observation_samples=object_path[:3],

                    orbital_period_days=1450.0,

                ),

            ),

        )

        detection = SolarSystemDetection(

            name="(1) Ceres",

            designation="1",

            object_type="Asteroid",

            orbit_class="main-belt",

            predicted_ra_deg=10.0,

            predicted_dec_deg=20.0,

            predicted_x=24.5,

            predicted_y=30.5,

            predicted_magnitude=12.3,

            ra_rate_arcsec_per_hour=3.6,

            dec_rate_arcsec_per_hour=0.0,

            motion_rate_arcsec_per_hour=3.6,

            expected_trail_length_px=1.0,

            positional_uncertainty_arcsec=0.2,

            altitude_deg=50.0,

            likely_visible=True,

            confidence_score=0.91,

            status="Likely visible",

        )

        frame_measurements = tuple(

            SolarSystemFrameMeasurement(

                source_path=Path(f"frame_{index}.fit"),

                observation_time=sample.observation_time,

                predicted_ra_deg=10.0,

                predicted_dec_deg=20.0,

                predicted_x=24.5 + index,

                predicted_y=30.5,

                expected_trail_length_px=1.0,

            )

            for index, sample in enumerate(context.observation_object_samples)

        )



        dialog = KnownObjectOrbit3DDialog(detection=detection, frame_measurements=frame_measurements, context=context, parent=self.window)



        self.assertEqual(dialog._camera_mode_combo.count(), 5)

        self.assertEqual(dialog._span_combo.count(), 5)

        self.assertEqual(dialog._span_combo.itemText(0), "Local")

        self.assertEqual(dialog._camera_mode_combo.itemText(2), "Side View")

        self.assertEqual(dialog._show_planets_checkbox.text(), "Planets")

        self.assertEqual(dialog._show_periods_checkbox.text(), "Periods")

        self.assertEqual(dialog._frame_slider.maximum(), 3)

        self.assertEqual(dialog._play_button.toolTip(), "Play timeline")

        self.assertFalse(dialog._play_button.icon().isNull())

        self.assertEqual(dialog._settings_button.toolTip(), "Display settings")

        self.assertEqual(dialog._settings_button.text(), "⚙")

        self.assertIn("Objects", dialog._object_menu_button.text())

        self.assertTrue(hasattr(dialog, "_periods_panel"))

        self.assertFalse(dialog._periods_panel.isVisible())

        self.assertIs(dialog._periods_panel.parentWidget(), dialog._gl_panel_container)

        self.assertTrue(hasattr(dialog, "_topdown_plot"))

        self.assertTrue(hasattr(dialog, "_magnitude_plot"))

        self.assertTrue(hasattr(dialog, "_distance_plot"))

        self.assertIn("Heliocentric top-down view", dialog._topdown_plot.getPlotItem().titleLabel.text)

        distance_xlim = dialog._distance_plot.getPlotItem().getViewBox().viewRange()[0]

        self.assertEqual(datetime.fromtimestamp(distance_xlim[0], tz=UTC).year, 2025)

        self.assertEqual(datetime.fromtimestamp(distance_xlim[1], tz=UTC).year, 2025)

        self.assertFalse(dialog._plot_hover_label.isVisible())

        self.assertEqual(dialog._right_splitter.count(), 2)

        self.assertEqual(dialog._frame_label.text(), "2/4")

        self.assertIn("2025-01-14", dialog._time_input.text())

        self.assertEqual([entry[0] for entry in dialog._period_entries()], ["Earth", "(1) Ceres"])

        self.assertIn("Targets: 1", dialog._summary_label.text())

        dialog.close()



