    def test_asteroid_synthetic_track_button_requires_selection_and_multi_frame_sequence(self) -> None:

        folder_path = Path(self._config_dir.name) / "subframes"

        folder_path.mkdir()

        first_path = folder_path / "first.fit"

        second_path = folder_path / "second.fit"

        first_path.write_bytes(b"first")

        second_path.write_bytes(b"second")

        metadata = {

            str(first_path.resolve()): ObservationMetadata(

                date_obs=datetime(2025, 1, 14, 21, 12, tzinfo=UTC),

                filter_name="L",

                exposure_seconds=120.0,

                width=2048,

                height=1536,

                object_name="Demo",

                frame_type="Light",

            ),

            str(second_path.resolve()): ObservationMetadata(

                date_obs=datetime(2025, 1, 14, 21, 14, tzinfo=UTC),

                filter_name="L",

                exposure_seconds=120.0,

                width=2048,

                height=1536,

                object_name="Demo",

                frame_type="Light",

            ),

        }



        def inspect_side_effect(path: Path, object_folder: str, observation_timezone: str = "UTC") -> FileScanResult:

            return FileScanResult(

                path=path,

                object_folder=object_folder,

                metadata=metadata[str(path.resolve())],

                wcs_status=WcsStatus.SOLVED,

            )



        detection = SolarSystemDetection(

            name="(1) Ceres",

            designation="1",

            object_type="Asteroid",

            orbit_class="MBA",

            predicted_ra_deg=10.0,

            predicted_dec_deg=20.0,

            predicted_x=25.0,

            predicted_y=35.0,

            predicted_magnitude=9.2,

            ra_rate_arcsec_per_hour=12.0,

            dec_rate_arcsec_per_hour=3.0,

            motion_rate_arcsec_per_hour=12.4,

            expected_trail_length_px=0.2,

            positional_uncertainty_arcsec=0.5,

            altitude_deg=48.0,

            likely_visible=True,

            confidence_score=0.91,

            status="Likely visible",

        )

        result = SolarSystemDetectionResult(

            source_path=first_path,

            solved_field=SolvedField(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=1.0, width=200, height=120, wcs_path=first_path),

            observation_time=datetime(2025, 1, 14, 21, 12, tzinfo=UTC),

            prediction_time=datetime(2025, 1, 14, 21, 13, tzinfo=UTC),

            exposure_seconds=120.0,

            filter_name="L",

            pixel_scale_arcsec_per_pixel=1.5,

            field_width_deg=0.2,

            field_height_deg=0.12,

            magnitude_limit=18.0,

            used_astrometry_fallback=False,

            detections=[detection],

            summary_text="1 predicted object",

        )



        self.assertFalse(self.window._asteroid_synthetic_track_button.isEnabled())



        with (

            patch("photometry_app.ui.main_window.inspect_fits_file", side_effect=inspect_side_effect),

            patch.object(self.window, "_refresh_asteroid_image_view"),

        ):

            self.window._set_asteroid_sequence_paths([first_path, second_path], source_label=folder_path)

            self.window._current_asteroid_detection_result = result

            self.window._populate_asteroid_results_table([detection])

            self.window._asteroid_results_table.setCurrentCell(0, 0)

            self.window._asteroid_results_table.selectRow(0)

            self.window._sync_asteroid_focus_controls()



        self.assertTrue(self.window._asteroid_synthetic_track_button.isEnabled())

