        self.assertEqual(self.window._asteroid_active_group_key, "__all__")

        self.assertFalse(self.window._asteroid_synthetic_track_button.isEnabled())

        self.assertIn("Mixed All Group", self.window._asteroid_synthetic_track_button.toolTip())



        subgroup_key = next(key for key in self.window._asteroid_frame_groups if key != "__all__")

