    def test_asteroid_discovery_dialog_shows_sources_and_marks_multiple_selected_candidates(self) -> None:

        reference_path = Path(self._config_dir.name) / "discover_sources.fit"

        reference_path.write_text("placeholder", encoding="utf-8")

        residual_candidate = MovingObjectCandidate(

            candidate_id="C1",

            frame_detections=(

                MovingObjectCandidateDetection(reference_path, datetime(2025, 1, 14, 21, 13, tzinfo=UTC), 0, 24.5, 30.5, 18.0, 7.2),

            ),

            average_snr=7.2,

            peak_value=18.0,

            fit_rms_px=0.3,

            motion_px_per_hour=2.4,

            motion_arcsec_per_hour=3.6,

            displacement_px=2.4,

            start_x=24.5,

            start_y=30.5,

            end_x=26.9,

            end_y=30.5,

            summary_text="Frames: 1 | Motion: 2.40 px/h",

        )

        sweep_candidate = MovingObjectCandidate(

            candidate_id="C2",

            frame_detections=(

                MovingObjectCandidateDetection(reference_path, datetime(2025, 1, 14, 21, 14, tzinfo=UTC), 0, 34.5, 20.5, 16.0, 6.4),

            ),

            average_snr=6.4,

            peak_value=16.0,

            fit_rms_px=0.4,

            motion_px_per_hour=1.8,

            motion_arcsec_per_hour=2.7,

            displacement_px=1.8,

            start_x=34.5,

            start_y=20.5,

            end_x=36.3,

            end_y=20.5,

            summary_text="Frames: 1 | Motion: 1.80 px/h",

            discovery_method="synthetic_sweep",

        )

        marked_batches: list[tuple[MovingObjectCandidate, ...]] = []

        dialog = AsteroidDiscoveryDialog(

            display=build_annotated_image_display_from_array(np.ones((16, 16), dtype=np.float32), image_path=reference_path),

            result=MovingObjectDiscoveryResult(

                reference_path=reference_path,

                preview_data=np.ones((16, 16), dtype=np.float32),

                candidate_count=2,

                aligned_frame_count=3,

                candidates=(residual_candidate, sweep_candidate),

                summary_text="Discover source summary.",

            ),

            mark_all_candidates_on_main_image=marked_batches.append,

            parent=self.window,

        )

        try:
            self.assertEqual(dialog._unmatched_table.item(0, 1).text(), "Residual")
            self.assertEqual(dialog._unmatched_table.item(1, 1).text(), "Sweep")
            self.assertEqual(dialog._mark_selected_button.text(), "Mark Selected")
            self.assertEqual(dialog._quick_label_button.text(), "Label...")
            self.assertEqual(dialog._unmatched_table.selectionMode(), QTableWidget.SelectionMode.ExtendedSelection)
            self.assertFalse(hasattr(dialog, "_mark_all_button"))
            self.assertIn("border:", dialog._trajectory_button.styleSheet())
            self.assertEqual(dialog._export_button.text(), "Export...")

            selection_model = dialog._unmatched_table.selectionModel()
            assert selection_model is not None
            selection_model.select(
                dialog._unmatched_table.model().index(1, 0),
                QItemSelectionModel.SelectionFlag.Select | QItemSelectionModel.SelectionFlag.Rows,
            )

            dialog._mark_selected_candidate_on_main_image()

            self.assertEqual(marked_batches, [(residual_candidate, sweep_candidate)])
        finally:
            dialog.close()



