    def test_completing_asteroid_detection_refreshes_recovery_and_discovery_buttons(self) -> None:

        folder_path = Path(self._config_dir.name) / "recovery-enable-subframes"

        folder_path.mkdir()

        first_path = folder_path / "first.fit"

        second_path = folder_path / "second.fit"

        third_path = folder_path / "third.fit"

        for path in (first_path, second_path, third_path):

            path.write_bytes(b"frame")



        metadata_by_path = {

            str(first_path.resolve()): ObservationMetadata(

                date_obs=datetime(2025, 1, 14, 21, 12, tzinfo=UTC),

                filter_name="L",

                exposure_seconds=120.0,

                width=2048,

                height=1536,

                object_name="Demo",

                frame_type="Light",

            ),

            str(second_path.resolve()): ObservationMetadata(

                date_obs=datetime(2025, 1, 14, 21, 14, tzinfo=UTC),

                filter_name="L",

                exposure_seconds=120.0,

                width=2048,

                height=1536,

                object_name="Demo",

                frame_type="Light",

            ),

            str(third_path.resolve()): ObservationMetadata(

                date_obs=datetime(2025, 1, 14, 21, 16, tzinfo=UTC),

                filter_name="L",

                exposure_seconds=120.0,

                width=2048,

                height=1536,

                object_name="Demo",

                frame_type="Light",

            ),

        }



        def inspect_side_effect(path: Path, object_folder: str, observation_timezone: str = "UTC") -> FileScanResult:

            return FileScanResult(

                path=path,

                object_folder=object_folder,

                metadata=metadata_by_path[str(path.resolve())],

                wcs_status=WcsStatus.SOLVED,

            )



        with (

            patch("photometry_app.ui.main_window.inspect_fits_file", side_effect=inspect_side_effect),

            patch.object(self.window, "_refresh_asteroid_image_view"),

        ):

            self.window._set_asteroid_sequence_paths([first_path, second_path, third_path], source_label=folder_path)



        self.assertFalse(self.window._asteroid_recover_button.isEnabled())

        self.assertFalse(self.window._asteroid_discover_button.isEnabled())



        result = SolarSystemDetectionResult(

            source_path=first_path,

            solved_field=SolvedField(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=1.0, width=200, height=120, wcs_path=first_path),

            observation_time=datetime(2025, 1, 14, 21, 12, tzinfo=UTC),

            prediction_time=datetime(2025, 1, 14, 21, 13, tzinfo=UTC),

            exposure_seconds=120.0,

            filter_name="L",

            pixel_scale_arcsec_per_pixel=1.5,

            field_width_deg=0.2,

            field_height_deg=0.12,

            magnitude_limit=18.0,

            used_astrometry_fallback=False,

            detections=[],

            summary_text="0 predicted objects",

        )



        with (

            patch.object(self.window, "_populate_asteroid_results_table"),

            patch.object(self.window, "_sync_asteroid_focus_controls"),

            patch.object(self.window, "_update_asteroid_frame_metadata"),

            patch.object(self.window, "_refresh_asteroid_image_view"),

        ):

            self.window._handle_asteroid_detection_completed(result)



        self.assertTrue(self.window._asteroid_recover_button.isEnabled())

        self.assertTrue(self.window._asteroid_discover_button.isEnabled())



