    def test_asteroid_discovery_dialog_labels_persist_and_score_candidates(self) -> None:

        reference_path = Path(self._config_dir.name) / "discover_training.fit"

        reference_path.write_text("placeholder", encoding="utf-8")

        start_time = datetime(2026, 5, 1, 3, 0, tzinfo=UTC)

        self.window._current_asteroid_source_image = reference_path

        self.window._asteroid_sequence_source_label = reference_path.parent

        self.window._asteroid_exposure_seconds = 120.0

        self.window._current_asteroid_detection_result = SolarSystemDetectionResult(

            source_path=reference_path,

            solved_field=SolvedField(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=1.0, width=200, height=120, wcs_path=reference_path),

            observation_time=start_time,

            prediction_time=start_time,

            exposure_seconds=120.0,

            filter_name="L",

            pixel_scale_arcsec_per_pixel=1.5,

            field_width_deg=0.2,

            field_height_deg=0.12,

            magnitude_limit=18.0,

            used_astrometry_fallback=False,

            detections=[],

            summary_text="0 predicted objects",

        )

        def build_candidate(candidate_id: str, *, snr: float, rms: float, motion: float) -> MovingObjectCandidate:

            detections = tuple(

                MovingObjectCandidateDetection(

                    source_path=reference_path,

                    observation_time=start_time + timedelta(minutes=index),

                    frame_index=index,

                    x=24.0 + index * motion / 60.0,

                    y=30.0 + index * 0.1,

                    peak_value=20.0 + snr,

                    local_snr=snr + index,

                )

                for index in range(3)

            )

            return MovingObjectCandidate(

                candidate_id=candidate_id,

                frame_detections=detections,

                average_snr=snr,

                peak_value=20.0 + snr,

                fit_rms_px=rms,

                motion_px_per_hour=motion,

                motion_arcsec_per_hour=motion * 1.5,

                displacement_px=motion / 20.0,

                start_x=detections[0].x,

                start_y=detections[0].y,

                end_x=detections[-1].x,

                end_y=detections[-1].y,

                summary_text=f"Candidate {candidate_id}",

            )

        candidates = (

            build_candidate("C1", snr=14.0, rms=0.2, motion=4.0),

            build_candidate("C2", snr=3.0, rms=1.4, motion=0.8),

        )

        result = MovingObjectDiscoveryResult(

            reference_path=reference_path,

            preview_data=np.ones((16, 16), dtype=np.float32),

            candidate_count=2,

            aligned_frame_count=3,

            candidates=candidates,

            summary_text="Discovered 2 unmatched moving candidate(s).",

        )

        self.window._open_asteroid_discovery_dialog(result)

        dialog = self.window._asteroid_discovery_dialog

        self.assertIsNotNone(dialog)

        assert dialog is not None

        main_headers = [self.window._asteroid_results_table.horizontalHeaderItem(index).text() for index in range(self.window._asteroid_results_table.columnCount())]

        self.assertNotIn("Label", main_headers)

        self.assertNotIn("ML Score", main_headers)

        headers = [dialog._unmatched_table.horizontalHeaderItem(index).text() for index in range(dialog._unmatched_table.columnCount())]

        label_column = headers.index("Label")

        score_column = headers.index("ML Score")



        def select_candidate(candidate_id: str) -> int:

            target_text = f"Candidate {candidate_id}"

            dialog._tabs.setCurrentWidget(dialog._unmatched_table)

            for row_index in range(dialog._unmatched_table.rowCount()):

                if dialog._unmatched_table.item(row_index, 0).text() == candidate_id:

                    dialog._unmatched_table.selectRow(row_index)

                    dialog._unmatched_table.setCurrentCell(row_index, 0)

                    dialog._handle_selection_changed()

                    return row_index

            self.fail(f"Could not find {target_text}")



        c1_row = select_candidate("C1")

        dialog._candidate_label_combo.setCurrentIndex(dialog._candidate_label_combo.findData("real_mover"))

        dialog._save_selected_candidate_label()

        c2_row = select_candidate("C2")

        dialog._candidate_label_combo.setCurrentIndex(dialog._candidate_label_combo.findData("artifact"))

        dialog._save_selected_candidate_label()

        dialog._train_candidate_model()



        c1_row = select_candidate("C1")

        c2_row = select_candidate("C2")

        self.assertEqual(dialog._unmatched_table.item(c1_row, label_column).text(), "Real Mover")

        self.assertEqual(dialog._unmatched_table.item(c2_row, label_column).text(), "Artifact")

        self.assertNotEqual(dialog._unmatched_table.item(c1_row, score_column).text(), "-")

        self.assertNotEqual(dialog._unmatched_table.item(c2_row, score_column).text(), "-")

        self.assertIn("Latest model", dialog._candidate_training_status_label.text())

        dialog.close()

