    def test_asteroid_discovery_options_dialog_updates_motion_range_preview_for_bias(self) -> None:

        frame_paths = [Path(self._config_dir.name) / f"preview_bias_{index:02d}.fit" for index in range(3)]

        start_time = datetime(2025, 1, 14, 21, 12, tzinfo=UTC)

        frame_metadata = {

            str(path.resolve()): ObservationMetadata(

                date_obs=start_time + timedelta(minutes=index),

                filter_name="L",

                exposure_seconds=180.0,

                width=64,

                height=64,

                object_name="Demo",

                frame_type="Light",

            )

            for index, path in enumerate(frame_paths)

        }

        dialog = AsteroidDiscoveryOptionsDialog(

            AsteroidDiscoveryRunOptions(motion_prior_bias="balanced"),

            frame_paths=frame_paths,

            frame_metadata=frame_metadata,

            pixel_scale_arcsec_per_pixel=1.5,

            parent=self.window,

        )

        self.assertIn("0.4-4.0 px during one 180s exposure", dialog._motion_range_preview_label.text())

        combo_index = dialog._motion_prior_bias_input.findData("near_earth")

        self.assertGreaterEqual(combo_index, 0)

        dialog._motion_prior_bias_input.setCurrentIndex(combo_index)

