    def test_prompt_asteroid_discovery_options_seeds_and_saves_persisted_run_settings(self) -> None:

        settings = AppSettings.from_root(Path(self._config_dir.name))
        settings.asteroid_discovery_assume_aligned = True
        settings.asteroid_discovery_min_residual_snr = 4.5
        settings.asteroid_discovery_max_residual_snr = 11.0
        settings.asteroid_discovery_frames_per_batch = 7
        settings.asteroid_discovery_single_batch_only = True
        settings.asteroid_discovery_binning_factor = 2
        settings.asteroid_discovery_use_temporary_cache = True
        settings.asteroid_discovery_min_seed_displacement_px = 0.8
        settings.asteroid_discovery_motion_prior_bias = "near_earth"
        settings.asteroid_discovery_retry_with_detailed_search = True
        self.window._settings = settings

        accepted_options = AsteroidDiscoveryRunOptions(
            assume_aligned=False,
            residual_min_snr=2.5,
            residual_max_snr=8.0,
            frames_per_batch=5,
            single_batch_only=False,
            binning_factor=3,
            use_temporary_cache=False,
            min_seed_displacement_px=1.2,
            motion_prior_bias="main_belt",
            retry_with_detailed_search=False,
        )

        dialog_instance = MagicMock()
        dialog_instance.exec.return_value = int(QDialog.DialogCode.Accepted)
        dialog_instance.build_options.return_value = accepted_options

        with patch("photometry_app.ui.main_window.AsteroidDiscoveryOptionsDialog", return_value=dialog_instance) as dialog_class:
            with patch.object(self.window, "_save_settings_snapshot") as save_snapshot:
                returned = self.window._prompt_asteroid_discovery_options(settings)

        self.assertEqual(returned, accepted_options)
        dialog_args = dialog_class.call_args.args[0]
        self.assertTrue(dialog_args.assume_aligned)
        self.assertEqual(dialog_args.min_seed_displacement_px, 0.8)
        self.assertEqual(dialog_args.motion_prior_bias, "near_earth")
        self.assertTrue(dialog_args.retry_with_detailed_search)
        self.assertFalse(self.window._settings.asteroid_discovery_assume_aligned)
        self.assertEqual(self.window._settings.asteroid_discovery_frames_per_batch, 5)
        self.assertEqual(self.window._settings.asteroid_discovery_binning_factor, 3)
        self.assertEqual(self.window._settings.asteroid_discovery_motion_prior_bias, "main_belt")
        self.assertAlmostEqual(self.window._settings.asteroid_discovery_min_seed_displacement_px, 1.2)
        save_snapshot.assert_called_once()

