    def test_starting_asteroid_discovery_prompts_for_alignment_mode_and_passes_choice_to_worker(self) -> None:

        first_path = Path(self._config_dir.name) / "discover_01.fit"

        second_path = Path(self._config_dir.name) / "discover_02.fit"

        third_path = Path(self._config_dir.name) / "discover_03.fit"

        for path in (first_path, second_path, third_path):

            path.write_text("placeholder", encoding="utf-8")



        class _FakeSignal:

            def connect(self, _callback) -> None:

                return None



        class _FakeDiscoveryWorker:

            instances: list["_FakeDiscoveryWorker"] = []



            def __init__(self, *, assume_aligned: bool, **_kwargs) -> None:

                self.assume_aligned = assume_aligned

                self.progress_updated = _FakeSignal()

                self.discovery_completed = _FakeSignal()

                self.discovery_cancelled = _FakeSignal()

                self.discovery_failed = _FakeSignal()

                self.started = False

                self.cancel_requested = False

                _FakeDiscoveryWorker.instances.append(self)



            def start(self) -> None:

                self.started = True



            def request_cancel(self) -> None:

                self.cancel_requested = True



            def isRunning(self) -> bool:

                return self.started and not self.cancel_requested



        self.window._asteroid_frame_paths = [first_path, second_path, third_path]

        self.window._asteroid_all_frame_paths = [first_path, second_path, third_path]

        self.window._current_asteroid_source_image = first_path

        subgroup_key = self.window._asteroid_sequence_group_key("L", 120.0)

        self.window._asteroid_active_group_key = subgroup_key

        self.window._asteroid_frame_groups = {

            subgroup_key: (

                ("L", 120.0, "Filter L | 120.0 s"),

                [

                    (first_path, ObservationMetadata(datetime(2025, 1, 14, 21, 12, tzinfo=UTC), "L", 120.0, 100, 100, "Demo")),

                    (second_path, ObservationMetadata(datetime(2025, 1, 14, 21, 14, tzinfo=UTC), "L", 120.0, 100, 100, "Demo")),

                    (third_path, ObservationMetadata(datetime(2025, 1, 14, 21, 16, tzinfo=UTC), "L", 120.0, 100, 100, "Demo")),

                ],

            )

        }

        self.window._asteroid_frame_scan_results = {

            str(path.resolve()): FileScanResult(

                path=path,

                object_folder="Demo",

                metadata=ObservationMetadata(datetime(2025, 1, 14, 21, 12, tzinfo=UTC), "L", 120.0, 100, 100, "Demo"),

                wcs_status=WcsStatus.SOLVED,

            )

            for path in (first_path, second_path, third_path)

        }

        self.window._current_asteroid_detection_result = SolarSystemDetectionResult(

            source_path=first_path,

            solved_field=SolvedField(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=1.0, width=100, height=100, wcs_path=first_path),

            observation_time=datetime(2025, 1, 14, 21, 12, tzinfo=UTC),

            prediction_time=datetime(2025, 1, 14, 21, 13, tzinfo=UTC),

            exposure_seconds=120.0,

            filter_name="L",

            pixel_scale_arcsec_per_pixel=1.5,

            field_width_deg=0.2,

            field_height_deg=0.12,

            magnitude_limit=18.0,

            used_astrometry_fallback=False,

            detections=[],

            summary_text="0 predicted objects",

        )



        with (

            patch("photometry_app.ui.main_window.AsteroidDiscoveryWorker", _FakeDiscoveryWorker),

            patch.object(self.window, "_prompt_asteroid_discovery_options", return_value=AsteroidDiscoveryRunOptions(assume_aligned=True)),

        ):

            self.window._start_asteroid_discovery()



        self.assertTrue(_FakeDiscoveryWorker.instances[-1].assume_aligned)

        self.assertTrue(_FakeDiscoveryWorker.instances[-1].started)

        self.window._asteroid_discovery_worker = None

        self.window._close_asteroid_discovery_progress_dialog()

        self.window._set_asteroid_detection_busy(False)



        with (

            patch("photometry_app.ui.main_window.AsteroidDiscoveryWorker", _FakeDiscoveryWorker),

            patch.object(self.window, "_prompt_asteroid_discovery_options", return_value=AsteroidDiscoveryRunOptions(assume_aligned=False)),

        ):

            self.window._start_asteroid_discovery()



        self.assertFalse(_FakeDiscoveryWorker.instances[-1].assume_aligned)

        self.assertTrue(_FakeDiscoveryWorker.instances[-1].started)

        self.window._asteroid_discovery_worker = None

        self.window._close_asteroid_discovery_progress_dialog()

        self.window._set_asteroid_detection_busy(False)



    def test_canceling_asteroid_discovery_requests_worker_cancellation(self) -> None:

        class _FakeDiscoveryWorker:

            def __init__(self) -> None:

                self.cancel_requested = False



            def request_cancel(self) -> None:

                self.cancel_requested = True



            def isRunning(self) -> bool:

                return True



        worker = _FakeDiscoveryWorker()

        self.window._asteroid_discovery_worker = worker

        self.window._asteroid_discovery_progress_dialog = QProgressDialog("Searching...", "Cancel", 0, 0, self.window)



        self.window._cancel_asteroid_discovery()



        self.assertTrue(worker.cancel_requested)

        self.assertIn("Canceling Discover", self.window._asteroid_status_label.text())

        self.window._asteroid_discovery_worker = None

        self.window._close_asteroid_discovery_progress_dialog()

