    def test_marking_discovery_candidates_keeps_blink_images_and_precaches_positions_before_restart(self) -> None:

        folder_path = Path(self._config_dir.name) / "subframes"

        folder_path.mkdir()

        first_path = folder_path / "frame1.fit"

        second_path = folder_path / "frame2.fit"

        first_path.write_bytes(b"first")

        second_path.write_bytes(b"second")

        self.window._asteroid_frame_paths = [first_path, second_path]

        render_settings = self.window._current_asteroid_image_render_settings()

        sequence_signature = self.window._asteroid_sequence_signature()

        for cache_key in sequence_signature:

            self.window._asteroid_sequence_qimage_cache[

                self.window._asteroid_render_cache_key(cache_key, render_settings)

            ] = QImage(12, 12, QImage.Format.Format_Grayscale8)

        self.window._asteroid_preloaded_sequence_signature = sequence_signature

        self.assertTrue(self.window._asteroid_blink_preload_ready())

        candidate = MovingObjectCandidate(

            candidate_id="C0",

            frame_detections=(

                MovingObjectCandidateDetection(

                    source_path=first_path,

                    observation_time=datetime(2025, 1, 14, 21, 13, tzinfo=UTC),

                    frame_index=0,

                    x=24.0,

                    y=35.0,

                    peak_value=10.0,

                    local_snr=7.5,

                ),

            ),

            average_snr=7.5,

            peak_value=10.0,

            fit_rms_px=0.4,

            motion_px_per_hour=8.0,

            motion_arcsec_per_hour=12.0,

            displacement_px=2.0,

            start_x=24.0,

            start_y=35.0,

            end_x=26.0,

            end_y=35.5,

            summary_text="Marked",

        )

        with patch.object(self.window, "_refresh_asteroid_image_view"):

            self.window._mark_asteroid_discovery_candidates_on_main_image((candidate,))

        self.assertEqual(self.window._asteroid_preloaded_sequence_signature, sequence_signature)

        self.assertTrue(self.window._asteroid_blink_preload_ready())

        with (

            patch.object(self.window, "_prepare_asteroid_blink_preload") as prepare_preload,

            patch.object(self.window, "_precompute_marked_asteroid_discovery_positions", wraps=self.window._precompute_marked_asteroid_discovery_positions) as precompute_positions,

        ):

            self.window._handle_asteroid_blink_toggled(True)

        prepare_preload.assert_not_called()

        precompute_positions.assert_called_once_with()

        position_key = self.window._marked_asteroid_discovery_position_cache_key(candidate, first_path)

        self.assertIsNotNone(position_key)

        self.assertEqual(self.window._marked_asteroid_discovery_position_cache[position_key], (24.0, 35.0))

        self.assertTrue(self.window._asteroid_blink_timer.isActive())

        self.window._asteroid_blink_timer.stop()



    def test_completing_asteroid_blink_preload_updates_cache_and_starts_blink_when_checked(self) -> None:

        folder_path = Path(self._config_dir.name) / "subframes"

        folder_path.mkdir()

        first_path = folder_path / "frame1.fit"

        second_path = folder_path / "frame2.fit"

        first_path.write_bytes(b"first")

        second_path.write_bytes(b"second")

        self.window._asteroid_frame_paths = [first_path, second_path]

        display_a = AnnotatedImageDisplay(

            image_path=first_path,

            normalized_data=np.zeros((4, 4), dtype=float),

            norm=object(),

            preview_normalized=np.zeros((4, 4), dtype=float),

            asinh_preview=np.zeros((4, 4), dtype=float),

        )

        display_b = AnnotatedImageDisplay(

            image_path=second_path,

            normalized_data=np.zeros((4, 4), dtype=float),

            norm=object(),

            preview_normalized=np.zeros((4, 4), dtype=float),

            asinh_preview=np.zeros((4, 4), dtype=float),

        )

        sequence_signature = (

            self.window._image_display_cache_key(first_path),

            self.window._image_display_cache_key(second_path),

        )

        result = AsteroidBlinkPreloadResult(

            image_displays={

                sequence_signature[0]: display_a,

                sequence_signature[1]: display_b,

            },

            rendered_qimages={

                sequence_signature[0]: QImage(4, 4, QImage.Format.Format_Grayscale8),

                sequence_signature[1]: QImage(4, 4, QImage.Format.Format_Grayscale8),

            },

            frame_measurements={},

            sequence_signature=sequence_signature,

            loaded_frame_count=2,

            measured_frame_count=0,

            render_settings=self.window._current_asteroid_image_render_settings(),

            measurement_generation=None,

            warning_messages=[],

        )

        self.window._asteroid_blink_button.blockSignals(True)

        self.window._asteroid_blink_button.setChecked(True)

        self.window._asteroid_blink_button.blockSignals(False)



        with (

            patch.object(self.window, "_refresh_asteroid_image_view") as refresh_image_view,

            patch.object(self.window, "_start_asteroid_blink_playback") as start_blink,

        ):

            self.window._handle_asteroid_blink_preload_completed(result)



        self.assertEqual(self.window._asteroid_preloaded_sequence_signature, sequence_signature)

        self.assertEqual(len(self.window._asteroid_sequence_display_cache), 2)

        refresh_image_view.assert_called_once()

        start_blink.assert_called_once_with()



