    def test_export_astrostack_animation_aligns_frames_and_writes_gif(self) -> None:

        folder_path = Path(self._config_dir.name) / "astrostack_export"

        folder_path.mkdir()

        first_path = folder_path / "frame1.fit"

        second_path = folder_path / "frame2.fit"

        first_path.write_bytes(b"first")

        second_path.write_bytes(b"second")

        output_path = folder_path / "astrostack.gif"

        aligned_first = folder_path / "aligned_1.fit"

        aligned_second = folder_path / "aligned_2.fit"

        alignment_result = SequenceAlignmentResult(
            output_directory=folder_path,
            reference_path=first_path,
            aligned_frames=(
                AlignedFrameOutput(source_path=first_path, output_path=aligned_first),
                AlignedFrameOutput(source_path=second_path, output_path=aligned_second),
            ),
            summary_text="Aligned 2 frame(s)",
        )

        captured_frame = QImage(24, 16, QImage.Format.Format_ARGB32)

        self.window._astrostack_frame_paths = [first_path, second_path]

        self.window._current_astrostack_root_path = folder_path

        self.window._current_astrostack_source_image = first_path

        self.window._settings.shared_parallel_workers = 3

        self.window._settings.astrostack_parallel_workers = 1

        self.window._astrostack_image_view.resize(96, 96)



        with (

            patch.object(self.window, "_prompt_astrostack_alignment_mode", return_value=False),

            patch.object(
                self.window,
                "_prompt_astrostack_gif_export_options",
                return_value=AstrostackGifExportOptions(frame_duration_ms=125, loop_count=None, scale_percent=80),
            ) as gif_options_dialog,

            patch("photometry_app.ui.main_window.QFileDialog.getSaveFileName", return_value=(str(output_path), "Animated GIF Files (*.gif)")),

            patch("photometry_app.ui.main_window.QMessageBox.warning") as warning_message,

            patch("photometry_app.ui.main_window.align_wcs_image_sequence", return_value=alignment_result) as align_sequence,

            patch(
                "photometry_app.ui.main_window.read_image_data",
                side_effect=[
                    np.full((8, 8), 2.0, dtype=np.float32),
                    np.full((8, 8), 6.0, dtype=np.float32),
                ],
            ),

            patch("photometry_app.ui.main_window.AnnotatedImageView.capture_view_image", return_value=captured_frame),

            patch("photometry_app.ui.main_window.export_qimages_to_gif") as export_gif,

        ):

            self.window._export_astrostack_animation()



        gif_options_dialog.assert_called_once_with(frame_count=2)

        self.assertEqual(align_sequence.call_args.args[0], [first_path, second_path])

        self.assertEqual(align_sequence.call_args.kwargs["reference_path"], first_path)

        self.assertEqual(align_sequence.call_args.kwargs["max_parallel_workers"], self.window._settings.astrostack_parallel_workers)

        self.assertEqual(align_sequence.call_args.kwargs["worker_limit_override"], self.window._settings.astrostack_parallel_workers)

        warning_message.assert_not_called()

        export_gif.assert_called_once()

        exported_frames = export_gif.call_args.args[0]

