    def test_selected_asteroid_target_marker_button_updates_overlay_style(self) -> None:

        source_path = Path(self._config_dir.name) / "asteroid_target_button.fit"

        source_path.write_bytes(b"source")

        detection = SolarSystemDetection(
            name="(1) Ceres",
            designation="1",
            object_type="Asteroid",
            orbit_class="MBA",
            predicted_ra_deg=10.0,
            predicted_dec_deg=20.0,
            predicted_x=25.0,
            predicted_y=35.0,
            predicted_magnitude=9.2,
            ra_rate_arcsec_per_hour=12.0,
            dec_rate_arcsec_per_hour=3.0,
            motion_rate_arcsec_per_hour=12.4,
            expected_trail_length_px=1.2,
            positional_uncertainty_arcsec=0.5,
            altitude_deg=48.0,
            likely_visible=True,
            confidence_score=0.91,
            status="Likely visible",
        )

        self.window._current_asteroid_source_image = source_path
        self.window._current_asteroid_detection_result = SolarSystemDetectionResult(
            source_path=source_path,
            solved_field=SolvedField(center_ra_deg=10.0, center_dec_deg=20.0, radius_deg=1.0, width=200, height=120, wcs_path=source_path),
            observation_time=datetime(2025, 1, 14, 21, 12, tzinfo=UTC),
            prediction_time=datetime(2025, 1, 14, 21, 13, tzinfo=UTC),
            exposure_seconds=120.0,
            filter_name="L",
            pixel_scale_arcsec_per_pixel=1.5,
            field_width_deg=0.2,
            field_height_deg=0.12,
            magnitude_limit=18.0,
            used_astrometry_fallback=False,
            detections=[detection],
            summary_text="1 predicted object",
        )
        self.window._populate_asteroid_results_table([detection])
        self.window._asteroid_results_table.setCurrentCell(0, 0)
        self.window._asteroid_results_table.selectRow(0)

        settings = self.window._ensure_settings()
        settings.asteroid_target_marker_line_color = "#aa1122"
        settings.asteroid_target_marker_accent_color = "#33cc88"
        settings.asteroid_target_marker_text_color = "#fef3c7"
        settings.asteroid_target_marker_outline_color = "#123456"
        settings.asteroid_target_marker_line_width = 5.5
        self.window._sync_asteroid_settings_menu_controls()

        self.assertFalse(self.window._asteroid_target_marker_button.isChecked())

        self.window._asteroid_target_marker_button.setChecked(True)

        self.assertTrue(settings.asteroid_visual_show_target_marker)

        overlay = next(overlay for overlay in self.window._current_asteroid_image_overlays() if overlay.source_id == "solar:0:predicted")
        self.assertEqual(overlay.marker_style, "target")
        self.assertEqual(overlay.color, "#aa1122")
        self.assertEqual(overlay.accent_color, "#33cc88")
        self.assertEqual(overlay.text_color, "#fef3c7")
        self.assertEqual(overlay.outline_color, "#123456")
        self.assertEqual(overlay.pen_width, 5.5)
        self.assertTrue(overlay.show_center_dot)

    def test_toggling_asteroid_invert_stops_blink_playback_first(self) -> None:

        self.window._asteroid_frame_paths = [Path("a.fit"), Path("b.fit")]

        self.window._asteroid_blink_button.blockSignals(True)

        self.window._asteroid_blink_button.setChecked(True)

        self.window._asteroid_blink_button.blockSignals(False)

        self.window._asteroid_blink_timer.start()

        with patch.object(self.window, "_refresh_asteroid_image_view") as refresh_image:

            self.window._asteroid_image_invert_checkbox.setChecked(True)

        self.assertFalse(self.window._asteroid_blink_timer.isActive())

        self.assertFalse(self.window._asteroid_blink_button.isChecked())

        refresh_image.assert_called_once_with(reset_view=False)

