    def test_loading_folder_settings_preserves_current_app_mode(self) -> None:

        with tempfile.TemporaryDirectory() as temp_dir:

            root_path = Path(temp_dir)

            config_path = root_path / "settings.json"

            previous_config_path = os.environ.get("CITIZEN_PHOTOMETRY_CONFIG_PATH")

            os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = str(config_path)

            try:

                settings = AppSettings.from_root(root_path)

                settings.app_mode = AppMode.HR_DIAGRAM

                settings.save(root_path)



                self.assertEqual(self.window._current_app_mode(), AppMode.DIFFERENTIAL_PHOTOMETRY)



                self.window._load_settings_for_root(root_path, preserve_app_mode=True)



                self.assertEqual(self.window._current_app_mode(), AppMode.DIFFERENTIAL_PHOTOMETRY)

                self.assertEqual(self.window._app_mode_stack.currentWidget(), self.window._differential_mode_panel)

            finally:

                if previous_config_path is None:

                    os.environ.pop("CITIZEN_PHOTOMETRY_CONFIG_PATH", None)

                else:

                    os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = previous_config_path



    def test_loading_folder_settings_preserves_visible_mode_even_if_settings_state_is_stale(self) -> None:

        with tempfile.TemporaryDirectory() as temp_dir:

            root_path = Path(temp_dir)

            config_path = root_path / "settings.json"

            previous_config_path = os.environ.get("CITIZEN_PHOTOMETRY_CONFIG_PATH")

            os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = str(config_path)

            try:

                saved_settings = AppSettings.from_root(root_path)

                saved_settings.app_mode = AppMode.HR_DIAGRAM

                saved_settings.save(root_path)



                self.window._settings = AppSettings.from_root(root_path)

                self.window._settings.app_mode = AppMode.HR_DIAGRAM

                self.window._apply_app_mode(AppMode.DIFFERENTIAL_PHOTOMETRY)



                self.window._load_settings_for_root(root_path, preserve_app_mode=True)



                self.assertEqual(self.window._current_app_mode(), AppMode.DIFFERENTIAL_PHOTOMETRY)

                self.assertEqual(self.window._app_mode_stack.currentWidget(), self.window._differential_mode_panel)

            finally:

                if previous_config_path is None:

                    os.environ.pop("CITIZEN_PHOTOMETRY_CONFIG_PATH", None)

                else:

                    os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = previous_config_path



