    def test_copy_selected_hr_result_names_to_clipboard(self) -> None:

        rows = [

            HrMeasurementRow(

                source_id="1",

                source_name="Alpha",

                catalog="gaia-dr3",

                ra_deg=0.0,

                dec_deg=0.0,

                gaia_g_mag=12.0,

                gaia_bp_rp=0.8,

                parallax_mas=10.0,

                parallax_error_mas=0.2,

                x=10.0,

                y=10.0,

                aperture_radius=5.0,

                annulus_inner_radius=8.0,

                annulus_outer_radius=12.0,

            ),

            HrMeasurementRow(

                source_id="2",

                source_name="Beta",

                catalog="gaia-dr3",

                ra_deg=1.0,

                dec_deg=1.0,

                gaia_g_mag=13.0,

                gaia_bp_rp=1.1,

                parallax_mas=9.0,

                parallax_error_mas=0.2,

                x=20.0,

                y=20.0,

                aperture_radius=5.0,

                annulus_inner_radius=8.0,

                annulus_outer_radius=12.0,

            ),

        ]

        self.window._populate_hr_results_table(rows, matching_count=2, plotted_count=2, total_count=2)

        selection_model = self.window._hr_results_table.selectionModel()

        assert selection_model is not None

        selection_model.select(

            self.window._hr_results_table.model().index(0, 0),

            QItemSelectionModel.SelectionFlag.Select | QItemSelectionModel.SelectionFlag.Rows,

        )

        selection_model.select(

            self.window._hr_results_table.model().index(1, 0),

            QItemSelectionModel.SelectionFlag.Select | QItemSelectionModel.SelectionFlag.Rows,

        )



        self.window._copy_selected_hr_result_names_to_clipboard()



        self.assertEqual(QGuiApplication.clipboard().text(), "Alpha\nBeta")



