    def test_prepare_hr_workflow_reuse_preserves_active_name_lookup_progress(self) -> None:

        with tempfile.TemporaryDirectory() as temp_dir:

            source_path = Path(temp_dir) / "demo_rgb.xisf"

            source_path.write_text("placeholder", encoding="utf-8")

            self.window._hr_source_image_input.setText(str(source_path))

            self.window._hr_working_directory_input.setText(temp_dir)

            self.window._current_hr_source_image = source_path

            self.window._current_hr_working_table = HrWorkingTable(rows=[], plane_labels=["red"], measured_count=0, usable_count=0)

            self.window._current_hr_measurement_cache_key = self.window._current_hr_measurement_cache_key_for(source_path)

            self.window._hr_roi_selections = [_HrRoiSelection("rectangle", 0.0, 0.0, 20.0, 20.0)]

            self.window._hr_background_name_lookup_total_count = 210

            self.window._hr_background_name_lookup_completed_count = 20

            self.window._hr_background_name_lookup_pending_row_keys = {("gaia-dr3", "123")}

            self.window._hr_background_name_lookup_restore_status_text = "Resolved field summary."

            progress_message = "Searching catalog/designation names for bright HR targets 20/210 (Gaia G <= 9.00 mag)."

            self.window._hr_status_label.setText(progress_message)

            self.window._set_hr_footer_left_override_text(progress_message)

            self.window._hr_progress_bar.setRange(0, 210)

            self.window._hr_progress_bar.setValue(20)

            self.window._hr_progress_bar.show()

            calls: list[str] = []

            self.window._refresh_hr_image_view = lambda **kwargs: calls.append("image")

            self.window._refresh_hr_plot = lambda: calls.append("plot")



            self.window._prepare_hr_diagram_workflow()



            self.assertEqual(calls, ["image", "plot"])

            self.assertEqual(self.window._hr_progress_bar.value(), 20)

            self.assertEqual(self.window._hr_progress_bar.maximum(), 210)

            self.assertEqual(self.window._hr_status_label.text(), progress_message)

            self.assertEqual(self.window._hr_roi_draft_status_label.text(), progress_message)



