    def test_export_hr_bundle_writes_science_package(self) -> None:

        row = HrMeasurementRow(

            source_id="1",

            source_name="Alpha",

            catalog="gaia-dr3",

            ra_deg=0.0,

            dec_deg=0.0,

            gaia_g_mag=12.0,

            gaia_bp_rp=0.8,

            parallax_mas=10.0,

            parallax_error_mas=0.2,

            x=10.0,

            y=20.0,

            aperture_radius=5.0,

            annulus_inner_radius=8.0,

            annulus_outer_radius=12.0,

            flux_luminance=1000.0,

            calibrated_mag_luminance=11.5,

            absolute_magnitude_proxy=6.5,

            gaia_absolute_magnitude=5.2,

            plot_color_index=0.8,

        )



        with tempfile.TemporaryDirectory() as temp_dir:

            export_parent = Path(temp_dir) / "exports"

            export_parent.mkdir(parents=True, exist_ok=True)

            source_path = Path(temp_dir) / "frame.fit"

            source_path.write_text("placeholder", encoding="utf-8")

            self.window._current_hr_source_image = source_path

            self.window._current_hr_working_table = HrWorkingTable(

                rows=[row],

                plane_labels=["red", "green", "blue", "luminance"],

                measured_count=1,

                usable_count=1,

            )



            capture = unittest.mock.Mock()



            def save_image(path: str) -> bool:

                Path(path).write_text("image", encoding="utf-8")

                return True



            capture.save.side_effect = save_image



            def write_plot(path: str, **_kwargs) -> None:

                Path(path).write_text("plot", encoding="utf-8")



            with (

                patch("photometry_app.ui.main_window.QFileDialog.getExistingDirectory", return_value=str(export_parent)),

                patch("photometry_app.ui.main_window.QInputDialog.getText", return_value=("M45 science", True)),

                patch.object(self.window, "_refresh_hr_image_view") as refresh_image,

                patch.object(self.window, "_append_hr_workflow_note") as append_note,

                patch.object(self.window._hr_image_view, "capture_view_image", return_value=capture),

                patch.object(self.window._hr_diagram_widget, "has_exportable_rows", return_value=True),

                patch.object(self.window._hr_diagram_widget, "scientific_export_rows", return_value=[row]),

                patch.object(self.window._hr_diagram_widget, "export_scientific_view", side_effect=write_plot) as export_plot,

            ):

                self.window._export_hr_bundle()



            export_root = export_parent / "M45_science"

            self.assertTrue((export_root / "M45_science_source_image.png").exists())

            self.assertTrue((export_root / "M45_science_hr_diagram.png").exists())

            science_table_path = export_root / "M45_science_science_table.csv"

            self.assertTrue(science_table_path.exists())

            science_table_text = science_table_path.read_text(encoding="utf-8")

            self.assertIn("source_id,source_name,catalog", science_table_text)

            self.assertIn("1,Alpha,gaia-dr3", science_table_text)

            refresh_image.assert_called_once_with(reset_view=False)

            export_plot.assert_called_once()

            append_note.assert_called_once()



