    def test_hr_splitter_sizes_persist_to_settings_and_reload(self) -> None:

        with tempfile.TemporaryDirectory() as temp_dir:

            root_path = Path(temp_dir)

            config_path = root_path / "settings.json"

            previous_config_path = os.environ.get("CITIZEN_PHOTOMETRY_CONFIG_PATH")

            os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = str(config_path)

            try:

                self.window._root_path_input.setText(str(root_path))

                self.window._settings = AppSettings.from_root(root_path)

                self.window.show()

                QApplication.processEvents()



                self.window._hr_left_splitter.setSizes([720, 140])

                self.window._hr_main_splitter.setSizes([700, 980])

                expected_left_sizes = self.window._hr_left_splitter.sizes()

                expected_main_sizes = self.window._hr_main_splitter.sizes()

                self.window._handle_hr_splitter_sizes_changed(0, 0)



                loaded_settings = AppSettings.from_root(root_path)

                self.assertEqual(loaded_settings.hr_left_splitter_sizes, expected_left_sizes)

                if all(size > 0 for size in expected_main_sizes):

                    self.assertEqual(loaded_settings.hr_main_splitter_sizes, expected_main_sizes)

                else:

                    self.assertIsNone(loaded_settings.hr_main_splitter_sizes)



                self.window._settings = None

                self.window._load_settings_for_root(root_path)



                self.assertEqual(self.window._hr_left_splitter.sizes(), expected_left_sizes)

                if all(size > 0 for size in expected_main_sizes):

                    self.assertEqual(self.window._hr_main_splitter.sizes(), expected_main_sizes)

            finally:

                if previous_config_path is None:

                    os.environ.pop("CITIZEN_PHOTOMETRY_CONFIG_PATH", None)

                else:

                    os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = previous_config_path



