    def test_sky_explorer_layout_state_restores_on_initial_window_startup(self) -> None:

        with tempfile.TemporaryDirectory() as temp_dir:

            root_path = Path(temp_dir)

            config_path = root_path / "settings.json"

            previous_config_path = os.environ.get("CITIZEN_PHOTOMETRY_CONFIG_PATH")

            os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = str(config_path)

            extra_window: MainWindow | None = None

            try:

                settings = AppSettings.from_root(root_path)

                settings.sky_explorer_left_splitter_sizes = [286, 344]

                settings.sky_explorer_results_splitter_sizes = [498, 212]

                settings.sky_explorer_main_splitter_sizes = [758, 962]

                settings.sky_explorer_object_type_column_widths = [127, 133, 277, 151, 215, 403]

                settings.sky_explorer_results_column_widths = [203, 164, 83, 125, 127, 93]

                settings.save(root_path)

                extra_window = MainWindow()

                extra_window.show()

                QApplication.processEvents()

                extra_window._handle_app_mode_changed(AppMode.SKY_EXPLORER)

                QApplication.processEvents()

                actual_left_sizes = extra_window._sky_explorer_left_panel_splitter.sizes()

                actual_results_sizes = extra_window._sky_explorer_results_splitter.sizes()

                actual_main_sizes = extra_window._sky_explorer_main_splitter.sizes()

                self.assertTrue(all(size > 0 for size in actual_left_sizes))

                self.assertTrue(all(size > 0 for size in actual_results_sizes))

                self.assertTrue(all(size > 0 for size in actual_main_sizes))

                self.assertAlmostEqual(

                    actual_left_sizes[0] / sum(actual_left_sizes),

                    settings.sky_explorer_left_splitter_sizes[0] / sum(settings.sky_explorer_left_splitter_sizes),

                    places=2,

                )

                self.assertAlmostEqual(

                    actual_results_sizes[0] / sum(actual_results_sizes),

                    settings.sky_explorer_results_splitter_sizes[0] / sum(settings.sky_explorer_results_splitter_sizes),

                    places=2,

                )

                self.assertAlmostEqual(

                    actual_main_sizes[0] / sum(actual_main_sizes),

                    settings.sky_explorer_main_splitter_sizes[0] / sum(settings.sky_explorer_main_splitter_sizes),

                    places=2,

                )

                self.assertEqual(

                    [

                        extra_window._sky_explorer_object_type_table.columnWidth(column_index)

                        for column_index in range(extra_window._sky_explorer_object_type_table.columnCount())

                    ],

                    settings.sky_explorer_object_type_column_widths,

                )

                actual_results_widths = [

                    extra_window._sky_explorer_results_table.columnWidth(column_index)

                    for column_index in range(extra_window._sky_explorer_results_table.columnCount())

                ]

                self.assertEqual(

                    actual_results_widths[:-1],

                    settings.sky_explorer_results_column_widths[:-1],

                )

                self.assertGreaterEqual(

                    actual_results_widths[-1],

                    settings.sky_explorer_results_column_widths[-1],

                )

            finally:

                if extra_window is not None:

                    extra_window.close()

                if previous_config_path is None:

                    os.environ.pop("CITIZEN_PHOTOMETRY_CONFIG_PATH", None)

                else:

                    os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = previous_config_path



