    def test_asteroid_discovery_dialog_quick_label_saves_and_advances_selection(self) -> None:

        reference_path = Path(self._config_dir.name) / "discover_quick_label.fit"

        reference_path.write_text("placeholder", encoding="utf-8")

        start_time = datetime(2026, 5, 1, 3, 0, tzinfo=UTC)

        def build_candidate(candidate_id: str, *, base_x: float, base_y: float) -> MovingObjectCandidate:

            detections = tuple(

                MovingObjectCandidateDetection(

                    source_path=reference_path,

                    observation_time=start_time + timedelta(minutes=index),

                    frame_index=index,

                    x=base_x + index * 0.4,

                    y=base_y + index * 0.2,

                    peak_value=20.0 + index,

                    local_snr=7.0 + index,

                )

                for index in range(2)

            )

            return MovingObjectCandidate(

                candidate_id=candidate_id,

                frame_detections=detections,

                average_snr=7.5,

                peak_value=21.0,

                fit_rms_px=0.2,

                motion_px_per_hour=1.8,

                motion_arcsec_per_hour=2.7,

                displacement_px=1.6,

                start_x=detections[0].x,

                start_y=detections[0].y,

                end_x=detections[-1].x,

                end_y=detections[-1].y,

                summary_text=f"{candidate_id} synthetic discover candidate",

            )

        first_candidate = build_candidate("C1", base_x=24.0, base_y=30.0)
        second_candidate = build_candidate("C2", base_x=32.0, base_y=26.0)
        saved: list[tuple[str, str]] = []

        dialog = AsteroidDiscoveryDialog(

            display=build_annotated_image_display_from_array(np.ones((64, 64), dtype=np.float32), image_path=reference_path),

            result=MovingObjectDiscoveryResult(

                reference_path=reference_path,

                preview_data=np.ones((64, 64), dtype=np.float32),

                candidate_count=2,

                aligned_frame_count=2,

                candidates=(first_candidate, second_candidate),

                summary_text="Discover quick-label summary.",

            ),

            candidate_label_options=(("Real Mover", "real_mover"), ("Artifact", "artifact")),

            candidate_label_lookup=lambda _candidate: None,

            save_candidate_label=lambda candidate, label: saved.append((candidate.candidate_id, label)),

            parent=self.window,

        )

        try:
            dialog._tabs.setCurrentWidget(dialog._unmatched_table)
            dialog._unmatched_table.selectRow(0)
            dialog._handle_selection_changed()

            dialog._open_quick_label_dialog()

            quick_label_dialog = dialog._quick_label_dialog
            self.assertIsNotNone(quick_label_dialog)
            assert quick_label_dialog is not None

            quick_label_dialog._save_current_label("real_mover")

            self.assertEqual(saved, [("C1", "real_mover")])
            self.assertEqual(dialog._selected_candidate().candidate_id, "C2")

            quick_label_dialog.close()
        finally:
            dialog.close()



