            self.assertEqual(task.light_curves, [series])

            self.assertEqual(task.output_dir, export_root / "Target")

            self.assertEqual(task.export_name_stem, "Target")

            self.assertEqual(worker_kwargs["plot_y_axis_mode"], self.window._current_light_curve_y_axis_mode())

            self.assertEqual(worker_kwargs["science_metadata"].observer_code, "KAY")

            self.assertEqual(worker_kwargs["science_metadata"].site_name, "Backyard")

            self.assertEqual(worker_kwargs["science_metadata"].aavso_chart_id, "X12345ABC")

            self.assertTrue(worker_kwargs["science_metadata"].transformed)

            worker_cls.return_value.start.assert_called_once_with()

            self.assertIn("Starting science export", self.window._work_log_output.toPlainText())



