        self.assertFalse(self.window._hr_roi_draft_status_label.wordWrap())

        self.assertIs(self.window._hr_view_mode_group.parentWidget(), self.window._hr_shared_actions_widget)

        self.assertIs(self.window._hr_catalog_links_group.parentWidget(), self.window._hr_shared_actions_widget)

        self.assertIs(self.window._hr_image_view_mode_button.parentWidget(), self.window._hr_view_mode_group)

        self.assertIs(self.window._hr_results_view_mode_button.parentWidget(), self.window._hr_view_mode_group)

        self.assertEqual(self.window._hr_view_mode_group_label.text(), "View")

        self.assertIs(self.window._hr_open_cds_button.parentWidget(), self.window._hr_catalog_links_group)

        self.assertIs(self.window._hr_open_simbad_button.parentWidget(), self.window._hr_catalog_links_group)

