        self.assertIs(self.window._hr_open_vsx_button.parentWidget(), self.window._hr_catalog_links_group)

        self.assertEqual(self.window._hr_catalog_links_group_label.text(), "Catalog Links")

        self.assertEqual(self.window._hr_plot_group.layout().contentsMargins().left(), 12)

        self.assertIs(self.window._hr_diagram_widget.parentWidget(), self.window._hr_plot_group)

        self.assertIs(self.window._hr_roi_summary_label.parentWidget(), self.window._hr_footer_right_widget)

        self.assertFalse(self.window._hr_roi_summary_label.wordWrap())

        self.assertIs(self.window._hr_image_view.parentWidget(), self.window._hr_source_image_group)

        shared_actions_layout_obj = self.window._hr_shared_actions_widget.layout()

        self.assertIsNotNone(shared_actions_layout_obj)

        shared_actions_layout = cast(QHBoxLayout, shared_actions_layout_obj)


        self.assertLess(shared_actions_layout.indexOf(self.window._hr_prepare_button), shared_actions_layout.indexOf(self.window._hr_view_mode_group))

        self.assertLess(shared_actions_layout.indexOf(self.window._hr_view_mode_group), shared_actions_layout.indexOf(self.window._hr_display_section_label))

        self.assertFalse(self.window._hr_image_view_mode_button.isHidden())

        plot_layout_obj = self.window._hr_plot_group.layout()

        self.assertIsNotNone(plot_layout_obj)

        plot_layout = cast(QVBoxLayout, plot_layout_obj)

        plot_toolbar_item = plot_layout.itemAt(0)

        self.assertIsNotNone(plot_toolbar_item)

        plot_toolbar_layout_obj = plot_toolbar_item.layout() if plot_toolbar_item is not None else None

        self.assertIsNotNone(plot_toolbar_layout_obj)

        plot_toolbar_layout = cast(QHBoxLayout, plot_toolbar_layout_obj)

        self.assertLess(plot_toolbar_layout.indexOf(self.window._hr_motion_overlay_button), plot_toolbar_layout.indexOf(self.window._hr_find_motion_group_button))

        self.assertLess(plot_toolbar_layout.indexOf(self.window._hr_find_motion_group_button), plot_toolbar_layout.indexOf(self.window._hr_motion_group_advanced_button))

        self.assertIs(self.window._hr_image_stretch_combo.parentWidget(), self.window._hr_display_controls_group)

        self.assertIs(self.window._hr_adjust_levels_button.parentWidget(), self.window._hr_display_controls_group)

        self.assertIs(self.window._hr_reset_button.parentWidget(), self.window._hr_display_controls_group)



