            source_path = Path(temp_dir) / "demo_rgb.xisf"

            source_path.write_text("placeholder", encoding="utf-8")

            alpha = HrMeasurementRow(

                source_id="123",

                source_name="Alpha",

                catalog="gaia-dr3",

                ra_deg=10.0,

                dec_deg=20.0,

                gaia_g_mag=12.0,

                gaia_bp_rp=0.8,

                parallax_mas=7.25,

                parallax_error_mas=0.2,

                x=100.0,

                y=120.0,

                aperture_radius=5.0,

                annulus_inner_radius=8.0,

                annulus_outer_radius=12.0,

                pm_ra_mas_per_year=12.0,

                pm_dec_mas_per_year=0.0,

            )

            beta = HrMeasurementRow(

                source_id="456",

                source_name="Beta",

                catalog="gaia-dr3",

                ra_deg=10.1,

                dec_deg=20.0,

                gaia_g_mag=12.5,

                gaia_bp_rp=0.9,

                parallax_mas=7.0,

                parallax_error_mas=0.2,

                x=200.0,

                y=220.0,

                aperture_radius=5.0,

                annulus_inner_radius=8.0,

                annulus_outer_radius=12.0,

                pm_ra_mas_per_year=10.0,

                pm_dec_mas_per_year=0.0,

            )



            class _FakeWcs:

                has_celestial = True



                def world_to_pixel_values(self, ra_value, dec_value):

                    return 100.0 + ((float(ra_value) - 10.0) * 1_000_000.0), 120.0 + ((float(dec_value) - 20.0) * 1_000_000.0)



            self.window._current_hr_source_image = source_path

            self.window._current_hr_working_table = HrWorkingTable(

                rows=[alpha, beta],

                plane_labels=["red", "green", "blue", "luminance"],

                measured_count=2,

                usable_count=2,

            )

            self.window._hr_diagram_widget.visible_rows = lambda: [alpha, beta]

            self.window._hr_diagram_widget.plotted_row_keys = lambda: {("gaia-dr3", "123")}

            self.window._cached_hr_source_wcs = lambda _path: _FakeWcs()



            self.assertEqual(self.window._current_hr_motion_vector_overlays(), [])



            self.window._hr_motion_overlay_button.setChecked(True)

            overlays = self.window._current_hr_motion_vector_overlays()



            self.assertEqual(len(overlays), 1)

            self.assertEqual(overlays[0].x, 100.0)

            self.assertGreater(overlays[0].dx, 0.0)

            self.assertAlmostEqual(overlays[0].dy, 0.0, places=6)



