    def test_prepare_hr_workflow_writes_field_catalog_file(self) -> None:

        with tempfile.TemporaryDirectory() as temp_dir:

            temp_path = Path(temp_dir)

            source_path = temp_path / "demo_rgb.xisf"

            source_path.write_text("placeholder", encoding="utf-8")

            working_dir = temp_path / "Exports"

            working_dir.mkdir()

            solved_field = SolvedField(

                center_ra_deg=83.8221,

                center_dec_deg=-5.3911,

                radius_deg=1.25,

                width=4000,

                height=3000,

                wcs_path=source_path,

            )

            field_catalog = FieldCatalog(

                center_ra_deg=solved_field.center_ra_deg,

                center_dec_deg=solved_field.center_dec_deg,

                radius_deg=solved_field.radius_deg,

                gaia_stars=[

                    CatalogStar(

                        catalog="gaia-dr3",

                        source_id="123",

                        name="123",

                        ra_deg=83.8,

                        dec_deg=-5.39,

                        magnitude=12.3,

                        is_variable=False,

                        metadata={"bp_rp": 0.82},

                    )

                ],

            )

            self.window._hr_source_image_input.setText(str(source_path))

            self.window._hr_working_directory_input.setText(str(working_dir))

            self.window._resolve_hr_source_field = lambda _path, progress_callback=None: solved_field

            self.window._query_hr_field_catalog = lambda _field, progress_callback=None: field_catalog

            self.window._build_hr_working_table = lambda _path, _catalog, progress_callback=None: HrWorkingTable(

                rows=[

                    HrMeasurementRow(

                        source_id="123",

                        source_name="123",

                        catalog="gaia-dr3",

                        ra_deg=83.8,

                        dec_deg=-5.39,

                        gaia_g_mag=12.3,

                        gaia_bp_rp=0.82,

                        parallax_mas=5.0,

                        parallax_error_mas=0.2,

                        x=120.0,

                        y=80.0,

                        aperture_radius=5.0,

                        annulus_inner_radius=8.0,

                        annulus_outer_radius=12.0,

                        flux_red=1000.0,

                        flux_green=900.0,

                        flux_blue=800.0,

                        flux_luminance=900.0,

                        calibrated_mag_luminance=12.1,

                        gaia_absolute_magnitude=5.6,

                        absolute_magnitude_proxy=5.6,

                        plot_color_index=0.82,

                        display_color_hex="#ffe0cc",

                        used_for_zero_point=True,

                    )

                ],

                plane_labels=["red", "green", "blue", "luminance"],

                measured_count=1,

                usable_count=1,

                zero_point_offset_mag=1.9,

                zero_point_source_count=1,

            )



            result = self.window._execute_hr_preparation(source_path, working_dir)

            with (
                patch.object(self.window, "_schedule_hr_footer_splitter_sync") as schedule_sync,
                patch.object(self.window, "_sync_hr_background_name_lookup") as sync_name_lookup,
            ):

                self.window._handle_hr_preparation_completed(result)

            schedule_sync.assert_called_once()

            sync_name_lookup.assert_called_once_with(force_restart=True)



            field_catalog_path = working_dir / "hr_field_catalog.json"

            working_table_json_path = working_dir / "hr_working_table.json"

            working_table_csv_path = working_dir / "hr_working_table.csv"

            self.assertTrue(field_catalog_path.exists())

            self.assertTrue(working_table_json_path.exists())

            self.assertTrue(working_table_csv_path.exists())

            self.assertIn("Gaia stars: 1", self.window._hr_steps_output.toPlainText())

            self.assertIn("Measured rows: 1", self.window._hr_steps_output.toPlainText())

            self.assertEqual(self.window._hr_roi_draft_status_label.text(), "No draft ROI pending.")

            self.assertIn("Zero-point sources: 1", self.window._hr_steps_output.toPlainText())

            self.assertIn("Zero-point offset: 1.9", self.window._hr_steps_output.toPlainText())

            self.assertIn(str(field_catalog_path), self.window._hr_steps_output.toPlainText())

            self.assertIn(str(working_table_json_path), self.window._hr_steps_output.toPlainText())

            self.assertIn(str(working_table_csv_path), self.window._hr_steps_output.toPlainText())

            self.assertEqual(self.window._hr_results_table.rowCount(), 1)

            self.assertEqual(self.window._hr_results_table.item(0, 0).text(), "123")

            self.assertIn("Showing 1 matching HR row", self.window._hr_table_summary_label.text())

            csv_text = working_table_csv_path.read_text(encoding="utf-8")

            self.assertIn("gaia_absolute_magnitude", csv_text)



