    def test_find_hr_common_motion_group_highlights_before_optional_filter(self) -> None:

        cluster_rows = [

            HrMeasurementRow(

                source_id=f"cluster-{index}",

                source_name=f"Cluster {index}",

                catalog="gaia-dr3",

                ra_deg=0.0,

                dec_deg=0.0,

                gaia_g_mag=12.0 + (index * 0.1),

                gaia_bp_rp=0.8 + (index * 0.02),

                parallax_mas=2.0 + (index * 0.03),

                parallax_error_mas=0.1,

                pm_ra_mas_per_year=10.0 + (index * 0.05),

                pm_dec_mas_per_year=-4.5 + (index * 0.04),

                x=float(index),

                y=float(index),

                aperture_radius=5.0,

                annulus_inner_radius=8.0,

                annulus_outer_radius=12.0,

                gaia_absolute_magnitude=5.0 + (index * 0.03),

            )

            for index in range(6)

        ]

        field_rows = [

            HrMeasurementRow(

                source_id="field-a",

                source_name="Field A",

                catalog="gaia-dr3",

                ra_deg=0.0,

                dec_deg=0.0,

                gaia_g_mag=14.0,

                gaia_bp_rp=1.1,

                parallax_mas=8.0,

                parallax_error_mas=0.2,

                pm_ra_mas_per_year=-14.0,

                pm_dec_mas_per_year=6.5,

                x=20.0,

                y=20.0,

                aperture_radius=5.0,

                annulus_inner_radius=8.0,

                annulus_outer_radius=12.0,

                gaia_absolute_magnitude=6.5,

            ),

            HrMeasurementRow(

                source_id="field-b",

                source_name="Field B",

                catalog="gaia-dr3",

                ra_deg=0.0,

                dec_deg=0.0,

                gaia_g_mag=15.0,

                gaia_bp_rp=1.4,

                parallax_mas=0.4,

                parallax_error_mas=0.2,

                pm_ra_mas_per_year=24.0,

                pm_dec_mas_per_year=15.0,

                x=21.0,

                y=21.0,

                aperture_radius=5.0,

                annulus_inner_radius=8.0,

                annulus_outer_radius=12.0,

                gaia_absolute_magnitude=7.0,

            ),

        ]

        self.window._current_hr_working_table = HrWorkingTable(

            rows=cluster_rows + field_rows,

            plane_labels=["red", "green", "blue", "luminance"],

            measured_count=8,

            usable_count=8,

        )



        self.window._refresh_hr_plot()

        self.assertEqual(self.window._hr_results_table.rowCount(), 8)



        self.window._find_hr_common_motion_group()



        self.assertEqual(self.window._hr_results_table.rowCount(), 8)

        self.assertEqual(self.window._hr_diagram_widget.plotted_row_count(), 8)

        self.assertEqual(self.window._hr_find_motion_group_button.text(), "Find All")

        self.assertTrue(self.window._hr_motion_group_filter_checkbox.isEnabled())

        self.assertFalse(self.window._hr_motion_group_filter_checkbox.isChecked())

        self.assertEqual(len(self.window._hr_common_motion_row_keys), 6)

        self.assertEqual(len(self.window._hr_common_motion_highlight_row_keys), 6)

        self.assertAlmostEqual(self.window._hr_common_motion_result.strictness, 1.0)

        self.assertEqual(self.window._hr_common_motion_result.clustering_method, "lightweight")



        highlighted_rows = [

            row

            for row in self.window._displayed_hr_result_rows

            if (row.catalog, row.source_id) in self.window._hr_common_motion_highlight_row_keys

        ]

        self.assertEqual([row.source_name for row in highlighted_rows], [f"Cluster {index}" for index in range(6)])



        model = self.window._hr_results_table_model

        first_cluster_index = next(

            row_index

            for row_index, row in enumerate(model._rows)

            if row.source_id == "cluster-0"

        )

        first_field_index = next(

            row_index

            for row_index, row in enumerate(model._rows)

            if row.source_id == "field-a"

        )

        self.assertEqual(

            model.data(model.index(first_cluster_index, 0), Qt.ItemDataRole.ToolTipRole),

            "Highlighted as part of the current common-motion candidate group.",

        )

        self.assertEqual(

            model.data(model.index(first_field_index, 0), Qt.ItemDataRole.ToolTipRole),

            "Currently included on the HR plot.",

        )



        self.window._hr_motion_group_filter_checkbox.setChecked(True)

        self.window._refresh_hr_plot()



        self.assertEqual(self.window._hr_results_table.rowCount(), 6)

        self.assertEqual(self.window._hr_diagram_widget.plotted_row_count(), 6)

        self.assertEqual([row.source_name for row in self.window._displayed_hr_result_rows], [f"Cluster {index}" for index in range(6)])



        self.window._handle_hr_plot_background_activated()



        self.assertEqual(self.window._hr_results_table.rowCount(), 6)

        self.assertEqual(self.window._hr_diagram_widget.plotted_row_count(), 6)

        self.assertEqual(len(self.window._hr_common_motion_row_keys), 6)

        self.assertEqual(len(self.window._hr_common_motion_highlight_row_keys), 0)

        self.assertIsNone(self.window._selected_hr_result_row)

        self.assertEqual(

            model.data(model.index(0, 0), Qt.ItemDataRole.ToolTipRole),

            "Currently included on the HR plot.",

        )



        self.window._find_hr_common_motion_group()



        self.assertEqual(self.window._hr_results_table.rowCount(), 8)

        self.assertEqual(self.window._hr_find_motion_group_button.text(), "Find Cluster")

        self.assertFalse(self.window._hr_motion_group_filter_checkbox.isEnabled())

        self.assertFalse(self.window._hr_motion_group_filter_checkbox.isChecked())



