    def test_open_hr_motion_group_dialog_updates_persisted_settings(self) -> None:

        with patch("photometry_app.ui.main_window.HrMotionGroupDialog") as dialog_class:

            dialog = dialog_class.return_value

            dialog.exec.return_value = QDialog.DialogCode.Accepted

            dialog.build_settings.return_value = HrMotionGroupSettings(

                preset="custom",

                method="sklearn",

                strictness=1.4,

                parallax_mode="always",

                refine_hr_consistency=False,

                auto_filter=True,

            )



            self.window._open_hr_motion_group_dialog()



        settings = AppSettings.from_root(Path(self._config_dir.name))

        self.assertEqual(settings.hr_motion_group_preset, "custom")

        self.assertEqual(settings.hr_motion_group_method, "sklearn")

        self.assertAlmostEqual(settings.hr_motion_group_strictness, 1.4)

        self.assertEqual(settings.hr_motion_group_parallax_mode, "always")

        self.assertFalse(settings.hr_motion_group_refine_hr_consistency)

        self.assertTrue(settings.hr_motion_group_auto_filter)



