    def test_resolve_hr_source_field_falls_back_to_astrometry_for_invalid_header(self) -> None:

        with tempfile.TemporaryDirectory() as temp_dir:

            temp_path = Path(temp_dir)

            source_path = temp_path / "demo_rgb.xisf"

            source_path.write_text("placeholder", encoding="utf-8")

            self.window._root_path_input.setText(str(temp_path))

            self.window._settings = AppSettings.from_root(temp_path)

            self.window._settings.astrometry_api_key = "demo-key"



            from astropy.io.fits import Header

            import photometry_app.ui.main_window as main_window_module



            header = Header()

            original_read_header_and_shape = main_window_module.read_header_and_shape

            original_client = main_window_module.AstrometryNetClient



            class FakeAstrometryClient:

                def __init__(self, api_key: str) -> None:

                    self.api_key = api_key



                def solve_file(self, fits_path, cache_dir, hints=None):

                    return PlateSolveResult(

                        source_path=fits_path,

                        status=WcsStatus.SOLVED,

                        solved_field=SolvedField(

                            center_ra_deg=83.822,

                            center_dec_deg=-5.391,

                            radius_deg=1.0,

                            width=32,

                            height=32,

                            wcs_path=Path(cache_dir) / "solved.fits",

                        ),

                        reasons=[],

                    )



            try:

                main_window_module.read_header_and_shape = lambda _path: (header, 32, 32)

                main_window_module.AstrometryNetClient = FakeAstrometryClient

                solved_field = self.window._resolve_hr_source_field(source_path)

            finally:

                main_window_module.read_header_and_shape = original_read_header_and_shape

                main_window_module.AstrometryNetClient = original_client



            self.assertAlmostEqual(solved_field.center_ra_deg, 83.822, places=2)

            self.assertAlmostEqual(solved_field.center_dec_deg, -5.391, places=2)



