    def test_milky_way_texture_sampler_wraps_horizontally(self) -> None:

        texture = np.array(
            [
                [[10, 0, 0], [20, 0, 0], [30, 0, 0], [40, 0, 0]],
                [[50, 0, 0], [60, 0, 0], [70, 0, 0], [80, 0, 0]],
            ],
            dtype=np.uint8,
        )
        texture_u = np.array([[0.0, 0.25, 0.875, 1.0]], dtype=np.float32)
        texture_v = np.array([[0.0, 0.0, 0.0, 0.0]], dtype=np.float32)

        sampled = _SkyAtlasViewWidget._sample_milky_way_texture(texture, texture_u, texture_v)

        self.assertAlmostEqual(float(sampled[0, 0, 0]), 10.0)
        self.assertAlmostEqual(float(sampled[0, 1, 0]), 20.0)
        self.assertAlmostEqual(float(sampled[0, 2, 0]), 25.0)
        self.assertAlmostEqual(float(sampled[0, 3, 0]), 10.0)

