    def test_milky_way_visible_shader_tile_requests_cache_hit_avoids_tile_filesystem_checks(self) -> None:

        widget = _SkyAtlasViewWidget.__new__(_SkyAtlasViewWidget)

        with tempfile.TemporaryDirectory() as temp_dir:

            root = Path(temp_dir)
            asset = self._milky_way_request_cache_asset(root)
            tile_root = root / "L0"
            widget._milky_way_visible_tile_coordinates = MagicMock(return_value=((0, 0), (1, 0)))
            scene = self._milky_way_request_cache_scene()
            widget._milky_way_visible_shader_tile_requests(scene, asset, asset.manifest.levels[0])

            original_stat = Path.stat
            original_is_file = Path.is_file
            stat_paths: list[Path] = []
            is_file_paths: list[Path] = []

            def counting_stat(path: Path, *args: object, **kwargs: object) -> object:
                stat_paths.append(path)
                return original_stat(path, *args, **kwargs)

            def counting_is_file(path: Path) -> bool:
                is_file_paths.append(path)
                return original_is_file(path)

            with patch.object(Path, "stat", counting_stat), patch.object(Path, "is_file", counting_is_file):
                widget._milky_way_visible_shader_tile_requests(scene, asset, asset.manifest.levels[0])

            self.assertFalse(any(tile_root in path.parents for path in stat_paths))
            self.assertFalse(any(tile_root in path.parents for path in is_file_paths))

