    def test_milky_way_manifest_base_image_matches_tile_upload_vertical_parity(self) -> None:

        widget = _SkyAtlasViewWidget.__new__(_SkyAtlasViewWidget)
        widget._milky_way_manifest_base_image_cache_key = None
        widget._milky_way_manifest_base_image_cache_value = None

        with tempfile.TemporaryDirectory() as temp_dir:

            root = Path(temp_dir)
            manifest_path = root / "manifest.json"
            level_dir = root / "L0"
            level_dir.mkdir(parents=True)

            tile_colors = {
                (0, 0): QColor(255, 0, 0),
                (1, 0): QColor(0, 255, 0),
                (2, 0): QColor(0, 128, 128),
                (3, 0): QColor(128, 0, 128),
                (0, 1): QColor(0, 0, 255),
                (1, 1): QColor(255, 255, 0),
                (2, 1): QColor(128, 128, 128),
                (3, 1): QColor(255, 128, 0),
            }

            for (x_index, y_index), color in tile_colors.items():

                tile_image = QImage(2, 2, QImage.Format.Format_RGB888)
                tile_image.fill(color)

                self.assertTrue(tile_image.save(str(level_dir / f"{x_index}_{y_index}.png")))

            manifest = parse_milky_way_manifest(
                {
                    "schema_version": 1,
                    "projection": "equirectangular_celestial",
                    "source_name": "demo",
                    "source_width": 8,
                    "source_height": 4,
                    "tile_size": 2,
                    "color_space": "srgb",
                    "tone_preprocessing": "source_like",
                    "orientation": {
                        "ra_increases": "left",
                        "dec_axis": "top_to_bottom",
                    },
                    "levels": [
                        {"level": 0, "width": 8, "height": 4, "path": "L0/{x}_{y}.png"},
                    ],
                },
                manifest_path=manifest_path,
            )

            asset = MilkyWayTilePyramidAsset(manifest=manifest, path=manifest_path)

            base_image, cache_key = widget._milky_way_manifest_base_image(asset)

            self.assertIsNotNone(base_image)
            self.assertIsNotNone(cache_key)
            assert base_image is not None
            assert cache_key is not None
            self.assertIn("tile_upload_vertical_parity_v1", cache_key)
            self.assertEqual(base_image.pixelColor(0, 0), tile_colors[(0, 1)])
            self.assertEqual(base_image.pixelColor(2, 0), tile_colors[(1, 1)])
            self.assertEqual(base_image.pixelColor(0, 2), tile_colors[(0, 0)])
            self.assertEqual(base_image.pixelColor(2, 2), tile_colors[(1, 0)])

