    def test_milky_way_tile_texture_cache_key_includes_manifest_and_padding_identity(self) -> None:

        widget = _SkyAtlasViewWidget.__new__(_SkyAtlasViewWidget)

        with tempfile.TemporaryDirectory() as temp_dir:
            temp_root = Path(temp_dir)
            manifest_path = temp_root / "manifest.json"
            manifest_payload = {
                "schema_version": 1,
                "projection": "equirectangular_celestial",
                "source_name": "demo_source",
                "source_width": 4096,
                "source_height": 2048,
                "tile_size": 1024,
                "color_space": "srgb",
                "tone_preprocessing": "source_like",
                "orientation": {
                    "ra_increases": "left",
                    "dec_axis": "top_to_bottom",
                },
                "levels": [
                    {
                        "level": 2,
                        "width": 4096,
                        "height": 2048,
                        "path": "L2/{x}_{y}.png",
                    }
                ],
            }
            manifest_path.write_text(json.dumps(manifest_payload), encoding="utf-8")
            manifest = parse_milky_way_manifest(manifest_payload, manifest_path=manifest_path, strict=False)
            asset = MilkyWayTilePyramidAsset(manifest=manifest, path=manifest_path)

            tile_dir = temp_root / "L2"
            tile_dir.mkdir(parents=True)
            tile_path = tile_dir / "0_0.png"
            tile_image = QImage(4, 4, QImage.Format.Format_RGB888)
            tile_image.fill(0)
            self.assertTrue(tile_image.save(str(tile_path)))

            cache_key = widget._milky_way_tile_texture_cache_key(
                asset,
                tile_path=tile_path,
                level=2,
                x_index=0,
                y_index=0,
            )

            self.assertIn(str(manifest_path.resolve()), cache_key)
            self.assertIn("demo_source", cache_key)
            self.assertIn(1024, cache_key)
            self.assertIn("srgb", cache_key)
            self.assertIn("source_like", cache_key)
            self.assertIn((0, 0, 1024, 1024), cache_key)
            self.assertIn("neighbor_border_1", cache_key)

