    def test_milky_way_texture_levels_build_once_and_reuse_cache(self) -> None:

        with patch.dict(os.environ, {"CITIZEN_PHOTOMETRY_SKY_VIEW_TIMING": "1"}):

            widget = _SkyAtlasViewWidget()

        try:

            first_levels = widget._milky_way_texture_levels()
            second_levels = widget._milky_way_texture_levels()

            self.assertIsNotNone(first_levels)
            self.assertIs(first_levels, second_levels)

            assert first_levels is not None

            self.assertGreaterEqual(len(first_levels), 3)
            self.assertEqual(first_levels[0].pixels.dtype, np.float32)
            self.assertTrue(first_levels[0].pixels.flags.c_contiguous)

            detail = widget._sky_view_timing_window.milky_way_detail
            self.assertEqual(detail.texture_load_count, 1)
            self.assertEqual(detail.texture_cache_hit_count, 2)
        finally:

            widget.close()

    def test_milky_way_texture_level_selection_uses_smallest_acceptable_source(self) -> None:

        levels = (
            _SkyViewMilkyWayTextureLevel("4096w", 4096, 2048, np.zeros((1, 1, 3), dtype=np.float32)),
            _SkyViewMilkyWayTextureLevel("2048w", 2048, 1024, np.zeros((1, 1, 3), dtype=np.float32)),
            _SkyViewMilkyWayTextureLevel("1024w", 1024, 512, np.zeros((1, 1, 3), dtype=np.float32)),
            _SkyViewMilkyWayTextureLevel("512w", 512, 256, np.zeros((1, 1, 3), dtype=np.float32)),
        )
        scene = SimpleNamespace(
            field_width_deg=95.0,
            field_height_deg=54.0,
            milky_way_resolution_mode="high",
        )

        wide_level = _SkyAtlasViewWidget._milky_way_texture_level(scene, 848, 477, "bilinear", levels)
        self.assertEqual(wide_level.width, 2048)

        scene.milky_way_resolution_mode = "low"
        low_level = _SkyAtlasViewWidget._milky_way_texture_level(scene, 848, 477, "bilinear", levels)
        self.assertEqual(low_level.width, 1024)

        zoomed_level = _SkyAtlasViewWidget._milky_way_texture_level(scene, 848, 477, "nearest", levels)
        self.assertEqual(zoomed_level.width, 512)

        scene.milky_way_resolution_mode = "high"
        scene.field_width_deg = 22.0
        scene.field_height_deg = 12.0
        detailed_level = _SkyAtlasViewWidget._milky_way_texture_level(scene, 848, 477, "bilinear", levels)
        self.assertEqual(detailed_level.width, 4096)

