    def test_milky_way_interactive_low_quality_control_is_removed_from_sky_view_ui(self) -> None:

        with tempfile.TemporaryDirectory() as config_dir, tempfile.TemporaryDirectory() as state_dir:

            config_path = Path(config_dir) / "settings.json"
            state_path = Path(state_dir) / "state.json"
            training_db_path = Path(state_dir) / "training.sqlite3"
            config_path.write_text("{}", encoding="utf-8")
            state_path.write_text("{}", encoding="utf-8")

            previous_config_path = os.environ.get("CITIZEN_PHOTOMETRY_CONFIG_PATH")
            previous_state_path = os.environ.get("CITIZEN_PHOTOMETRY_STATE_PATH")
            previous_training_db = os.environ.get("CITIZEN_PHOTOMETRY_TRAINING_DB")

            os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = str(config_path)
            os.environ["CITIZEN_PHOTOMETRY_STATE_PATH"] = str(state_path)
            os.environ["CITIZEN_PHOTOMETRY_TRAINING_DB"] = str(training_db_path)

            try:

                window = MainWindow()

                try:

                    self.assertFalse(hasattr(window, "_sky_view_milky_way_interactive_low_checkbox"))
                    self.assertTrue(hasattr(window, "_sky_view_milky_way_tone_preset_combo"))
                    self.assertTrue(hasattr(window, "_sky_view_milky_way_contrast_slider"))
                    self.assertTrue(hasattr(window, "_sky_view_milky_way_saturation_slider"))
                    self.assertTrue(hasattr(window, "_sky_view_milky_way_black_point_slider"))
                    self.assertTrue(hasattr(window, "_sky_view_milky_way_gamma_slider"))
                    self.assertEqual(window._sky_view_milky_way_opacity_slider.value(), 48)
                    self.assertEqual(window._sky_view_milky_way_brightness_slider.value(), 118)
                    self.assertEqual(window._sky_view_milky_way_contrast_slider.value(), 134)
                    self.assertEqual(window._sky_view_milky_way_saturation_slider.value(), 155)
                    self.assertAlmostEqual(window._sky_view_canvas.milky_way_opacity(), 0.48)

                finally:

                    window.close()

            finally:

                if previous_config_path is None:

                    os.environ.pop("CITIZEN_PHOTOMETRY_CONFIG_PATH", None)

                else:

                    os.environ["CITIZEN_PHOTOMETRY_CONFIG_PATH"] = previous_config_path

                if previous_state_path is None:

                    os.environ.pop("CITIZEN_PHOTOMETRY_STATE_PATH", None)

                else:

                    os.environ["CITIZEN_PHOTOMETRY_STATE_PATH"] = previous_state_path

                if previous_training_db is None:

                    os.environ.pop("CITIZEN_PHOTOMETRY_TRAINING_DB", None)

                else:

                    os.environ["CITIZEN_PHOTOMETRY_TRAINING_DB"] = previous_training_db

