    def test_milky_way_draw_bypasses_gl_and_cpu_when_disabled(self) -> None:

        widget = _SkyAtlasViewWidget.__new__(_SkyAtlasViewWidget)
        widget._sky_view_timing_window = None
        widget._gl_milky_way_layer = SimpleNamespace(reset_frame_diagnostics=MagicMock())
        widget._milky_way_runtime_asset_info = MagicMock(return_value=SimpleNamespace(active_source_level="preview"))
        widget._maybe_log_milky_way_runtime_state = MagicMock()
        widget._try_draw_gl_milky_way_layer = MagicMock(side_effect=AssertionError("GL path should not run when Milky Way is disabled"))
        widget._milky_way_view_image = MagicMock(side_effect=AssertionError("CPU path should not run when Milky Way is disabled"))
        widget._sky_view_gl_milky_way_last_draw_attempted = False
        widget._sky_view_gl_milky_way_last_draw_succeeded = False
        widget._sky_view_gl_milky_way_last_cpu_fallback_used = False
        widget._sky_view_gl_milky_way_last_renderer_used = "inactive"
        widget._sky_view_gl_milky_way_last_layer_seconds = 0.0
        widget._sky_view_gl_milky_way_last_cpu_cache_miss = False
        widget._sky_view_gl_milky_way_visible_tile_count = 12
        widget._sky_view_gl_milky_way_last_mesh_build_seconds = 1.5
        widget._sky_view_gl_milky_way_last_tile_debug_records = (SimpleNamespace(tile_id="L4/0/0"),)
        widget._sky_view_gl_milky_way_last_tile_debug_snapshot = {"total_triangles": 42}

        target = QImage(32, 24, QImage.Format.Format_ARGB32)
        target.fill(0)
        painter = QPainter(target)
        scene = SimpleNamespace(
            milky_way_enabled=False,
            milky_way_resolution_mode="high",
            milky_way_opacity=0.8,
            viewport_rect=QRectF(0.0, 0.0, 32.0, 24.0),
            interaction_state="stable",
        )

        try:

            widget._draw_milky_way_layer(painter, scene)

        finally:

            painter.end()

        widget._try_draw_gl_milky_way_layer.assert_not_called()
        widget._milky_way_view_image.assert_not_called()
        widget._gl_milky_way_layer.reset_frame_diagnostics.assert_called_once_with()
        self.assertEqual(widget._sky_view_gl_milky_way_visible_tile_count, 0)
        self.assertEqual(widget._sky_view_gl_milky_way_last_mesh_build_seconds, 0.0)
        self.assertEqual(widget._sky_view_gl_milky_way_last_tile_debug_snapshot, {})

