    def test_milky_way_gl_failure_disables_session_and_returns_false(self) -> None:

        widget = _SkyAtlasViewWidget.__new__(_SkyAtlasViewWidget)
        widget._milky_way_renderer_mode = "opengl"
        widget._sky_view_gl_milky_way_requested = True
        widget._sky_view_gl_milky_way_disabled_for_session = False
        widget._sky_view_gl_milky_way_error_logged = False
        widget._sky_view_gl_milky_way_init_attempted = False
        widget._sky_view_gl_milky_way_init_succeeded = False
        widget._sky_view_gl_milky_way_last_fallback_reason = ""
        widget._sky_view_gl_milky_way_fallback_count = 0
        widget._gl_functions = object()
        widget._milky_way_source_image_cache_key = ("demo", 1, 2)
        widget._gl_milky_way_layer = SimpleNamespace(
            is_available=MagicMock(return_value=True),
            draw=MagicMock(side_effect=RuntimeError("boom")),
            release=MagicMock(),
            last_draw_seconds=0.0,
            last_program_initialized=False,
            last_texture_uploaded=False,
            last_program_init_seconds=0.0,
            last_texture_upload_seconds=0.0,
        )
        widget._milky_way_source_image = MagicMock(return_value=QImage(4, 2, QImage.Format.Format_RGB888))
        widget._build_gl_milky_way_uniforms = MagicMock(return_value=object())

        painter = MagicMock()
        scene = SimpleNamespace(milky_way_resolution_mode="high")

        drew = widget._try_draw_gl_milky_way_layer(painter, scene, None)

        self.assertFalse(drew)
        self.assertTrue(widget._sky_view_gl_milky_way_disabled_for_session)
        widget._gl_milky_way_layer.release.assert_called_once_with()
        painter.beginNativePainting.assert_called_once_with()
        painter.endNativePainting.assert_called_once_with()




